{
  "name": "Soft Rose Modern Trade",
  "description": "Internal management system for sales, inventory, and competitor tracking",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type UserRole = 'admin' | 'user';

export interface User {
  id: string;
  username: string;
  password?: string;
  role: UserRole;
  employeeName: string;
  employeeCode: string;
  phone: string;
  isOnline: boolean;
  canSeeAllSales: boolean;
  vacationBalance: {
    annual: number;
    casual: number;
    sick: number;
    exams: number;
  };
}

export interface SaleItem {
  id: string;
  category: string;
  productName: string;
  price: number;
  quantity: number;
}

export interface DailySale {
  id: string;
  userId: string;
  userName: string;
  marketName: string;
  date: string;
  items: SaleItem[];
  total: number;
}

export interface InventoryRecord {
  id: string;
  userId: string;
  userName: string;
  marketName: string;
  date: string;
  items: {
    productName: string;
    quantity: number;
  }[];
}

export interface CompetitorPrice {
  id: string;
  userId: string;
  marketName: string;
  companyName: string;
  category: string;
  items: {
    productName: string;
    price: number;
  }[];
}

export interface Vacation {
  id: string;
  userId: string;
  userName: string;
  date: string;
  days: number;
  type: 'annual' | 'casual' | 'sick' | 'exams';
}

export interface AppSettings {
  tickerText: string;
  showDailySalesTicker: boolean;
  showMonthlySalesTicker: boolean;
  whatsappNumber: string;
  programName: string;
  sidebarConfig: {
    [key: string]: {
      label: string;
      isVisible: boolean;
    }
  };
}

import { initializeApp } from "firebase/app";
import { getDatabase, ref, set, onValue, push, update, remove } from "firebase/database";

// Insert your Firebase config here
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "YOUR_PROJECT_ID.firebaseapp.com",
  databaseURL: "https://YOUR_PROJECT_ID-default-rtdb.firebaseio.com",
  projectId: "YOUR_PROJECT_ID",
  storageBucket: "YOUR_PROJECT_ID.appspot.com",
  messagingSenderId: "YOUR_MESSAGING_ID",
  appId: "YOUR_APP_ID"
};

const app = initializeApp(firebaseConfig);
const db = getDatabase(app);

export { db, ref, set, onValue, push, update, remove };

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, MessageCircle, Calendar,
  Download, Plus, Trash2, Edit
} from 'lucide-react';
import { db, ref, onValue, set, update, push } from './firebase';
import { User, AppSettings, DailySale, InventoryRecord, CompetitorPrice, Vacation } from './types';
import { INITIAL_MARKETS, PRODUCT_GROUPS } from './constants';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [markets, setMarkets] = useState<string[]>(INITIAL_MARKETS);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);

  useEffect(() => {
    // Sync settings
    const settingsRef = ref(db, 'settings');
    onValue(settingsRef, (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    // Sync users
    const usersRef = ref(db, 'users');
    onValue(usersRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setUsers(Object.values(data));
      }
    });

    // Sync markets
    const marketsRef = ref(db, 'markets');
    onValue(marketsRef, (snapshot) => {
      const data = snapshot.val();
      if (data) setMarkets([...INITIAL_MARKETS, ...Object.values(data) as string[]]);
    });
  }, []);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user) {
      update(ref(db, `users/${user.id}`), { isOnline: false });
    }
    setUser(null);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const sidebarItems = [
    { id: 'daily-sales', label: settings?.sidebarConfig?.['daily-sales']?.label || 'المبيعات اليومية', icon: <ShoppingCart size={20}/> },
    { id: 'sales-history', label: settings?.sidebarConfig?.['sales-history']?.label || 'سجل المبيعات', icon: <History size={20}/> },
    { id: 'inventory-reg', label: settings?.sidebarConfig?.['inventory-reg']?.label || 'تسجيل المخزون', icon: <Package size={20}/> },
    { id: 'inventory-history', label: settings?.sidebarConfig?.['inventory-history']?.label || 'سجل المخزون', icon: <ClipboardList size={20}/> },
    { id: 'competitor-prices', label: settings?.sidebarConfig?.['competitor-prices']?.label || 'أسعار المنافسين', icon: <TrendingUp size={20}/> },
    { id: 'competitor-reports', label: settings?.sidebarConfig?.['competitor-reports']?.label || 'تقارير المنافسين', icon: <BarChart size={20}/> },
    { id: 'vacation-mgmt', label: settings?.sidebarConfig?.['vacation-mgmt']?.label || 'رصيد الاجازات', icon: <Calendar size={20}/> },
    { id: 'settings', label: 'الإعدادات', icon: <SettingsIcon size={20}/>, adminOnly: true },
  ].filter(item => {
    if (item.adminOnly && user.role !== 'admin') return false;
    const config = settings?.sidebarConfig?.[item.id];
    if (config && !config.isVisible && user.role !== 'admin') return false;
    return true;
  });

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className={`bg-rose-700 text-white w-64 flex-shrink-0 transition-all duration-300 ${isSidebarOpen ? 'ml-0' : '-ml-64'} md:relative fixed inset-y-0 z-50`}>
        <div className="p-4 flex flex-col h-full">
          <div className="mb-8 flex items-center justify-between">
            <h1 className="text-xl font-bold">{settings?.programName || 'Soft Rose'}</h1>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden">
              <X size={24} />
            </button>
          </div>

          <nav className="flex-1 space-y-1">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); if (window.innerWidth < 768) setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${activeTab === item.id ? 'bg-white/20 font-bold' : 'hover:bg-white/10'}`}
              >
                {item.icon}
                <span>{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="pt-4 border-t border-white/20">
            <div className="flex items-center gap-3 mb-4 px-4">
              <div className={`w-3 h-3 rounded-full ${user.isOnline ? 'bg-blue-400' : 'bg-red-400'}`}></div>
              <span className="text-sm">{user.employeeName}</span>
            </div>
            <button 
              onClick={handleLogout}
              className="w-full flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/10 transition"
            >
              <LogOut size={20} />
              <span>خروج</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Header */}
        <header className="bg-white border-b h-16 flex items-center justify-between px-4 sticky top-0 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className={`${isSidebarOpen ? 'hidden' : 'block'} p-2 hover:bg-gray-100 rounded-lg`}>
            <Menu size={24} />
          </button>

          <div className="flex-1 text-center font-bold text-rose-800 text-lg hidden sm:block">
            {settings?.programName || 'Soft Rose Modern Trade'}
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsNotificationOpen(true)}
              className="relative p-2 hover:bg-gray-100 rounded-full"
            >
              <Bell size={22} className="text-gray-600" />
              {notifications.length > 0 && <span className="absolute top-0 right-0 w-2 h-2 bg-rose-500 rounded-full"></span>}
            </button>

            {settings?.whatsappNumber && (
              <a 
                href={`https://wa.me/${settings.whatsappNumber}`} 
                target="_blank"
                className="flex items-center gap-2 bg-green-500 text-white px-3 py-1.5 rounded-full text-sm hover:bg-green-600 transition"
              >
                <MessageCircle size={18} />
                <span className="hidden md:inline">تواصل واتس اب</span>
              </a>
            )}
          </div>
        </header>

        {/* Ticker */}
        {settings && (settings.tickerText || settings.showDailySalesTicker) && (
          <div className="bg-rose-100 py-1 text-rose-800 text-sm overflow-hidden border-b">
            <div className="ticker-container">
              <div className="ticker-text px-4">
                {settings.tickerText} {settings.showDailySalesTicker && " | مبيعات اليوم الأعلى: محلاوي الحي العاشر 5000ج"}
              </div>
            </div>
          </div>
        )}

        {/* Views */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6">
          {activeTab === 'daily-sales' && <DailySales user={user} markets={markets} />}
          {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets} users={users} />}
          {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets} />}
          {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets} users={users} />}
          {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets} />}
          {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets} />}
          {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} />}
          {activeTab === 'settings' && user.role === 'admin' && <Settings user={user} settings={settings} users={users} />}
        </div>
      </main>

      {/* Notification Modal */}
      {isNotificationOpen && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-md p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-xl font-bold">الإشعارات</h3>
              <button onClick={() => setIsNotificationOpen(false)}><X/></button>
            </div>
            <div className="space-y-3">
              {notifications.length === 0 ? (
                <p className="text-gray-500 text-center py-8">لا توجد إشعارات حالياً</p>
              ) : (
                notifications.map((n, i) => (
                  <div key={i} className="p-3 border rounded-lg bg-gray-50">
                    <p>{n.message}</p>
                  </div>
                ))
              )}
            </div>
            <button 
              onClick={() => setIsNotificationOpen(false)}
              className="w-full mt-6 bg-rose-600 text-white py-2 rounded-lg"
            >
              إغلاق
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, SaleItem, DailySale } from '../types';
import { PRODUCT_GROUPS } from '../constants';
import { Plus, Trash2, Save } from 'lucide-react';
import { db, ref, push, set } from '../firebase';

interface Props {
  user: User;
  markets: string[];
}

const DailySales: React.FC<Props> = ({ user, markets }) => {
  const [selectedMarket, setSelectedMarket] = useState('');
  const [items, setItems] = useState<SaleItem[]>([]);
  const [customProducts, setCustomProducts] = useState<string[]>([]);

  const addProductRow = () => {
    setItems([...items, { id: Date.now().toString(), category: '', productName: '', price: 0, quantity: 0 }]);
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const updateItem = (id: string, field: keyof SaleItem, value: any) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const calculateTotal = () => {
    return items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  };

  const handleSave = async () => {
    if (!selectedMarket || items.length === 0) {
      alert("يرجى اختيار ماركت وإضافة أصناف");
      return;
    }

    const sale: Partial<DailySale> = {
      userId: user.id,
      userName: user.employeeName,
      marketName: selectedMarket,
      date: new Date().toISOString(),
      items,
      total: calculateTotal()
    };

    try {
      const salesRef = ref(db, 'sales');
      await push(salesRef, sale);
      alert("تم الحفظ والترحيل بنجاح");
      setItems([]);
      setSelectedMarket('');
    } catch (e) {
      alert("حدث خطأ أثناء الحفظ");
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white rounded-xl shadow-sm border p-6">
        <h2 className="text-2xl font-bold text-rose-800 mb-6">المبيعات اليومية</h2>

        <div className="flex flex-col md:flex-row gap-4 mb-6">
          <div className="flex-1">
            <label className="block text-sm font-medium mb-1">اسم الماركت</label>
            <div className="flex gap-2">
              <select 
                className="flex-1 border rounded-lg p-2"
                value={selectedMarket}
                onChange={(e) => setSelectedMarket(e.target.value)}
              >
                <option value="">اختر الماركت</option>
                {markets.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
              <button className="bg-rose-100 text-rose-700 px-3 py-2 rounded-lg hover:bg-rose-200">
                اضف ماركت
              </button>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          {/* Facial Group */}
          <div>
            <div className="bg-gray-200 p-2 font-bold mb-3 rounded">مناديل السحب</div>
            {items.filter(i => i.category === 'facial').map(item => (
              <div key={item.id} className="grid grid-cols-1 md:grid-cols-4 gap-2 mb-2 items-end">
                <select 
                  className="border rounded p-2"
                  value={item.productName}
                  onChange={(e) => updateItem(item.id, 'productName', e.target.value)}
                >
                  <option value="">اختر الصنف</option>
                  {PRODUCT_GROUPS.facial.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <input 
                  type="number" placeholder="السعر" className="border rounded p-2"
                  value={item.price || ''} onChange={(e) => updateItem(item.id, 'price', Number(e.target.value))}
                />
                <input 
                  type="number" placeholder="الكمية" className="border rounded p-2"
                  value={item.quantity || ''} onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))}
                />
                <button onClick={() => removeItem(item.id)} className="text-red-500 p-2 hover:bg-red-50 rounded"><Trash2 size={20}/></button>
              </div>
            ))}
            <button 
              onClick={() => setItems([...items, { id: Math.random().toString(), category: 'facial', productName: '', price: 0, quantity: 0 }])}
              className="flex items-center gap-2 text-rose-600 font-medium hover:underline text-sm"
            >
              <Plus size={16}/> اضف منتج (Facial)
            </button>
          </div>

          {/* Kitchen Group */}
          <div>
            <div className="bg-gray-200 p-2 font-bold mb-3 rounded">مناديل مطبخ</div>
            {items.filter(i => i.category === 'kitchen').map(item => (
              <div key={item.id} className="grid grid-cols-1 md:grid-cols-4 gap-2 mb-2 items-end">
                <select className="border rounded p-2" value={item.productName} onChange={(e) => updateItem(item.id, 'productName', e.target.value)}>
                  <option value="">اختر الصنف</option>
                  {PRODUCT_GROUPS.kitchen.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <input type="number" placeholder="السعر" className="border rounded p-2" value={item.price || ''} onChange={(e) => updateItem(item.id, 'price', Number(e.target.value))} />
                <input type="number" placeholder="الكمية" className="border rounded p-2" value={item.quantity || ''} onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))} />
                <button onClick={() => removeItem(item.id)} className="text-red-500 p-2 hover:bg-red-50 rounded"><Trash2 size={20}/></button>
              </div>
            ))}
            <button onClick={() => setItems([...items, { id: Math.random().toString(), category: 'kitchen', productName: '', price: 0, quantity: 0 }])} className="flex items-center gap-2 text-rose-600 font-medium hover:underline text-sm">
              <Plus size={16}/> اضف منتج (Kitchen)
            </button>
          </div>

          {/* Toilet Group */}
          <div>
            <div className="bg-gray-200 p-2 font-bold mb-3 rounded">مناديل تواليت</div>
            {items.filter(i => i.category === 'toilet').map(item => (
              <div key={item.id} className="grid grid-cols-1 md:grid-cols-4 gap-2 mb-2 items-end">
                <select className="border rounded p-2" value={item.productName} onChange={(e) => updateItem(item.id, 'productName', e.target.value)}>
                  <option value="">اختر الصنف</option>
                  {PRODUCT_GROUPS.toilet.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <input type="number" placeholder="السعر" className="border rounded p-2" value={item.price || ''} onChange={(e) => updateItem(item.id, 'price', Number(e.target.value))} />
                <input type="number" placeholder="الكمية" className="border rounded p-2" value={item.quantity || ''} onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))} />
                <button onClick={() => removeItem(item.id)} className="text-red-500 p-2 hover:bg-red-50 rounded"><Trash2 size={20}/></button>
              </div>
            ))}
            <button onClick={() => setItems([...items, { id: Math.random().toString(), category: 'toilet', productName: '', price: 0, quantity: 0 }])} className="flex items-center gap-2 text-rose-600 font-medium hover:underline text-sm">
              <Plus size={16}/> اضف منتج (Toilet)
            </button>
          </div>
        </div>

        <div className="mt-10 pt-6 border-t flex flex-col items-center gap-4">
          <div className="text-xl font-bold text-gray-800">
            إجمالي المبيعات: <span className="text-rose-600">{calculateTotal().toLocaleString()} ج.م</span>
          </div>
          <button 
            onClick={handleSave}
            className="w-full md:w-64 bg-rose-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-rose-700 transition"
          >
            <Save size={20}/> حفظ وترحيل
          </button>
        </div>
      </div>
    </div>
  );
};

export default DailySales;

import React, { useState, useEffect } from 'react';
import { User, DailySale } from '../types';
import { Search, Download, Trash2, Edit } from 'lucide-react';
import { db, ref, onValue, remove, update } from '../firebase';
import * as XLSX from 'xlsx';

interface Props {
  user: User;
  markets: string[];
  users: User[];
}

const SalesHistory: React.FC<Props> = ({ user, markets, users }) => {
  const [sales, setSales] = useState<DailySale[]>([]);
  const [filters, setFilters] = useState({
    date: '',
    employeeId: '',
    marketName: ''
  });

  useEffect(() => {
    const salesRef = ref(db, 'sales');
    onValue(salesRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        let salesList = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));

        // Filter based on user permissions
        if (user.role !== 'admin' && !user.canSeeAllSales) {
          salesList = salesList.filter(s => s.userId === user.id);
        }

        setSales(salesList);
      }
    });
  }, [user]);

  const filteredSales = sales.filter(s => {
    const matchDate = filters.date ? s.date.startsWith(filters.date) : true;
    const matchEmp = filters.employeeId ? s.userId === filters.employeeId : true;
    const matchMarket = filters.marketName ? s.marketName === filters.marketName : true;
    return matchDate && matchEmp && matchMarket;
  });

  const handleDelete = async (id: string) => {
    if (confirm("هل أنت متأكد من حذف هذه المبيعات؟")) {
      await remove(ref(db, `sales/${id}`));
    }
  };

  const exportExcel = () => {
    const data = filteredSales.flatMap(s => s.items.map(item => ({
      'الموظف': s.userName,
      'التاريخ': new Date(s.date).toLocaleDateString('ar-EG'),
      'الماركت': s.marketName,
      'الصنف': item.productName,
      'السعر': item.price,
      'الكمية': item.quantity,
      'الإجمالي': item.price * item.quantity
    })));

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "المبيعات");
    XLSX.writeFile(wb, `مبيعات_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border">
        <h2 className="text-2xl font-bold text-rose-800 mb-6">سجل المبيعات</h2>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
          <input 
            type="date" className="border rounded-lg p-2"
            onChange={(e) => setFilters({...filters, date: e.target.value})}
          />
          <select className="border rounded-lg p-2" onChange={(e) => setFilters({...filters, employeeId: e.target.value})}>
            <option value="">كل الموظفين</option>
            {users.map(u => <option key={u.id} value={u.id}>{u.employeeName}</option>)}
          </select>
          <select className="border rounded-lg p-2" onChange={(e) => setFilters({...filters, marketName: e.target.value})}>
            <option value="">كل الماركت</option>
            {markets.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
          <button onClick={exportExcel} className="bg-green-600 text-white rounded-lg flex items-center justify-center gap-2 px-4 hover:bg-green-700">
            <Download size={20}/> تصدير اكسيل
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-gray-50 border-b">
                <th className="p-3 text-right">التاريخ</th>
