import React, { useState } from 'react';
import { User, AppSettings, Market, Company, Notification } from '../types';
import { db, ref, update, set, push, remove } from '../firebase';
import { 
  Save, UserPlus, Shield, MessageCircle, AlertCircle, 
  Store, Building2, UserCog, Send, Trash2, Edit,
  // Fix: Added missing SettingsIcon import
  Settings as SettingsIcon
} from 'lucide-react';

interface Props {
  user: User;
  settings: AppSettings | null;
  users: User[];
  markets: Market[];
  companies: Company[];
}

const Settings: React.FC<Props> = ({ user, settings, users, markets, companies }) => {
  const [activeSubTab, setActiveSubTab] = useState('general');
  const [newTickerText, setNewTickerText] = useState(settings?.tickerText || '');
  const [newProgramName, setNewProgramName] = useState(settings?.programName || '');
  const [whatsapp, setWhatsapp] = useState(settings?.whatsappNumber || '');

  // User Management States
  const [newUser, setNewUser] = useState({ username: '', password: '', employeeName: '', role: 'user' as const });
  const [editingPermissions, setEditingPermissions] = useState<string | null>(null);
  const [messageTarget, setMessageTarget] = useState<string | null>(null);
  const [messageText, setMessageText] = useState('');

  // Market/Company States
  const [newItemName, setNewItemName] = useState('');

  const handleSaveGeneral = async () => {
    await update(ref(db, 'settings'), {
      tickerText: newTickerText,
      programName: newProgramName,
      whatsappNumber: whatsapp
    });
    alert("تم حفظ الإعدادات العامة");
  };

  const handleAddUser = async () => {
    if (!newUser.username || !newUser.password) return;
    const newId = push(ref(db, 'users')).key || '';
    await set(ref(db, `users/${newId}`), {
      ...newUser,
      id: newId,
      isOnline: false,
      permissions: {
        viewColleaguesSales: false,
        viewSalesHistory: true,
        registerInventory: true,
        viewInventoryHistory: true,
        viewCompetitorReports: true,
        viewCompetitorPrices: true,
      },
      vacationBalance: { annual: 21, casual: 7, sick: 15, exams: 0 }
    });
    setNewUser({ username: '', password: '', employeeName: '', role: 'user' });
  };

  const togglePerm = async (userId: string, perm: string, current: boolean) => {
    await update(ref(db, `users/${userId}/permissions`), { [perm]: !current });
  };

  const sendNotification = async () => {
    if (!messageText || !messageTarget) return;
    await push(ref(db, 'notifications'), {
      senderId: user.id,
      receiverId: messageTarget,
      message: messageText,
      timestamp: new Date().toISOString(),
      isRead: false
    });
    setMessageText('');
    setMessageTarget(null);
    alert('تم إرسال الرسالة');
  };

  const addItem = async (type: 'markets' | 'companies') => {
    if (!newItemName) return;
    await push(ref(db, type), { name: newItemName });
    setNewItemName('');
  };

  return (
    <div className="space-y-6">
      {/* Settings Navigation */}
      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
        {[
          { id: 'general', label: 'إعدادات عامة', icon: <SettingsIcon size={18}/> },
          { id: 'users', label: 'الموظفون والصلاحيات', icon: <UserCog size={18}/> },
          { id: 'markets', label: 'إدارة الماركتات', icon: <Store size={18}/> },
          { id: 'companies', label: 'إدارة الشركات', icon: <Building2 size={18}/> },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id)}
            className={`flex items-center gap-2 px-6 py-3 rounded-2xl whitespace-nowrap transition-all font-bold ${activeSubTab === tab.id ? 'bg-rose-800 text-white shadow-lg' : 'bg-white text-gray-600 hover:bg-rose-50'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'general' && (
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-rose-100">
          <h3 className="text-xl font-black text-rose-900 mb-8">الإعدادات العامة للنظام</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-500 mr-2">اسم البرنامج</label>
              <input 
                className="w-full bg-slate-50 rounded-2xl p-4 border-2 border-transparent focus:border-rose-200 outline-none"
                value={newProgramName} onChange={e => setNewProgramName(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-500 mr-2">رقم واتساب الدعم</label>
              <input 
                className="w-full bg-slate-50 rounded-2xl p-4 border-2 border-transparent focus:border-rose-200 outline-none"
                value={whatsapp} onChange={e => setWhatsapp(e.target.value)}
              />
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-sm font-bold text-gray-500 mr-2">نص الشريط المتحرك (Ticker)</label>
              <textarea 
                className="w-full bg-slate-50 rounded-2xl p-4 border-2 border-transparent focus:border-rose-200 outline-none h-32"
                value={newTickerText} onChange={e => setNewTickerText(e.target.value)}
              />
            </div>
          </div>
          <button onClick={handleSaveGeneral} className="bg-rose-800 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-rose-200 hover:scale-[1.02] transition-all">حفظ الإعدادات العامة</button>
        </div>
      )}

      {activeSubTab === 'users' && (
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-rose-100">
            <h3 className="text-xl font-black text-rose-900 mb-6 flex items-center gap-2">
              <UserPlus className="text-rose-600"/> إضافة موظف جديد
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <input className="bg-slate-50 p-4 rounded-2xl outline-none" placeholder="الاسم الكامل" value={newUser.employeeName} onChange={e => setNewUser({...newUser, employeeName: e.target.value})}/>
              <input className="bg-slate-50 p-4 rounded-2xl outline-none" placeholder="اسم المستخدم" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})}/>
              <input className="bg-slate-50 p-4 rounded-2xl outline-none" type="password" placeholder="كلمة المرور" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})}/>
              <select className="bg-slate-50 p-4 rounded-2xl outline-none" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as any})}>
                <option value="user">موظف</option>
                <option value="admin">مدير</option>
              </select>
            </div>
            <button onClick={handleAddUser} className="mt-6 bg-blue-600 text-white px-8 py-3 rounded-xl font-bold">إضافة الموظف</button>
          </div>

          <div className="bg-white p-0 rounded-[2.5rem] shadow-sm border border-rose-100 overflow-hidden">
            <table className="w-full text-right">
              <thead className="bg-slate-50 text-gray-500 text-xs uppercase tracking-widest font-bold">
                <tr>
                  <th className="p-6">الموظف</th>
                  <th className="p-6">الوظيفة</th>
                  <th className="p-6">إجراءات</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {users.map(u => (
                  <tr key={u.id} className="hover:bg-rose-50/30 transition-colors">
                    <td className="p-6">
                      <div className="flex items-center gap-3">
                        <div className={`w-3 h-3 rounded-full ${u.isOnline ? 'bg-blue-500 animate-pulse' : 'bg-rose-200'}`}></div>
                        <div>
                          <p className="font-bold text-gray-800">{u.employeeName}</p>
                          <p className="text-xs text-gray-400">@{u.username}</p>
                        </div>
                      </div>
                    </td>
                    <td className="p-6 text-sm font-medium">{u.role === 'admin' ? 'مدير نظام' : 'مندوب'}</td>
                    <td className="p-6">
                      <div className="flex gap-2">
                        <button onClick={() => setMessageTarget(u.id)} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100" title="إرسال رسالة"><Send size={18}/></button>
                        <button onClick={() => setEditingPermissions(u.id)} className="p-2 bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100" title="الصلاحيات"><Shield size={18}/></button>
                        <button className="p-2 bg-gray-50 text-gray-600 rounded-lg hover:bg-gray-100"><Edit size={18}/></button>
                        <button onClick={() => remove(ref(db, `users/${u.id}`))} className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-100"><Trash2 size={18}/></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {(activeSubTab === 'markets' || activeSubTab === 'companies') && (
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-rose-100">
          <h3 className="text-xl font-black text-rose-900 mb-6">إدارة {activeSubTab === 'markets' ? 'الماركتات' : 'الشركات المنافسة'}</h3>
          <div className="flex gap-2 mb-8">
            <input 
              className="flex-1 bg-slate-50 p-4 rounded-2xl outline-none font-bold" 
              placeholder={`اسم ال${activeSubTab === 'markets' ? 'ماركت' : 'شركة'}`} 
              value={newItemName}
              onChange={e => setNewItemName(e.target.value)}
            />
            <button onClick={() => addItem(activeSubTab as any)} className="bg-rose-800 text-white px-8 rounded-2xl font-bold">إضافة</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
            {(activeSubTab === 'markets' ? markets : companies).map(item => (
              <div key={item.id} className="p-4 bg-slate-50 rounded-2xl flex items-center justify-between group">
                <span className="font-bold text-gray-700">{item.name}</span>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button className="p-2 text-blue-600 hover:bg-blue-100 rounded-lg"><Edit size={16}/></button>
                  <button onClick={() => remove(ref(db, `${activeSubTab}/${item.id}`))} className="p-2 text-red-600 hover:bg-red-100 rounded-lg"><Trash2 size={16}/></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Permissions Modal */}
      {editingPermissions && (
        <div className="fixed inset-0 bg-black/50 z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] p-8 max-w-md w-full">
            <h4 className="text-lg font-black mb-6 border-b pb-4 text-rose-900">إدارة صلاحيات الموظف</h4>
            <div className="space-y-4">
              {users.find(u => u.id === editingPermissions)?.permissions && Object.entries(users.find(u => u.id === editingPermissions)!.permissions).map(([key, val]: any) => (
                <label key={key} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl cursor-pointer hover:bg-slate-100 transition">
                  <span className="text-sm font-bold text-gray-600">
                    {key === 'viewColleaguesSales' ? 'رؤية مبيعات الزملاء' : 
                     key === 'viewSalesHistory' ? 'رؤية سجل المبيعات' :
                     key === 'registerInventory' ? 'تسجيل المخزون' :
                     key === 'viewInventoryHistory' ? 'رؤية سجل المخزون' :
                     key === 'viewCompetitorReports' ? 'رؤية تقارير المنافسين' : 'رؤية أسعار المنافسين'}
                  </span>
                  <input 
                    type="checkbox" 
                    className="w-5 h-5 accent-rose-600" 
                    checked={val} 
                    onChange={() => togglePerm(editingPermissions, key, val)}
                  />
                </label>
              ))}
            </div>
            <button onClick={() => setEditingPermissions(null)} className="w-full mt-8 bg-rose-800 text-white py-4 rounded-2xl font-black">حفظ وإغلاق</button>
          </div>
        </div>
      )}

      {/* Message Modal */}
      {messageTarget && (
        <div className="fixed inset-0 bg-black/50 z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] p-8 max-w-md w-full">
            <h4 className="text-lg font-black mb-6 text-rose-900">إرسال رسالة إدارية</h4>
            <textarea 
              className="w-full bg-slate-50 p-4 rounded-2xl outline-none h-40 border-2 border-transparent focus:border-rose-200"
              placeholder="اكتب نص الرسالة هنا..."
              value={messageText}
              onChange={e => setMessageText(e.target.value)}
            ></textarea>
            <div className="flex gap-3 mt-6">
              <button onClick={sendNotification} className="flex-1 bg-rose-800 text-white py-4 rounded-2xl font-black">إرسال الآن</button>
              <button onClick={() => setMessageTarget(null)} className="flex-1 bg-gray-100 text-gray-600 py-4 rounded-2xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Settings;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Users, ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, MessageCircle, Calendar,
  Loader2, Wifi, WifiOff, Palette, Copy, Trash2, User as UserIcon
} from 'lucide-react';
import { db, ref, onValue, set, update, push, remove } from './firebase';
import { User, AppSettings, Notification, AppTheme, Market, Company } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<AppTheme>('standard');
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    window.addEventListener('online', () => setIsOnline(true));
    window.addEventListener('offline', () => setIsOnline(false));

    // Sync settings
    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    // Sync users
    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) setUsers(Object.values(data));
    });

    // Sync markets & companies
    onValue(ref(db, 'markets'), (snapshot) => {
      const data = snapshot.val();
      if (data) setMarkets(Object.entries(data).map(([id, val]: any) => ({ id, name: val.name })));
    });
    onValue(ref(db, 'companies'), (snapshot) => {
      const data = snapshot.val();
      if (data) setCompanies(Object.entries(data).map(([id, val]: any) => ({ id, name: val.name })));
    });

    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (user) {
      const notifRef = ref(db, 'notifications');
      onValue(notifRef, (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const allNotifs = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
          const myNotifs = allNotifs.filter(n => n.receiverId === 'all' || n.receiverId === user.id);
          setNotifications(myNotifs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
        } else {
          setNotifications([]);
        }
      });
    }
  }, [user]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user && user.id !== 'admin-id') {
      update(ref(db, `users/${user.id}`), { isOnline: false });
    }
    setUser(null);
  };

  const deleteNotification = (id: string) => {
    remove(ref(db, `notifications/${id}`));
  };

  const copyNotifText = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('تم نسخ نص الرسالة');
  };

  const cycleTheme = () => {
    if (theme === 'standard') setTheme('glass');
    else if (theme === 'glass') setTheme('dark');
    else setTheme('standard');
  };

  if (isLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-rose-50">
      <Loader2 className="animate-spin text-rose-600 mb-4" size={48}/>
      <p className="text-rose-900 font-bold animate-pulse">جاري تحميل نظام Soft Rose...</p>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} />;

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: true },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: user.role === 'admin' || user.permissions?.viewSalesHistory },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: user.role === 'admin' || user.permissions?.registerInventory },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: user.role === 'admin' || user.permissions?.viewInventoryHistory },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: user.role === 'admin' || user.permissions?.viewCompetitorPrices },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: user.role === 'admin' || user.permissions?.viewCompetitorReports },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: true },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user.role === 'admin' },
  ].filter(i => i.visible);

  return (
    <div className={`flex h-screen overflow-hidden theme-${theme} transition-all duration-300 relative`}>
      {/* Overlay for auto-closing sidebar on mobile */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`bg-rose-900 text-white w-72 flex-shrink-0 transition-all duration-300 z-50 fixed md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:right-0'} ${theme === 'glass' ? 'bg-rose-900/70 backdrop-blur-xl border-l border-white/10' : ''} shadow-2xl`}>
        <div className="p-6 flex flex-col h-full">
          <div className="mb-8 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-widest text-rose-300">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 hover:bg-white/10 rounded-full"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-1.5 overflow-y-auto custom-scrollbar pr-2">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all duration-200 ${activeTab === item.id ? 'bg-white text-rose-900 font-bold shadow-xl shadow-black/10' : 'hover:bg-white/10 opacity-80 hover:opacity-100'}`}
              >
                <span className={activeTab === item.id ? 'text-rose-600' : 'text-white'}>{item.icon}</span>
                <span className="text-sm">{item.label}</span>
              </button>
            ))}

            {/* Admin-only connection list */}
            {user.role === 'admin' && (
              <div className="mt-10 pt-6 border-t border-white/10">
                <p className="text-[10px] uppercase text-rose-400 px-5 mb-4 font-black tracking-widest">الموظفون المتصلون</p>
                <div className="space-y-3">
                  {users.map(u => (
                    <div key={u.id} className="flex items-center gap-3 px-5">
                      <div className="relative">
                        <div className={`w-2.5 h-2.5 rounded-full ${u.isOnline ? 'bg-blue-400 shadow-[0_0_8px_rgba(96,165,250,0.8)]' : 'bg-rose-800'}`}></div>
                      </div>
                      <span className={`text-xs font-bold ${u.isOnline ? 'text-white' : 'text-rose-400/60'}`}>{u.employeeName}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </nav>

          <div className="mt-4 text-[10px] text-center text-rose-400/40 uppercase font-bold tracking-widest">
            System v3.0.0 Stable
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className={`flex-1 flex flex-col min-w-0 overflow-hidden ${theme === 'dark' ? 'bg-[#0a0a0a]' : 'bg-[#F9FAFB]'}`}>
        {/* Header */}
        <header className={`h-20 flex items-center justify-between px-8 border-b transition-all duration-300 z-30 ${theme === 'glass' ? 'bg-white/40 backdrop-blur-md border-white/20 shadow-sm' : 'bg-white shadow-sm'} ${theme === 'dark' ? 'bg-[#121212] border-[#222]' : ''}`}>
          <div className="flex items-center gap-6">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-3 hover:bg-rose-50 rounded-2xl transition-all">
              <Menu size={24} className="text-rose-800" />
            </button>
            <div className="flex flex-col">
              <h2 className="font-black text-rose-900 text-lg md:text-2xl tracking-tighter uppercase leading-tight">
                {settings?.programName || 'Soft Rose Modern Trade'}
              </h2>
              <div className="flex items-center gap-2 mt-0.5">
                <div className={`w-2 h-2 rounded-full ${isOnline ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest flex items-center gap-1">
                  {user.employeeName} <span className="opacity-30">|</span> {user.role === 'admin' ? 'Manager' : 'Staff'}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* Connection & Theme Tools */}
            <div className="flex items-center bg-slate-100/50 p-1 rounded-2xl gap-1 mr-4 hidden sm:flex">
              <div className={`p-2 rounded-xl ${isOnline ? 'text-blue-600' : 'text-red-500'}`} title={isOnline ? 'متصل' : 'أنت غير متصل'}>
                {isOnline ? <Wifi size={18} /> : <WifiOff size={18} />}
              </div>
              <button 
                onClick={cycleTheme} 
                className="p-2.5 hover:bg-white hover:shadow-md rounded-xl text-gray-500 transition-all group"
                title="تغيير ستايل البرنامج"
              >
                <Palette size={20} className="group-hover:rotate-12 transition-transform" />
              </button>
            </div>

            {settings?.whatsappNumber && (
              <a 
                href={`https://wa.me/${settings.whatsappNumber}`} 
                target="_blank" 
                className="p-3 bg-green-500 text-white rounded-2xl hover:bg-green-600 hover:scale-105 transition-all shadow-lg shadow-green-100"
                title="تواصل واتساب"
              >
                <MessageCircle size={22} />
              </a>
            )}

            <div className="h-8 w-px bg-gray-200 mx-2"></div>

            <button 
              onClick={() => setIsNotificationOpen(true)} 
              className="relative p-3 hover:bg-rose-50 rounded-2xl group transition-all"
              title="الإشعارات والرسائل"
            >
              <Bell size={24} className="text-gray-500 group-hover:text-rose-600" />
              {unreadCount > 0 && (
                <span className="absolute top-2.5 right-2.5 w-3.5 h-3.5 bg-red-600 border-2 border-white rounded-full animate-pulse shadow-sm"></span>
              )}
            </button>

            <button 
              onClick={handleLogout} 
              className="flex items-center gap-2 p-3 bg-rose-50 text-rose-800 rounded-2xl hover:bg-rose-100 hover:text-rose-900 transition-all font-bold text-sm border border-rose-100"
              title="تسجيل الخروج"
            >
              <LogOut size={20} />
              <span className="hidden lg:inline">خروج</span>
            </button>
          </div>
        </header>

        {/* Ticker Section */}
        {settings?.tickerText && (
          <div className="bg-rose-950 py-2 text-white text-[13px] overflow-hidden border-b border-rose-900/50 shadow-inner">
            <div className="ticker-container">
              <div className="ticker-text font-bold opacity-90" style={{ animationDuration: '45s' }}>
                {settings.tickerText} &nbsp;&nbsp; ★ &nbsp;&nbsp; {settings.tickerText} &nbsp;&nbsp; ★ &nbsp;&nbsp; {settings.tickerText}
              </div>
            </div>
          </div>
        )}

        {/* Views Router */}
        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar" onClick={() => isSidebarOpen && setIsSidebarOpen(false)}>
          <div className="max-w-7xl mx-auto animate-in fade-in slide-in-from-bottom-2 duration-500">
            {activeTab === 'daily-sales' && <DailySales user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} />}
            {activeTab === 'settings' && <Settings user={user} settings={settings} users={users} markets={markets} companies={companies} />}
          </div>
        </div>
      </main>

      {/* Notification Modal */}
      {isNotificationOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-in fade-in duration-300" onClick={() => setIsNotificationOpen(false)}>
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg overflow-hidden shadow-2xl animate-in zoom-in-95 duration-300" onClick={e => e.stopPropagation()}>
            <div className="bg-rose-900 p-8 text-white flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black tracking-tight">صندوق الرسائل</h3>
                <p className="text-rose-300 text-xs font-bold uppercase mt-1">Admin Communication Center</p>
              </div>
              <button onClick={() => setIsNotificationOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <X size={28}/>
              </button>
            </div>
            <div className="p-8 max-h-[60vh] overflow-y-auto space-y-6 custom-scrollbar bg-slate-50/50">
              {notifications.length === 0 ? (
                <div className="text-center py-20">
                  <Bell className="mx-auto text-gray-200 mb-4" size={60} />
                  <p className="text-gray-400 font-bold">لا توجد رسائل جديدة في بريدك</p>
                </div>
              ) : (
                notifications.map(n => (
                  <div key={n.id} className="p-6 bg-white rounded-3xl border border-rose-100 shadow-sm relative group hover:shadow-md transition-all">
                    <div className="flex items-start gap-4">
                      <div className="w-10 h-10 rounded-2xl bg-rose-50 flex items-center justify-center text-rose-600">
                        <UserIcon size={20} />
                      </div>
                      <div className="flex-1">
                        <p className="text-[15px] font-bold text-gray-800 leading-relaxed mb-4">{n.message}</p>
                        <div className="flex items-center justify-between">
                          <span className="text-[10px] text-rose-300 font-black uppercase tracking-widest bg-rose-50 px-3 py-1 rounded-full">
                            {new Date(n.timestamp).toLocaleDateString('ar-EG')} - {new Date(n.timestamp).toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'})}
                          </span>
                          <div className="flex gap-2">
                            <button onClick={() => copyNotifText(n.message)} className="p-2.5 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all" title="نسخ"><Copy size={16}/></button>
                            <button onClick={() => deleteNotification(n.id)} className="p-2.5 bg-slate-50 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all" title="حذف"><Trash2 size={16}/></button>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
            <div className="p-6 border-t bg-white text-center">
               <button onClick={() => setIsNotificationOpen(false)} className="px-10 py-3 bg-rose-800 text-white rounded-2xl font-black text-sm hover:bg-rose-900 transition-all shadow-lg shadow-rose-100">إغلاق التنبيهات</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, AppSettings, Market, Company, Notification } from '../types';
import { db, ref, update, set, push, remove } from '../firebase';
import { 
  Save, UserPlus, Shield, MessageCircle, AlertCircle, 
  Store, Building2, UserCog, Send, Trash2, Edit,
  Settings as SettingsIcon, Key, UserCheck
} from 'lucide-react';

interface Props {
  user: User;
  settings: AppSettings | null;
  users: User[];
  markets: Market[];
  companies: Company[];
}

const Settings: React.FC<Props> = ({ user, settings, users, markets, companies }) => {
  const [activeSubTab, setActiveSubTab] = useState('general');
  const [newTickerText, setNewTickerText] = useState(settings?.tickerText || '');
  const [newProgramName, setNewProgramName] = useState(settings?.programName || '');
  const [whatsapp, setWhatsapp] = useState(settings?.whatsappNumber || '');

  // User Management States
  const [newUser, setNewUser] = useState({ username: '', password: '', employeeName: '', role: 'user' as const });
  const [editingPermissions, setEditingPermissions] = useState<string | null>(null);
  const [editingCredentials, setEditingCredentials] = useState<User | null>(null);
  const [messageTarget, setMessageTarget] = useState<string | null>(null);
  const [messageText, setMessageText] = useState('');

  // Market/Company States
  const [newItemName, setNewItemName] = useState('');
  const [editItem, setEditItem] = useState<{id: string, name: string, type: 'markets' | 'companies'} | null>(null);

  const handleSaveGeneral = async () => {
    await update(ref(db, 'settings'), {
      tickerText: newTickerText,
      programName: newProgramName,
      whatsappNumber: whatsapp
    });
    alert("تم حفظ الإعدادات العامة بنجاح");
  };

  const handleAddUser = async () => {
    if (!newUser.username || !newUser.password || !newUser.employeeName) {
      alert("يرجى إكمال كافة بيانات الموظف");
      return;
    }
    const newId = push(ref(db, 'users')).key || '';
    await set(ref(db, `users/${newId}`), {
      ...newUser,
      id: newId,
      isOnline: false,
      permissions: {
        viewColleaguesSales: false,
        viewSalesHistory: true,
        registerInventory: true,
        viewInventoryHistory: true,
        viewCompetitorReports: true,
        viewCompetitorPrices: true,
      },
      vacationBalance: { annual: 21, casual: 7, sick: 15, exams: 0 }
    });
    setNewUser({ username: '', password: '', employeeName: '', role: 'user' });
    alert("تمت إضافة الموظف بنجاح");
  };

  const handleUpdateCredentials = async () => {
    if (!editingCredentials) return;
    await update(ref(db, `users/${editingCredentials.id}`), {
      username: editingCredentials.username,
      password: editingCredentials.password,
      employeeName: editingCredentials.employeeName
    });
    setEditingCredentials(null);
    alert("تم تحديث بيانات الحساب");
  };

  const togglePerm = async (userId: string, perm: string, current: boolean) => {
    await update(ref(db, `users/${userId}/permissions`), { [perm]: !current });
  };

  const sendNotification = async () => {
    if (!messageText || !messageTarget) return;
    await push(ref(db, 'notifications'), {
      senderId: user.id,
      receiverId: messageTarget,
      message: messageText,
      timestamp: new Date().toISOString(),
      isRead: false
    });
    setMessageText('');
    setMessageTarget(null);
    alert('تم إرسال الرسالة بنجاح');
  };

  const addItem = async (type: 'markets' | 'companies') => {
    if (!newItemName) return;
    await push(ref(db, type), { name: newItemName });
    setNewItemName('');
  };

  const updateItemName = async () => {
    if (!editItem) return;
    await update(ref(db, `${editItem.type}/${editItem.id}`), { name: editItem.name });
    setEditItem(null);
  };

  const deleteUser = async (u: User) => {
    if (confirm(`هل أنت متأكد من حذف حساب ${u.employeeName}؟`)) {
      await remove(ref(db, `users/${u.id}`));
    }
  };

  return (
    <div className="space-y-8 pb-20">
      {/* Settings Navigation */}
      <div className="flex gap-3 overflow-x-auto pb-4 scrollbar-hide">
        {[
          { id: 'general', label: 'إعدادات عامة', icon: <SettingsIcon size={20}/> },
          { id: 'users', label: 'إدارة الموظفين', icon: <UserCog size={20}/> },
          { id: 'markets', label: 'إدارة الماركتات', icon: <Store size={20}/> },
          { id: 'companies', label: 'إدارة الشركات', icon: <Building2 size={20}/> },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id)}
            className={`flex items-center gap-3 px-8 py-4 rounded-2xl whitespace-nowrap transition-all font-black text-sm uppercase tracking-tight ${activeSubTab === tab.id ? 'bg-rose-800 text-white shadow-xl shadow-rose-200 scale-105' : 'bg-white text-gray-500 hover:bg-rose-50 border border-gray-100'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'general' && (
        <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-rose-50 animate-in fade-in duration-500">
          <h3 className="text-2xl font-black text-rose-900 mb-10 flex items-center gap-3">
            <SettingsIcon className="text-rose-600" /> الإعدادات العامة للنظام
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-10">
            <div className="space-y-3">
              <label className="text-xs font-black text-rose-400 uppercase tracking-widest mr-2">اسم البرنامج المعروض</label>
              <input 
                className="w-full bg-slate-50 rounded-2xl p-5 border-2 border-transparent focus:border-rose-200 outline-none font-bold text-rose-900 transition-all"
                value={newProgramName} onChange={e => setNewProgramName(e.target.value)}
              />
            </div>
            <div className="space-y-3">
              <label className="text-xs font-black text-rose-400 uppercase tracking-widest mr-2">رقم واتساب الدعم الفني</label>
              <input 
                className="w-full bg-slate-50 rounded-2xl p-5 border-2 border-transparent focus:border-rose-200 outline-none font-bold text-rose-900 transition-all"
                value={whatsapp} onChange={e => setWhatsapp(e.target.value)}
              />
            </div>
            <div className="md:col-span-2 space-y-3">
              <label className="text-xs font-black text-rose-400 uppercase tracking-widest mr-2">نص الشريط المتحرك (Ticker)</label>
              <textarea 
                className="w-full bg-slate-50 rounded-2xl p-6 border-2 border-transparent focus:border-rose-200 outline-none h-40 font-bold text-rose-900 leading-relaxed transition-all resize-none"
                placeholder="اكتب النص الذي سيظهر في الشريط المتحرك بالأعلى..."
                value={newTickerText} onChange={e => setNewTickerText(e.target.value)}
              />
            </div>
          </div>
          <div className="flex justify-end">
            <button onClick={handleSaveGeneral} className="bg-rose-800 text-white px-12 py-5 rounded-2xl font-black shadow-2xl shadow-rose-200 hover:scale-105 transition-all flex items-center gap-3">
              <Save size={20}/> حفظ الإعدادات العامة
            </button>
          </div>
        </div>
      )}

      {activeSubTab === 'users' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-rose-50">
            <h3 className="text-2xl font-black text-rose-900 mb-8 flex items-center gap-3">
              <UserPlus className="text-rose-600"/> إضافة موظف جديد
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-5">
              <input className="bg-slate-50 p-5 rounded-2xl outline-none font-bold text-sm border border-transparent focus:border-rose-200" placeholder="الاسم الكامل" value={newUser.employeeName} onChange={e => setNewUser({...newUser, employeeName: e.target.value})}/>
              <input className="bg-slate-50 p-5 rounded-2xl outline-none font-bold text-sm border border-transparent focus:border-rose-200" placeholder="اسم المستخدم" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})}/>
              <input className="bg-slate-50 p-5 rounded-2xl outline-none font-bold text-sm border border-transparent focus:border-rose-200" type="password" placeholder="كلمة المرور" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})}/>
              <select className="bg-slate-50 p-5 rounded-2xl outline-none font-black text-sm border border-transparent focus:border-rose-200" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as any})}>
                <option value="user">موظف (Staff)</option>
                <option value="admin">مدير (Manager)</option>
              </select>
            </div>
            <button onClick={handleAddUser} className="mt-8 bg-blue-600 text-white px-10 py-4 rounded-2xl font-black shadow-lg shadow-blue-100 hover:scale-105 transition-all">إضافة الموظف الآن</button>
          </div>

          <div className="bg-white rounded-[3rem] shadow-sm border border-rose-50 overflow-hidden">
            <div className="p-8 border-b bg-slate-50/50">
              <h4 className="font-black text-rose-900">قائمة حسابات الموظفين</h4>
            </div>
            <table className="w-full text-right">
              <thead className="bg-slate-50 text-gray-400 text-[10px] uppercase tracking-widest font-black">
                <tr>
                  <th className="p-8">الموظف</th>
                  <th className="p-8">الحالة والوظيفة</th>
                  <th className="p-8 text-center">الإجراءات والتحكم</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {users.map(u => (
                  <tr key={u.id} className="hover:bg-rose-50/30 transition-colors group">
                    <td className="p-8">
                      <div className="flex items-center gap-5">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg ${u.isOnline ? 'bg-blue-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                          {u.employeeName.charAt(0)}
                        </div>
                        <div>
                          <p className="font-black text-gray-800">{u.employeeName}</p>
                          <p className="text-xs text-gray-400 font-bold">@{u.username}</p>
                        </div>
                      </div>
                    </td>
                    <td className="p-8">
                      <div className="flex flex-col gap-1">
                        <span className={`text-[10px] font-black uppercase tracking-widest ${u.role === 'admin' ? 'text-purple-600' : 'text-blue-500'}`}>
                          {u.role === 'admin' ? 'مدير نظام' : 'مندوب مبيعات'}
                        </span>
                        <div className="flex items-center gap-2">
                           <div className={`w-2 h-2 rounded-full ${u.isOnline ? 'bg-blue-500 animate-pulse' : 'bg-rose-100'}`}></div>
                           <span className="text-[10px] font-bold text-gray-400 uppercase">{u.isOnline ? 'Online' : 'Offline'}</span>
                        </div>
                      </div>
                    </td>
                    <td className="p-8">
                      <div className="flex gap-2 justify-center">
                        <button onClick={() => setMessageTarget(u.id)} className="p-3 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm" title="إرسال رسالة"><Send size={18}/></button>
                        <button onClick={() => setEditingPermissions(u.id)} className="p-3 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-sm" title="الصلاحيات"><Shield size={18}/></button>
                        <button onClick={() => setEditingCredentials(u)} className="p-3 bg-amber-50 text-amber-600 rounded-xl hover:bg-amber-600 hover:text-white transition-all shadow-sm" title="تعديل الحساب"><Edit size={18}/></button>
                        <button onClick={() => deleteUser(u)} className="p-3 bg-red-50 text-red-600 rounded-xl hover:bg-red-600 hover:text-white transition-all shadow-sm" title="حذف الحساب"><Trash2 size={18}/></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {(activeSubTab === 'markets' || activeSubTab === 'companies') && (
        <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-rose-50 animate-in fade-in duration-500">
          <h3 className="text-2xl font-black text-rose-900 mb-8 flex items-center gap-3">
             {activeSubTab === 'markets' ? <Store className="text-rose-600" /> : <Building2 className="text-rose-600" />}
             إدارة {activeSubTab === 'markets' ? 'الماركتات' : 'الشركات المنافسة'}
          </h3>
          <div className="flex gap-4 mb-10">
            <input 
              className="flex-1 bg-slate-50 p-5 rounded-2xl outline-none font-bold text-sm border-2 border-transparent focus:border-rose-200" 
              placeholder={`أدخل اسم ال${activeSubTab === 'markets' ? 'ماركت' : 'شركة'} الجديد...`} 
              value={newItemName}
              onChange={e => setNewItemName(e.target.value)}
            />
            <button onClick={() => addItem(activeSubTab as any)} className="bg-rose-800 text-white px-12 rounded-2xl font-black shadow-xl shadow-rose-100 hover:scale-105 transition-all">إضافة</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {(activeSubTab === 'markets' ? markets : companies).map(item => (
              <div key={item.id} className="p-6 bg-slate-50 rounded-3xl flex items-center justify-between group hover:bg-rose-50 transition-all border border-transparent hover:border-rose-100">
                <span className="font-bold text-gray-700">{item.name}</span>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => setEditItem({ id: item.id, name: item.name, type: activeSubTab as any })} className="p-2.5 text-blue-600 hover:bg-white rounded-xl shadow-sm"><Edit size={16}/></button>
                  <button onClick={() => remove(ref(db, `${activeSubTab}/${item.id}`))} className="p-2.5 text-red-600 hover:bg-white rounded-xl shadow-sm"><Trash2 size={16}/></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Permissions Modal */}
      {editingPermissions && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] p-10 max-w-lg w-full shadow-2xl animate-in zoom-in-95">
            <div className="flex items-center gap-4 mb-8 border-b pb-6">
              <div className="w-12 h-12 rounded-2xl bg-rose-900 flex items-center justify-center text-white"><Shield /></div>
              <div>
                <h4 className="text-xl font-black text-rose-900">صلاحيات الموظف</h4>
                <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-0.5">Custom Access Control</p>
              </div>
            </div>
            <div className="space-y-3">
              {users.find(u => u.id === editingPermissions)?.permissions && Object.entries(users.find(u => u.id === editingPermissions)!.permissions).map(([key, val]: any) => (
                <label key={key} className="flex items-center justify-between p-5 bg-slate-50 rounded-2xl cursor-pointer hover:bg-rose-50 transition-all group">
                  <span className="text-sm font-bold text-gray-700 group-hover:text-rose-900 transition-colors">
                    {key === 'viewColleaguesSales' ? 'رؤية مبيعات الزملاء' : 
                     key === 'viewSalesHistory' ? 'رؤية سجل المبيعات' :
                     key === 'registerInventory' ? 'تسجيل المخزون' :
                     key === 'viewInventoryHistory' ? 'رؤية سجل المخزون' :
                     key === 'viewCompetitorReports' ? 'رؤية تقارير المنافسين' : 'رؤية أسعار المنافسين'}
                  </span>
                  <div className="relative inline-flex items-center cursor-pointer">
                    <input 
                      type="checkbox" 
                      className="sr-only peer" 
                      checked={val} 
                      onChange={() => togglePerm(editingPermissions, key, val)}
                    />
                    <div className="w-12 h-7 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-rose-700"></div>
                  </div>
                </label>
              ))}
            </div>
            <button onClick={() => setEditingPermissions(null)} className="w-full mt-10 bg-rose-900 text-white py-5 rounded-2xl font-black shadow-xl shadow-rose-100 hover:scale-105 transition-all">حفظ وإغلاق الصلاحيات</button>
          </div>
        </div>
      )}

