import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { PRODUCT_GROUPS } from '../constants';
import { Save, Plus, Package, PlusCircle } from 'lucide-react';
import { db, ref, push } from '../firebase';

interface Props {
  user: User;
  markets: string[];
}

const InventoryRegistration: React.FC<Props> = ({ user, markets }) => {
  const [selectedMarket, setSelectedMarket] = useState('');
  const [inventory, setInventory] = useState<Record<string, {name: string, quantity: number}>>({});
  const [manualProducts, setManualProducts] = useState<Record<string, string[]>>({
    facial: [], kitchen: [], hotel_toilet: [], dolphin: []
  });

  useEffect(() => {
    if (selectedMarket) {
      const initial: any = {};
      Object.entries(PRODUCT_GROUPS).forEach(([cat, products]) => {
        products.forEach(p => {
          initial[p] = { name: p, quantity: 0 };
        });
      });
      setInventory(initial);
    } else {
      setInventory({});
    }
  }, [selectedMarket]);

  const handleUpdateQuantity = (pKey: string, qty: number) => {
    setInventory(prev => ({ ...prev, [pKey]: { ...prev[pKey], quantity: qty } }));
  };

  const updateManualName = (pKey: string, name: string) => {
    setInventory(prev => ({ ...prev, [pKey]: { ...prev[pKey], name } }));
  };

  const addProductManual = (cat: string) => {
    const newKey = `manual-${cat}-${Date.now()}`;
    setInventory(prev => ({ ...prev, [newKey]: { name: '', quantity: 0 } }));
    setManualProducts(prev => ({ ...prev, [cat]: [...prev[cat], newKey] }));
  };

  const handleSave = async () => {
    if (!selectedMarket) {
      alert("يرجى اختيار ماركت");
      return;
    }

    // Fix: Explicitly cast Object.values to avoid 'unknown' type inference which causes property access errors
    const items = (Object.values(inventory) as Array<{name: string, quantity: number}>)
      .filter(i => i.quantity > 0 && i.name.trim() !== '')
      .map(i => ({ productName: i.name, quantity: i.quantity }));

    if (items.length === 0) {
      alert("يرجى إدخال كمية لمنتج واحد على الأقل واسم المنتج");
      return;
    }

    try {
      await push(ref(db, 'inventory'), {
        userId: user.id,
        userName: user.employeeName,
        marketName: selectedMarket,
        date: new Date().toISOString(),
        items
      });
      alert("تم ترحيل بيانات الجرد بنجاح، يمكنك مراجعتها في سجل المخزون");
      setInventory({});
      setSelectedMarket('');
    } catch (e) {
      alert("حدث خطأ أثناء الحفظ");
    }
  };

  const getCategoryLabel = (cat: string) => {
    switch(cat) {
      case 'facial': return 'مناديل سحب (Facial)';
      case 'kitchen': return 'مناديل مطبخ (Kitchen)';
      case 'hotel_toilet': return 'تواليت فنادق (Hotel Toilet)';
      case 'dolphin': return 'دولفن (Dolphin)';
      default: return cat;
    }
  };

  return (
    <div className="max-w-5xl mx-auto pb-20">
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-rose-50 p-8 md:p-10 animate-in fade-in duration-500">
        <div className="flex items-center gap-4 mb-8">
          <div className="p-4 bg-blue-100 text-blue-800 rounded-3xl">
            <Package size={28} />
          </div>
          <div>
            <h2 className="text-2xl font-black text-rose-900">تسجيل الجرد الفعلي</h2>
            <p className="text-rose-400 text-xs font-bold uppercase tracking-widest mt-1">Inventory Counting Sheet</p>
          </div>
        </div>

        <div className="mb-10 bg-slate-50 p-6 rounded-3xl border border-slate-100">
          <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3 mr-2">اختيار الماركت المراد جرده</label>
          <select 
            className="w-full bg-white border-2 border-transparent focus:border-blue-200 rounded-2xl p-4 outline-none font-bold text-gray-700 shadow-sm transition-all"
            value={selectedMarket}
            onChange={(e) => setSelectedMarket(e.target.value)}
          >
            <option value="">-- اضغط لاختيار الماركت --</option>
            {/* Fix: Corrected JSX syntax for map items */}
            {markets.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
        </div>

        {selectedMarket && (
          <div className="space-y-10 animate-in slide-in-from-bottom-4 duration-500">
            {/* Fix: Cast Object.keys to correct category array to prevent indexing errors */}
            {(Object.keys(PRODUCT_GROUPS) as Array<keyof typeof PRODUCT_GROUPS>).map((cat) => (
              <div key={cat}>
                <div className="bg-slate-100 px-6 py-3 font-black text-slate-600 rounded-2xl mb-4 text-sm flex items-center justify-between">
                  <span>{getCategoryLabel(cat)}</span>
                  <span className="text-[10px] bg-white px-3 py-1 rounded-full text-slate-400 uppercase tracking-widest">Category</span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {/* Standard Products */}
                  {/* Fix: Corrected key prop syntax */}
                  {PRODUCT_GROUPS[cat].map(p => (
                    <div key={p} className="p-4 bg-white border border-slate-100 rounded-2xl flex items-center justify-between group hover:border-blue-200 transition-all">
                      <span className="text-xs font-bold text-gray-600 flex-1 ml-4 leading-tight">{p}</span>
                      <input 
                        type="number" 
                        placeholder="0" 
                        className={`w-20 bg-slate-50 border-2 border-transparent focus:border-blue-200 rounded-xl p-2 text-center font-black outline-none transition-all ${inventory[p]?.quantity > 0 ? 'bg-blue-600 text-white' : 'text-gray-400'}`}
                        value={inventory[p]?.quantity || ''}
                        onChange={(e) => handleUpdateQuantity(p, Number(e.target.value))}
                      />
                    </div>
                  ))}

                  {/* Manual Products */}
                  {/* Fix: Corrected key prop syntax */}
                  {manualProducts[cat].map(mKey => (
                    <div key={mKey} className="p-4 bg-white border border-rose-200 rounded-2xl flex items-center gap-2 group transition-all">
                      <input 
                        placeholder="اسم الصنف الجديد..."
                        className="text-xs font-bold text-rose-800 flex-1 bg-rose-50 rounded-lg p-2 outline-none border-transparent focus:border-rose-200"
                        value={inventory[mKey]?.name || ''}
                        onChange={(e) => updateManualName(mKey, e.target.value)}
                      />
                      <input 
                        type="number" 
                        placeholder="0" 
                        className={`w-20 bg-slate-50 border-2 border-transparent focus:border-blue-200 rounded-xl p-2 text-center font-black outline-none transition-all ${inventory[mKey]?.quantity > 0 ? 'bg-blue-600 text-white' : 'text-gray-400'}`}
                        value={inventory[mKey]?.quantity || ''}
                        onChange={(e) => handleUpdateQuantity(mKey, Number(e.target.value))}
                      />
                    </div>
                  ))}
                </div>

                <button 
                  onClick={() => addProductManual(cat)}
                  className="mt-4 w-full py-3 border-2 border-dashed border-slate-200 rounded-2xl text-slate-400 font-black text-xs flex items-center justify-center gap-2 hover:bg-slate-50 hover:border-blue-200 hover:text-blue-600 transition-all"
                >
                  <PlusCircle size={18}/> إضافة منتج جديد لقسم {getCategoryLabel(cat)}
                </button>
              </div>
            ))}

            <div className="mt-12 pt-8 border-t border-slate-100">
              <button 
                onClick={handleSave}
                className="w-full bg-blue-600 text-white py-5 rounded-[2rem] font-black flex items-center justify-center gap-3 hover:bg-blue-700 hover:scale-[1.02] transition-all shadow-2xl shadow-blue-100"
              >
                <Save size={24}/> ترحيل بيانات الجرد للمخزون
              </button>
            </div>
          </div>
        )}

        {!selectedMarket && (
          <div className="py-20 text-center">
            <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-200">
              <Package size={48} />
            </div>
            <p className="text-gray-400 font-bold">يرجى اختيار ماركت لإظهار نموذج الجرد الفعلي</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default InventoryRegistration;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Users, ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, MessageCircle, Calendar,
  Loader2, Wifi, WifiOff, Palette, Copy, Trash2, User as UserIcon
} from 'lucide-react';
import { db, ref, onValue, set, update, push, remove } from './firebase';
import { User, AppSettings, Notification, AppTheme, Market, Company } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<AppTheme>('standard');
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    window.addEventListener('online', () => setIsOnline(true));
    window.addEventListener('offline', () => setIsOnline(false));

    // Sync settings
    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    // Sync users
    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) setUsers(Object.values(data));
    });

    setIsLoading(false);
  }, []);

  // Sync markets & companies with privacy filter
  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(m => user.role === 'admin' || m.creatorId === user.id || !m.creatorId);
          setMarkets(filtered);
        }
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(c => user.role === 'admin' || c.creatorId === user.id || !c.creatorId);
          setCompanies(filtered);
        }
      });
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      const notifRef = ref(db, 'notifications');
      onValue(notifRef, (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const allNotifs = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
          const myNotifs = allNotifs.filter(n => n.receiverId === 'all' || n.receiverId === user.id);
          setNotifications(myNotifs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
        } else {
          setNotifications([]);
        }
      });
    }
  }, [user]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user && user.id !== 'admin-id') {
      update(ref(db, `users/${user.id}`), { isOnline: false });
    }
    setUser(null);
  };

  const deleteNotification = (id: string) => {
    remove(ref(db, `notifications/${id}`));
  };

  const cycleTheme = () => {
    if (theme === 'standard') setTheme('glass');
    else if (theme === 'glass') setTheme('dark');
    else setTheme('standard');
  };

  const openWhatsApp = () => {
    if (settings?.whatsappNumber) {
      window.open(`https://wa.me/${settings.whatsappNumber}`, '_blank');
    } else {
      alert("رقم الواتساب غير مسجل في الإعدادات");
    }
  };

  if (isLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-rose-50">
      <Loader2 className="animate-spin text-rose-600 mb-4" size={48}/>
      <p className="text-rose-900 font-bold animate-pulse">جاري تحميل نظام Soft Rose...</p>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} />;

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: true },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: user.role === 'admin' || user.permissions?.viewSalesHistory },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: user.role === 'admin' || user.permissions?.registerInventory },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: user.role === 'admin' || user.permissions?.viewInventoryHistory },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: user.role === 'admin' || user.permissions?.viewCompetitorPrices },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: user.role === 'admin' || user.permissions?.viewCompetitorReports },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: true },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user.role === 'admin' },
  ].filter(i => i.visible);

  const getRoleLabel = (role: string) => {
    switch (role) {
      case 'admin': return 'مدير';
      case 'coordinator': return 'منسق';
      case 'usher': return 'أشر';
      default: return 'موظف';
    }
  };

  return (
    <div className={`flex h-screen overflow-hidden theme-${theme} transition-all duration-300 relative`}>
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`bg-rose-900 text-white w-72 flex-shrink-0 transition-all duration-300 z-50 fixed md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:right-0'} ${theme === 'glass' ? 'bg-rose-900/70 backdrop-blur-xl border-l border-white/10' : ''} shadow-2xl`}>
        <div className="p-6 flex flex-col h-full">
          <div className="mb-8 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-widest text-rose-300">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 hover:bg-white/10 rounded-full"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-1.5 overflow-y-auto custom-scrollbar pr-2">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all duration-200 ${activeTab === item.id ? 'bg-white text-rose-900 font-bold shadow-xl shadow-black/10' : 'hover:bg-white/10 opacity-80 hover:opacity-100'}`}
              >
                <span className={activeTab === item.id ? 'text-rose-600' : 'text-white'}>{item.icon}</span>
                <span className="text-sm">{item.label}</span>
              </button>
            ))}

            {user.role === 'admin' && (
              <div className="mt-10 pt-6 border-t border-white/10">
                <p className="text-[10px] uppercase text-rose-400 px-5 mb-4 font-black tracking-widest">الموظفون المتصلون</p>
                <div className="space-y-3">
                  {users.map(u => (
                    <div key={u.id} className="flex items-center gap-3 px-5">
                      <div className="relative">
                        <div className={`w-2.5 h-2.5 rounded-full ${u.isOnline ? 'bg-blue-400 shadow-[0_0_8px_rgba(96,165,250,0.8)]' : 'bg-rose-800'}`}></div>
                      </div>
                      <span className={`text-xs font-bold ${u.isOnline ? 'text-white' : 'text-rose-400/60'}`}>{u.employeeName} ({getRoleLabel(u.role)})</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </nav>
          <div className="mt-4 text-[10px] text-center text-rose-400/40 uppercase font-bold tracking-widest">
            System v3.0.0 Stable
          </div>
        </div>
      </aside>

      <main className={`flex-1 flex flex-col min-w-0 overflow-hidden ${theme === 'dark' ? 'bg-[#0a0a0a]' : 'bg-[#F9FAFB]'}`}>
        {/* Ticker at the VERY top */}
        {settings?.tickerText && (
          <div className="bg-rose-950 py-2 text-white text-[13px] overflow-hidden border-b border-rose-900/50 shadow-inner z-50">
            <div className="ticker-container">
              <div className="ticker-text font-bold opacity-90" style={{ animationDuration: '45s' }}>
                {settings.tickerText} &nbsp;&nbsp; ★ &nbsp;&nbsp; {settings.tickerText} &nbsp;&nbsp; ★ &nbsp;&nbsp; {settings.tickerText}
              </div>
            </div>
          </div>
        )}

        <header className={`h-20 flex items-center justify-between px-4 md:px-8 border-b transition-all duration-300 z-30 ${theme === 'glass' ? 'bg-white/40 backdrop-blur-md border-white/20 shadow-sm' : 'bg-white shadow-sm'} ${theme === 'dark' ? 'bg-[#121212] border-[#222]' : ''}`}>
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-3 hover:bg-rose-50 rounded-2xl transition-all">
