import React, { useState, useEffect } from 'react';
import { User, SaleItem, DailySale } from '../types';
import { PRODUCT_GROUPS } from '../constants';
import { Plus, Trash2, Save, ShoppingBag, PlusCircle } from 'lucide-react';
import { db, ref, push } from '../firebase';

interface Props {
  user: User;
  markets: string[];
}

const DailySales: React.FC<Props> = ({ user, markets }) => {
  const [selectedMarket, setSelectedMarket] = useState('');
  const [items, setItems] = useState<SaleItem[]>([]);
  const [isAddMarketModalOpen, setIsAddMarketModalOpen] = useState(false);
  const [newMarketName, setNewMarketName] = useState('');

  useEffect(() => {
    if (selectedMarket) {
      const allItems: SaleItem[] = [];
      Object.entries(PRODUCT_GROUPS).forEach(([cat, products]) => {
        products.forEach(p => {
          allItems.push({
            id: `${cat}-${p}-${Date.now()}-${Math.random()}`,
            category: cat,
            productName: p,
            price: 0,
            quantity: 0
          });
        });
      });
      setItems(allItems);
    } else {
      setItems([]);
    }
  }, [selectedMarket]);

  const updateItem = (id: string, field: keyof SaleItem, value: any) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const addItemManual = (category: string) => {
    const newItem: SaleItem = {
      id: `manual-${category}-${Date.now()}-${Math.random()}`,
      category,
      productName: '',
      price: 0,
      quantity: 0
    };
    setItems([...items, newItem]);
  };

  const calculateTotal = () => {
    return items.reduce((sum, item) => sum + (Number(item.price) * Number(item.quantity)), 0);
  };

  const handleSave = async () => {
    if (!selectedMarket) {
      alert("يرجى اختيار الماركت أولاً");
      return;
    }

    const finalItems = items.filter(i => i.quantity > 0 && i.productName.trim() !== '');
    if (finalItems.length === 0) {
      alert("يرجى إدخال كمية لمنتج واحد على الأقل واسم المنتج");
      return;
    }

    const sale: Partial<DailySale> = {
      userId: user.id,
      userName: user.employeeName,
      marketName: selectedMarket,
      date: new Date().toISOString(),
      items: finalItems,
      total: calculateTotal()
    };

    try {
      await push(ref(db, 'sales'), sale);
      alert("تم ترحيل وحفظ المبيعات النهائية بنجاح");
      setSelectedMarket('');
      setItems([]);
    } catch (e) {
      alert("حدث خطأ أثناء الاتصال بالقاعدة");
    }
  };

  const handleAddMarket = async () => {
    if (!newMarketName.trim()) return;
    await push(ref(db, 'markets'), {
      name: newMarketName.trim(),
      creatorId: user.id
    });
    setNewMarketName('');
    setIsAddMarketModalOpen(false);
    alert("تمت إضافة الماركت بنجاح");
  };

  const getCategoryLabel = (cat: string) => {
    switch(cat) {
      case 'facial': return 'مناديل سحب (Facial)';
      case 'kitchen': return 'مناديل مطبخ (Kitchen)';
      case 'hotel_toilet': return 'تواليت فنادق (Hotel Toilet)';
      case 'dolphin': return 'دولفن (Dolphin)';
      default: return cat;
    }
  };

  return (
    <div className="max-w-7xl mx-auto pb-20 px-2 md:px-4">
      <div className="bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-xl border border-rose-50 p-4 md:p-10">

        {/* Header Total Section */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-8 bg-rose-900 p-6 md:p-10 rounded-[2rem] text-white shadow-2xl">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-white/10 rounded-2xl md:rounded-3xl backdrop-blur-md">
              <ShoppingBag size={32} />
            </div>
            <div className="text-center md:text-right">
              <h2 className="text-lg md:text-xl font-black leading-none">إجمالي المبيعات اليومية</h2>
              <p className="text-[10px] font-bold text-rose-300 uppercase tracking-widest mt-1">Daily Sales Summary</p>
            </div>
          </div>
          <div className="text-4xl md:text-6xl font-black tracking-tighter">
            {calculateTotal().toLocaleString()} <span className="text-lg md:text-xl font-bold opacity-60">ج.م</span>
          </div>
        </div>

        {/* Market Selector */}
        <div className="mb-8 flex flex-col md:flex-row items-stretch md:items-end gap-3 bg-slate-50 p-4 md:p-6 rounded-[1.5rem] md:rounded-3xl border border-slate-100">
          <div className="flex-1">
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-2">اختيار الماركت</label>
            <select 
              className="w-full bg-white border-2 border-transparent focus:border-rose-300 rounded-xl md:rounded-2xl p-4 outline-none font-bold text-gray-700 shadow-sm transition-all"
              value={selectedMarket}
              onChange={(e) => setSelectedMarket(e.target.value)}
            >
              <option value="">-- اضغط لاختيار الماركت --</option>
              {markets.map(m => <option key={m} value={m}>{m}</option>)}
