        {selectedMarket && (
          <div className="space-y-8 md:space-y-12">
            {['facial', 'kitchen', 'hotel_toilet', 'dolphin'].map(cat => (
              <div key={cat} className="space-y-4">
                <div className="bg-slate-800 px-6 py-4 font-black text-white rounded-xl md:rounded-2xl flex items-center justify-between shadow-md">
                  <span className="text-xs md:text-sm">{getCategoryLabel(cat)}</span>
                  <span className="text-[10px] opacity-40 uppercase tracking-widest">Section</span>
                </div>

                <div className="space-y-2">
                  {/* Table Header for Desktop */}
                  <div className="hidden md:grid grid-cols-[2fr,120px,120px,140px] gap-4 px-6 mb-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                    <span>اسم الصنف</span>
                    <span className="text-center">السعر</span>
                    <span className="text-center">العدد</span>
                    <span className="text-center">إجمالي الصنف</span>
                  </div>

                  {items.filter(i => i.category === cat).map(item => (
                    <div key={item.id} className="p-4 bg-white border border-slate-100 rounded-xl md:rounded-3xl hover:border-rose-200 hover:shadow-lg transition-all group">
                      <div className="grid grid-cols-1 md:grid-cols-[2fr,120px,120px,140px] gap-3 md:gap-4 items-center">
                        {/* Product Name */}
                        <div>
                          {item.id.includes('manual') ? (
                            <input 
                              placeholder="أدخل اسم الصنف الجديد..."
                              className="w-full bg-slate-50 border-2 border-transparent focus:border-rose-300 rounded-xl p-3 font-bold text-gray-800 outline-none"
                              value={item.productName}
                              onChange={(e) => updateItem(item.id, 'productName', e.target.value)}
                            />
                          ) : (
                            <p className="font-black text-gray-700 md:px-2 text-sm">{item.productName}</p>
                          )}
                        </div>

                        {/* Price Input */}
                        <div className="flex items-center md:justify-center gap-2">
                          <label className="md:hidden text-[10px] font-black text-gray-400 uppercase w-16">السعر:</label>
                          <input 
                            type="number" placeholder="0.00" 
                            className="flex-1 md:w-24 bg-slate-50 border-2 border-transparent focus:border-rose-300 rounded-xl p-3 text-center font-bold text-rose-900 outline-none"
                            value={item.price || ''} onChange={(e) => updateItem(item.id, 'price', e.target.value)}
                          />
                        </div>

                        {/* Quantity Input */}
                        <div className="flex items-center md:justify-center gap-2">
                          <label className="md:hidden text-[10px] font-black text-gray-400 uppercase w-16">العدد:</label>
                          <input 
                            type="number" placeholder="0" 
                            className={`flex-1 md:w-24 bg-slate-50 border-2 border-transparent focus:border-blue-300 rounded-xl p-3 text-center font-black outline-none transition-all ${item.quantity > 0 ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}
                            value={item.quantity || ''} onChange={(e) => updateItem(item.id, 'quantity', e.target.value)}
                          />
                        </div>

                        {/* Item Total */}
                        <div className="flex items-center md:justify-center gap-2">
                          <label className="md:hidden text-[10px] font-black text-gray-400 uppercase w-16">الإجمالي:</label>
                          <div className="flex-1 md:w-28 bg-slate-100 rounded-xl p-3 text-center font-black text-gray-800 text-sm">
                            {(Number(item.price) * Number(item.quantity)).toLocaleString()} <span className="text-[10px] opacity-40">ج.م</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}

                  <button 
                    onClick={() => addItemManual(cat)}
                    className="w-full py-4 border-2 border-dashed border-slate-200 rounded-xl md:rounded-[2rem] text-slate-400 font-black text-[11px] flex items-center justify-center gap-2 hover:bg-slate-50 hover:border-rose-300 hover:text-rose-600 transition-all active:scale-95 mt-4"
                  >
                    <PlusCircle size={18}/> إضافة منتج جديد لقسم {getCategoryLabel(cat)}
                  </button>
                </div>
              </div>
            ))}

            <button 
              onClick={handleSave}
              className="w-full bg-rose-800 text-white py-6 rounded-xl md:rounded-[2rem] font-black text-lg md:text-xl flex items-center justify-center gap-3 hover:bg-rose-900 hover:scale-[1.01] transition-all shadow-2xl shadow-rose-200 mt-12 active:scale-95"
            >
              <Save size={28}/> ترحيل وحفظ المبيعات النهائية
            </button>
          </div>
        )}

        {!selectedMarket && (
          <div className="py-24 text-center">
            <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mx-auto mb-6 text-rose-200">
              <ShoppingBag size={48} />
            </div>
            <p className="text-gray-400 font-black px-4">يرجى اختيار ماركت من القائمة بالأعلى لبدء تسجيل المبيعات</p>
          </div>
        )}
      </div>

      {isAddMarketModalOpen && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] p-8 md:p-10 max-w-md w-full shadow-2xl animate-in zoom-in-95">
            <h3 className="text-xl font-black text-rose-900 mb-6">إضافة ماركت جديد</h3>
            <input 
              className="w-full bg-slate-50 p-5 rounded-xl outline-none font-bold border-2 border-transparent focus:border-rose-300"
              placeholder="أدخل اسم الماركت الجديد..."
              value={newMarketName}
              onChange={(e) => setNewMarketName(e.target.value)}
            />
            <div className="flex gap-4 mt-8">
              <button onClick={handleAddMarket} className="flex-1 bg-rose-800 text-white py-4 rounded-xl font-black shadow-lg">إضافة الماركت</button>
              <button onClick={() => setIsAddMarketModalOpen(false)} className="flex-1 bg-slate-100 text-slate-500 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

