          </div>
        </div>

        {/* Market Selection Section */}
        <div className="mb-8 flex flex-col md:flex-row items-stretch md:items-end gap-3 bg-slate-50 p-4 md:p-6 rounded-[1.5rem] md:rounded-3xl border border-slate-100">
