import React, { useState, useEffect, useMemo } from 'react';
import { User, Vacation } from '../types';
import { db, ref, onValue, push, set, remove, update } from '../firebase';
import { Calendar, Plus, Trash2, Clock, ChevronRight, ChevronLeft, X, Edit, User as UserIcon } from 'lucide-react';

interface Props {
  user: User;
  users: User[];
}

const VacationManagement: React.FC<Props> = ({ user, users }) => {
  const [vacations, setVacations] = useState<Vacation[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDetails, setSelectedDetails] = useState<{ userId: string, type: string, userName: string } | null>(null);
  const [editingUserBalance, setEditingUserBalance] = useState<User | null>(null);
  const [currentPeriodDate, setCurrentPeriodDate] = useState(new Date());

  const [newVacation, setNewVacation] = useState({
    date: new Date().toISOString().split('T')[0],
    days: 1,
    type: 'annual' as const,
    targetUserId: user.id
  });

  useEffect(() => {
    const vRef = ref(db, 'vacations');
    onValue(vRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setVacations(Object.entries(data).map(([id, val]: any) => ({ ...val, id })));
      } else {
        setVacations([]);
      }
    });
  }, []);

  const handleAddVacation = async () => {
    const vRef = ref(db, 'vacations');
    const targetUser = users.find(u => u.id === newVacation.targetUserId) || user;

    // Deduction logic for Annual/Casual/AbsentWithPermission
    const currentBalance = targetUser.vacationBalance || { annual: 14, casual: 7, sick: 0, exams: 0 };
    let updatedBalance = { ...currentBalance };

    if (newVacation.type === 'annual') updatedBalance.annual -= newVacation.days;
    else if (newVacation.type === 'casual') updatedBalance.casual -= newVacation.days;
    else if (newVacation.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) - newVacation.days;

    // Save deduction to user object
    await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });

    // Push vacation record
    await push(vRef, {
      ...newVacation,
      userId: targetUser.id,
      userName: targetUser.employeeName,
      createdAt: new Date().toISOString()
    });

    setIsModalOpen(false);
    alert("تم تسجيل الإجازة وخصمها من الرصيد بنجاح");
  };

  const handleDeleteVacation = async (id: string) => {
    if (window.confirm("⚠️ هل أنت متأكد من حذف هذا السجل؟ سيتم إعادة الأيام للرصيد.")) {
      const vToDelete = vacations.find(v => v.id === id);
      if (vToDelete) {
        const targetUser = users.find(u => u.id === vToDelete.userId);
        if (targetUser) {
          const currentBalance = targetUser.vacationBalance || { annual: 14, casual: 7 };
          let updatedBalance = { ...currentBalance };

          if (vToDelete.type === 'annual') updatedBalance.annual += Number(vToDelete.days);
          else if (vToDelete.type === 'casual') updatedBalance.casual += Number(vToDelete.days);
          else if (vToDelete.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) + Number(vToDelete.days);

          await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });
        }
      }
      await remove(ref(db, `vacations/${id}`));
      alert("تم الحذف وإرجاع الرصيد بنجاح");
    }
  };

  const handleSaveBalanceEdit = async () => {
    if (!editingUserBalance) return;
    await update(ref(db, `users/${editingUserBalance.id}`), {
      vacationBalance: editingUserBalance.vacationBalance
    });
    alert("تم تحديث الرصيد بنجاح");
    setEditingUserBalance(null);
  };

  // Helper to get financial month period (21 to 20)
  const getPeriodRange = (baseDate: Date) => {
    let year = baseDate.getFullYear();
    let month = baseDate.getMonth(); // 0-11

    const start = new Date(year, month - 1, 21);
    const end = new Date(year, month, 20);
    return { start, end };
  };

  const currentRange = useMemo(() => getPeriodRange(currentPeriodDate), [currentPeriodDate]);

  const changePeriod = (direction: 'prev' | 'next') => {
    const newDate = new Date(currentPeriodDate);
    if (direction === 'prev') newDate.setMonth(newDate.getMonth() - 1);
    else newDate.setMonth(newDate.getMonth() + 1);
    setCurrentPeriodDate(newDate);
  };

  const visibleUsers = user.role === 'admin' ? users : users.filter(u => u.id === user.id);

  return (
    <div className="space-y-6 pb-20" dir="rtl">
      <div className="bg-white p-6 md:p-8 rounded-[2rem] shadow-sm border border-rose-50">
        <div className="flex justify-between items-center mb-10">
          <div className="flex items-center gap-3">
            <div className="p-3 bg-rose-900 text-white rounded-2xl"><Calendar size={24}/></div>
            <h2 className="text-2xl font-black text-rose-900 leading-none">إدارة رصيد الإجازات</h2>
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-rose-800 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-rose-900 shadow-lg shadow-rose-100 font-black text-sm transition-all"
          >
            <Plus size={20}/> تسجيل جديد
          </button>
        </div>

        {/* User Vacation Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {visibleUsers.map(u => (
            <div key={u.id} className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 group hover:border-rose-200 transition-all relative">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-rose-900 shadow-sm"><UserIcon size={24}/></div>
                  <div>
                    <p className="font-black text-rose-900">{u.employeeName}</p>
                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{u.employeeCode || 'بدون كود'}</p>
                  </div>
                </div>
                {user.role === 'admin' && (
                  <div className="flex gap-1">
                    <button onClick={() => setEditingUserBalance(u)} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-600 hover:text-white transition-all"><Edit size={14}/></button>
                    <button onClick={() => { if(window.confirm("حذف الموظف نهائياً؟")) remove(ref(db, `users/${u.id}`)); }} className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-600 hover:text-white transition-all"><Trash2 size={14}/></button>
                  </div>
                )}
              </div>

              {/* 4 Mini Squares showing CURRENT BALANCE */}
              <div className="grid grid-cols-4 gap-2">
                {[
                  { label: 'سنوي', type: 'annual', balance: u.vacationBalance?.annual ?? 14, text: 'text-blue-600', light: 'bg-blue-50' },
                  { label: 'عارضة', type: 'casual', balance: u.vacationBalance?.casual ?? 7, text: 'text-orange-500', light: 'bg-orange-50' },
                  { label: 'مرضي', type: 'sick', balance: u.vacationBalance?.sick ?? 0, text: 'text-red-500', light: 'bg-red-50' },
                  { label: 'بدون إذن', type: 'absent_without_permission', balance: u.vacationBalance?.absent_without_permission ?? 0, text: 'text-purple-600', light: 'bg-purple-50' }
                ].map(box => (
                  <button 
                    key={box.type}
                    onClick={() => setSelectedDetails({ userId: u.id, type: box.type, userName: u.employeeName })}
                    className={`${box.light} p-3 rounded-2xl flex flex-col items-center justify-center hover:scale-105 transition-all shadow-sm border border-transparent hover:border-rose-200`}
                  >
                    <span className={`text-[8px] font-black uppercase ${box.text} mb-1`}>{box.label}</span>
                    <span className={`text-xl font-black ${box.text}`}>{box.balance}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Edit Balance Modal (Admin Only) */}
      {editingUserBalance && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-8 shadow-2xl animate-in zoom-in-95">
            <h3 className="text-xl font-black text-rose-900 mb-6">تعديل رصيد أيام {editingUserBalance.employeeName}</h3>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">سنوي</label>
                <input 
                  type="number" className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200"
                  value={editingUserBalance.vacationBalance?.annual}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...editingUserBalance.vacationBalance, annual: Number(e.target.value)}})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">عارضة</label>
                <input 
                  type="number" className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200"
                  value={editingUserBalance.vacationBalance?.casual}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...editingUserBalance.vacationBalance, casual: Number(e.target.value)}})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">مرضي</label>
                <input 
                  type="number" className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200"
                  value={editingUserBalance.vacationBalance?.sick}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...editingUserBalance.vacationBalance, sick: Number(e.target.value)}})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">بدون إذن</label>
                <input 
                  type="number" className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200"
                  value={editingUserBalance.vacationBalance?.absent_without_permission}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...editingUserBalance.vacationBalance, absent_without_permission: Number(e.target.value)}})}
                />
              </div>
            </div>
            <div className="flex gap-4 mt-8">
              <button onClick={handleSaveBalanceEdit} className="flex-1 bg-rose-800 text-white py-4 rounded-xl font-black shadow-lg">حفظ التعديلات</button>
              <button onClick={() => setEditingUserBalance(null)} className="flex-1 bg-slate-100 text-slate-500 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}

      {/* Details Modal (Calendar/Period View) */}
      {selectedDetails && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg overflow-hidden shadow-2xl animate-in zoom-in-95">
            <div className="bg-rose-900 p-6 text-white flex justify-between items-center">
              <div>
                <h3 className="text-lg font-black">{selectedDetails.userName}</h3>
                <p className="text-[10px] font-bold text-rose-300 uppercase mt-1">
                  سجل: {
                    selectedDetails.type === 'annual' ? 'إجازات سنوية' :
                    selectedDetails.type === 'casual' ? 'إجازات عارضة' :
                    selectedDetails.type === 'sick' ? 'إجازات مرضية' : 'غياب بدون إذن'
                  }
                </p>
              </div>
              <button onClick={() => setSelectedDetails(null)} className="p-2 hover:bg-white/10 rounded-full transition-all"><X size={24}/></button>
            </div>

            {/* Period Navigation */}
            <div className="p-4 bg-slate-50 flex items-center justify-between border-b">
              <button onClick={() => changePeriod('prev')} className="p-2 bg-white rounded-xl shadow-sm hover:bg-rose-50 transition-all text-rose-900"><ChevronRight size={20}/></button>
              <div className="text-center">
                <p className="text-xs font-black text-rose-900">
                  {currentRange.start.toLocaleDateString('ar-EG', { month: 'long', year: 'numeric' })}
                </p>
                <p className="text-[9px] font-bold text-gray-400">الفترة المالية (21 - 20)</p>
              </div>
              <button onClick={() => changePeriod('next')} className="p-2 bg-white rounded-xl shadow-sm hover:bg-rose-50 transition-all text-rose-900"><ChevronLeft size={20}/></button>
            </div>

            {/* Dates List */}
            <div className="p-6 max-h-[50vh] overflow-y-auto space-y-3">
              {vacations
                .filter(v => v.userId === selectedDetails.userId && v.type === selectedDetails.type)
                .filter(v => {
                  const d = new Date(v.date);
                  return d >= currentRange.start && d <= currentRange.end;
                })
                .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
                .map(v => (
                  <div key={v.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-rose-800 shadow-sm font-black text-xs">
                        {new Date(v.date).getDate()}
                      </div>
                      <div>
                        <p className="font-bold text-sm text-slate-800">{new Date(v.date).toLocaleDateString('ar-EG', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{v.days} يوم</p>
                      </div>
                    </div>
                    {user.role === 'admin' && (
                      <div className="flex gap-2">
                        <button onClick={() => handleDeleteVacation(v.id)} className="p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all opacity-0 group-hover:opacity-100"><Trash2 size={16}/></button>
                      </div>
                    )}
                  </div>
                ))}

              {vacations
                .filter(v => v.userId === selectedDetails.userId && v.type === selectedDetails.type)
                .filter(v => {
                  const d = new Date(v.date);
                  return d >= currentRange.start && d <= currentRange.end;
                }).length === 0 && (
                  <div className="py-20 text-center text-gray-300 font-bold italic text-sm">لا توجد سجلات لهذه الفترة</div>
                )}
            </div>
          </div>
        </div>
      )}

      {/* Register New Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-8 shadow-2xl animate-in zoom-in-95">
            <h3 className="text-2xl font-black text-rose-900 mb-8">تسجيل إجازة / غياب</h3>
            <div className="space-y-4">
              {user.role === 'admin' && (
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">الموظف</label>
                  <select 
                    className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200"
                    value={newVacation.targetUserId}
                    onChange={(e) => setNewVacation({...newVacation, targetUserId: e.target.value})}
                  >
                    {users.map(u => <option key={u.id} value={u.id}>{u.employeeName}</option>)}
                  </select>
                </div>
              )}
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">التاريخ</label>
                <input 
                  type="date" className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200"
                  value={newVacation.date}
                  onChange={(e) => setNewVacation({...newVacation, date: e.target.value})}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">نوع الإجازة</label>
                  <select 
                    className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200 text-sm"
                    value={newVacation.type}
                    onChange={(e) => setNewVacation({...newVacation, type: e.target.value as any})}
                  >
                    <option value="annual">سنوي</option>
                    <option value="casual">عارضة</option>
                    <option value="sick">مرضي</option>
                    <option value="absent_with_permission">غياب بإذن</option>
                    <option value="absent_without_permission">غياب بدون إذن</option>
                    <option value="exams">امتحانات</option>
                  </select>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 mr-1">الأيام</label>
                  <input 
                    type="number" className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200"
                    value={newVacation.days}
                    onChange={(e) => setNewVacation({...newVacation, days: Number(e.target.value)})}
                  />
                </div>
              </div>
            </div>
            <div className="flex gap-4 mt-8">
              <button onClick={handleAddVacation} className="flex-1 bg-rose-800 text-white py-4 rounded-xl font-black shadow-lg">تأكيد التسجيل</button>
              <button onClick={() => setIsModalOpen(false)} className="flex-1 bg-slate-100 text-slate-500 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default VacationManagement;

export type UserRole = 'admin' | 'coordinator' | 'usher';
export type AppTheme = 'standard' | 'glass' | 'dark' | 'modern';

export interface UserPermissions {
  registerSales: boolean;
  viewSalesHistory: boolean;
  registerInventory: boolean;
  viewInventoryHistory: boolean;
  registerCompetitorPrices: boolean;
  viewCompetitorReports: boolean;
  viewVacationMgmt: boolean;
  viewSettings: boolean;
  viewColleaguesSales: boolean;
}

export interface User {
  id: string;
  username: string;
  password?: string;
  role: UserRole;
  employeeName: string;
  employeeCode: string;
  phone: string;
  isOnline: boolean;
  permissions: UserPermissions;
  canSeeAllSales?: boolean;
  vacationBalance: {
    annual: number;
    casual: number;
    sick: number;
    exams: number;
    absent_with_permission?: number;
    absent_without_permission?: number;
  };
}

export interface Notification {
  id: string;
  senderId: string;
  receiverId: string;
  message: string;
  timestamp: string;
  isRead: boolean;
}

export interface AppSettings {
  tickerText: string;
  tickerSpeed: number;
  whatsappNumber: string;
  programName: string;
}

export interface Market {
  id: string;
  name: string;
  creatorId: string;
}

export interface Company {
  id: string;
  name: string;
  creatorId: string;
}

export interface SaleItem {
  id: string;
  category: string;
  productName: string;
  price: number;
  quantity: number;
}

export interface DailySale {
  id: string;
  userId: string;
  userName: string;
  marketName: string;
  date: string;
  items: SaleItem[];
  total: number;
}

export interface Vacation {
  id: string;
  userId: string;
  userName: string;
  date: string;
  days: number;
  type: 'annual' | 'casual' | 'sick' | 'exams' | 'absent_with_permission' | 'absent_without_permission';
  createdAt: string;
}

export interface InventoryRecord {
  id: string;
  userId: string;
  userName: string;
  marketName: string;
  date: string;
  items: Array<{
    productName: string;
    quantity: number;
  }>;
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Users, ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, MessageCircle, Calendar,
  Loader2, Wifi, WifiOff, Palette, Copy, Trash2, User as UserIcon
} from 'lucide-react';
import { db, ref, onValue, set, update, push, remove } from './firebase';
import { User, AppSettings, Notification, AppTheme, Market, Company } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<AppTheme>('standard');
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    window.addEventListener('online', () => setIsOnline(true));
    window.addEventListener('offline', () => setIsOnline(false));

    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) setUsers(Object.values(data));
    });

    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(m => user.role === 'admin' || m.creatorId === user.id || !m.creatorId);
          setMarkets(filtered);
        }
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(c => user.role === 'admin' || c.creatorId === user.id || !c.creatorId);
          setCompanies(filtered);
        }
      });
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      const notifRef = ref(db, 'notifications');
      onValue(notifRef, (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const allNotifs = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
          const myNotifs = allNotifs.filter(n => n.receiverId === 'all' || n.receiverId === user.id);
          setNotifications(myNotifs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
        } else {
          setNotifications([]);
        }
      });
    }
  }, [user]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user && user.id !== 'admin-id') {
      update(ref(db, `users/${user.id}`), { isOnline: false });
    }
    setUser(null);
  };

  const deleteNotification = (id: string) => {
    remove(ref(db, `notifications/${id}`));
  };

  const cycleTheme = () => {
    if (theme === 'standard') setTheme('glass');
    else if (theme === 'glass') setTheme('dark');
    else setTheme('standard');
  };

  const openWhatsApp = () => {
    if (settings?.whatsappNumber) {
      window.open(`https://wa.me/${settings.whatsappNumber}`, '_blank');
    } else {
      alert("رقم الواتساب غير مسجل في الإعدادات");
    }
  };

  if (isLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-rose-50">
      <Loader2 className="animate-spin text-rose-600 mb-4" size={48}/>
      <p className="text-rose-900 font-bold animate-pulse">جاري تحميل نظام Soft Rose...</p>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} />;

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: user.role === 'admin' || user.permissions?.registerSales },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: user.role === 'admin' || user.permissions?.viewSalesHistory },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: user.role === 'admin' || user.permissions?.registerInventory },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: user.role === 'admin' || user.permissions?.viewInventoryHistory },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: user.role === 'admin' || user.permissions?.registerCompetitorPrices },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: user.role === 'admin' || user.permissions?.viewCompetitorReports },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: user.role === 'admin' || user.permissions?.viewVacationMgmt },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user.role === 'admin' || user.permissions?.viewSettings },
  ].filter(i => i.visible);

  const getRoleLabel = (role: string) => {
    switch (role) {
      case 'admin': return 'مدير';
      case 'coordinator': return 'منسق';
      case 'usher': return 'أشر';
      default: return 'موظف';
    }
  };

  return (
    <div className={`flex h-screen overflow-hidden theme-${theme} transition-all duration-300 relative`}>
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-40 md:hidden backdrop-blur-sm" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar Section */}
      <aside className={`bg-rose-900 text-white w-72 flex-shrink-0 transition-all duration-300 z-50 fixed md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:right-0'} ${theme === 'glass' ? 'bg-rose-900/70 backdrop-blur-xl border-l border-white/10' : ''} shadow-2xl`}>
        <div className="p-6 flex flex-col h-full">
          <div className="mb-8 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-widest text-rose-300">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 hover:bg-white/10 rounded-full"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-1.5 overflow-y-auto custom-scrollbar pr-2">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl transition-all duration-200 ${activeTab === item.id ? 'bg-white text-rose-900 font-bold shadow-xl shadow-black/10' : 'hover:bg-white/10 opacity-80 hover:opacity-100'}`}
              >
                <span className={activeTab === item.id ? 'text-rose-600' : 'text-white'}>{item.icon}</span>
                <span className="text-sm font-bold">{item.label}</span>
              </button>
            ))}

            {user.role === 'admin' && (
              <div className="mt-8 pt-6 border-t border-white/10">
                <p className="text-[10px] uppercase text-rose-400 px-5 mb-4 font-black tracking-widest">الموظفون المتصلون</p>
                <div className="space-y-2">
                  {users.map(u => (
                    <div key={u.id} className="flex items-center gap-3 px-5 py-1">
                      <div className="relative">
                        <div className={`w-2 h-2 rounded-full ${u.isOnline ? 'bg-blue-400 shadow-[0_0_8px_rgba(96,165,250,0.8)]' : 'bg-rose-800'}`}></div>
                      </div>
                      <span className={`text-[11px] font-bold ${u.isOnline ? 'text-white' : 'text-rose-400/60'}`}>{u.employeeName}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </nav>
        </div>
      </aside>

      <main className={`flex-1 flex flex-col min-w-0 overflow-hidden ${theme === 'dark' ? 'bg-[#0a0a0a]' : 'bg-[#F9FAFB]'}`}>

        {/* Ticker Section */}
        {settings?.tickerText && (
          <div className="bg-rose-950 py-2 text-white text-[11px] md:text-[13px] overflow-hidden border-b border-rose-900/50 shadow-inner z-50">
            <div className="ticker-container">
              <div className="ticker-text font-bold opacity-90" style={{ animationDuration: '45s' }}>
                {settings.tickerText} &nbsp;&nbsp; ★ &nbsp;&nbsp; {settings.tickerText}
              </div>
            </div>
          </div>
        )}

        {/* Improved Header Section */}
        <header className={`h-16 md:h-20 flex items-center justify-between px-3 md:px-8 border-b transition-all duration-300 z-30 ${theme === 'glass' ? 'bg-white/40 backdrop-blur-md border-white/20 shadow-sm' : 'bg-white shadow-sm'} ${theme === 'dark' ? 'bg-[#121212] border-[#222]' : ''}`}>
          <div className="flex items-center gap-2 md:gap-4 flex-1 min-w-0">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 hover:bg-rose-50 rounded-xl transition-all">
              <Menu size={20} className="text-rose-800" />
            </button>
            <div className="flex flex-col truncate">
              <h2 className="font-black text-rose-900 text-sm md:text-xl tracking-tighter uppercase leading-tight truncate">
                {settings?.programName || 'Soft Rose Modern Trade'}
              </h2>
              <div className="flex items-center gap-1 mt-0.5">
                <span className="text-[9px] md:text-[10px] font-bold text-gray-400 uppercase tracking-widest truncate">
                  {user.employeeName} • {getRoleLabel(user.role)}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 md:gap-2">
            {/* Control Center Pill */}
            <div className="flex items-center bg-slate-100/70 p-1 rounded-xl md:rounded-2xl gap-0.5 md:gap-1 shadow-inner">
              <button onClick={openWhatsApp} className="p-2 md:p-3 hover:bg-green-50 text-green-600 rounded-lg md:rounded-xl transition-all" title="واتساب">
                <MessageCircle size={18} />
              </button>

              <button onClick={cycleTheme} className="p-2 md:p-3 hover:bg-white hover:shadow-md rounded-lg md:rounded-xl text-amber-500 transition-all" title="الاستايل">
                <Palette size={18} />
              </button>

              <div className={`p-2 md:p-3 rounded-lg md:rounded-xl ${isOnline ? 'text-blue-600' : 'text-red-500'}`} title={isOnline ? 'متصل' : 'غير متصل'}>
                {isOnline ? <Wifi size={18} /> : <WifiOff size={18} />}
              </div>

              <button onClick={() => setIsNotificationOpen(true)} className="relative p-2 md:p-3 hover:bg-rose-50 rounded-lg md:rounded-xl text-gray-500 transition-all" title="الإشعارات">
                <Bell size={18} />
                {unreadCount > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-red-600 border-2 border-white rounded-full"></span>
                )}
              </button>
            </div>

            <button onClick={handleLogout} className="p-2 md:p-3 bg-rose-50 text-rose-800 rounded-xl md:rounded-2xl hover:bg-rose-100 transition-all font-bold text-[11px] md:text-sm border border-rose-100 ml-1">
              <LogOut size={18} className="md:hidden" />
              <span className="hidden md:inline">خروج</span>
            </button>
          </div>
        </header>

        {/* Content Section */}
        <div className="flex-1 overflow-y-auto p-3 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto animate-in fade-in duration-500">
            {activeTab === 'daily-sales' && <DailySales user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} />}
            {activeTab === 'settings' && <Settings user={user} settings={settings} users={users} markets={markets} companies={companies} />}
          </div>
        </div>
      </main>

      {/* Notifications Modal */}
      {isNotificationOpen && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-[100] flex items-center justify-center p-4" onClick={() => setIsNotificationOpen(false)}>
          <div className="bg-white rounded-[2rem] w-full max-w-lg overflow-hidden shadow-2xl animate-in slide-in-from-bottom-10" onClick={e => e.stopPropagation()}>
            <div className="bg-rose-900 p-6 md:p-8 text-white flex justify-between items-center">
              <h3 className="text-xl font-black">صندوق الرسائل</h3>
              <button onClick={() => setIsNotificationOpen(false)} className="p-2 hover:bg-white/10 rounded-full"><X size={24}/></button>
            </div>
            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-4 bg-slate-50">
              {notifications.length === 0 ? (
                <div className="text-center py-12 text-gray-300 font-bold">لا توجد رسائل جديدة</div>
              ) : (
                notifications.map(n => (
                  <div key={n.id} className="p-5 bg-white rounded-2xl border border-rose-100 shadow-sm">
                    <p className="text-sm font-bold text-gray-800 mb-2">{n.message}</p>
                    <div className="flex justify-between items-center text-[10px] text-rose-300 font-bold uppercase">
                      <span>{new Date(n.timestamp).toLocaleString('ar-EG')}</span>
                      <button onClick={() => deleteNotification(n.id)} className="text-red-400 hover:text-red-600"><Trash2 size={14}/></button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, AppSettings, Market, Company, Notification, UserRole } from '../types';
import { db, ref, update, set, push, remove } from '../firebase';
import { 
  Save, UserPlus, Shield, MessageCircle, AlertCircle, 
  Store, Building2, UserCog, Send, Trash2, Edit,
  Settings as SettingsIcon, Key, UserCheck, X, Mail, Hash, User as UserIcon
} from 'lucide-react';

interface Props {
  user: User;
  settings: AppSettings | null;
  users: User[];
  markets: Market[];
  companies: Company[];
}

const Settings: React.FC<Props> = ({ user, settings, users = [], markets = [], companies = [] }) => {
  const [activeSubTab, setActiveSubTab] = useState('general');
  const [newTickerText, setNewTickerText] = useState(settings?.tickerText || '');
  const [newProgramName, setNewProgramName] = useState(settings?.programName || '');
  const [whatsapp, setWhatsapp] = useState(settings?.whatsappNumber || '');

  const [newUser, setNewUser] = useState({ 
    username: '', 
    password: '', 
    employeeName: '', 
    employeeCode: '', 
    role: 'coordinator' as UserRole 
  });

  const [editingPermissions, setEditingPermissions] = useState<string | null>(null);
  const [editingCredentials, setEditingCredentials] = useState<User | null>(null);
  const [editItem, setEditItem] = useState<{id: string, name: string, type: 'markets' | 'companies'} | null>(null);
  const [newItemName, setNewItemName] = useState('');

  // Message Modal State
  const [messageTarget, setMessageTarget] = useState<User | null>(null);
  const [msgText, setMsgText] = useState('');

  const handleSaveGeneral = async () => {
    await update(ref(db, 'settings'), {
      tickerText: newTickerText,
      programName: newProgramName,
      whatsappNumber: whatsapp
    });
    alert("تم حفظ الإعدادات بنجاح");
  };

  const handleDeleteUser = (id: string, name: string) => {
    if (window.confirm(`⚠️ هل أنت متأكد من حذف الموظف "${name}" نهائياً؟`)) {
      remove(ref(db, `users/${id}`));
      alert("تم الحذف بنجاح");
    }
  };

  const handleUpdateCredentials = async () => {
    if (!editingCredentials) return;
    if (!editingCredentials.username || !editingCredentials.password) {
      alert("يرجى ملء كافة البيانات");
      return;
    }
    await update(ref(db, `users/${editingCredentials.id}`), {
      username: editingCredentials.username,
      password: editingCredentials.password
    });
    alert("تم تحديث بيانات الدخول بنجاح");
    setEditingCredentials(null);
  };

  const handleSendMessage = async () => {
    if (!messageTarget || !msgText.trim()) return;
    const notifRef = ref(db, 'notifications');
    await push(notifRef, {
      senderId: user.id,
      receiverId: messageTarget.id,
      message: msgText,
      timestamp: new Date().toISOString(),
      isRead: false
    });
    alert("تم إرسال الرسالة بنجاح");
    setMessageTarget(null);
    setMsgText('');
  };

  const handleDeleteItem = (id: string, type: 'markets' | 'companies', name: string) => {
    if (window.confirm(`⚠️ هل أنت متأكد من حذف "${name}"؟ هذا الإجراء قد يؤثر على السجلات المرتبطة.`)) {
      remove(ref(db, `${type}/${id}`));
      alert("تم الحذف بنجاح");
    }
  };

  const handleUpdateItem = async () => {
    if (!editItem || !editItem.name.trim()) return;
    await update(ref(db, `${editItem.type}/${editItem.id}`), {
      name: editItem.name.trim()
    });
    alert("تم تعديل الاسم بنجاح");
    setEditItem(null);
  };

  const getRoleLabel = (role: string) => {
    const roles: Record<string, string> = {
      admin: 'مدير نظام',
      coordinator: 'منسق',
      usher: 'أشر'
    };
    return roles[role] || role;
  };

  const permissionLabels: Record<string, string> = {
    registerSales: 'المبيعات اليومية',
    viewSalesHistory: 'سجل المبيعات',
    registerInventory: 'تسجيل المخزون',
    viewInventoryHistory: 'سجل المخزون',
    registerCompetitorPrices: 'أسعار المنافسين',
    viewCompetitorReports: 'تقارير المنافسين',
    viewVacationMgmt: 'رصيد الإجازات',
    viewSettings: 'إعدادات النظام',
    viewColleaguesSales: 'رؤية مبيعات الزملاء'
  };

  return (
    <div className="space-y-8 pb-20 px-2 md:px-0">
      {/* Navigation Pills */}
      <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar">
        {[
          { id: 'general', label: 'عام', icon: <SettingsIcon size={18}/> },
          { id: 'users', label: 'الموظفين', icon: <UserCog size={18}/> },
          { id: 'markets', label: 'الماركتات', icon: <Store size={18}/> },
          { id: 'companies', label: 'المنافسين', icon: <Building2 size={18}/> },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id)}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl whitespace-nowrap transition-all font-black text-xs ${activeSubTab === tab.id ? 'bg-rose-800 text-white shadow-lg' : 'bg-white text-gray-500 border border-slate-100'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'general' && (
        <div className="bg-white p-6 md:p-10 rounded-[2rem] shadow-sm border border-rose-50 animate-in fade-in">
          <h3 className="text-xl font-black text-rose-900 mb-8">الإعدادات العامة</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mr-2">اسم البرنامج</label>
              <input className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200" value={newProgramName} onChange={e => setNewProgramName(e.target.value)}/>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mr-2">رقم الواتساب</label>
              <input className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200" value={whatsapp} onChange={e => setWhatsapp(e.target.value)}/>
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mr-2">نص شريط الأخبار</label>
              <textarea className="w-full bg-slate-50 rounded-xl p-4 font-bold outline-none border-2 border-transparent focus:border-rose-200 h-32 resize-none" value={newTickerText} onChange={e => setNewTickerText(e.target.value)}/>
            </div>
          </div>
          <button onClick={handleSaveGeneral} className="w-full md:w-auto bg-rose-800 text-white px-10 py-4 rounded-xl font-black flex items-center justify-center gap-2">
            <Save size={18}/> حفظ التعديلات
          </button>
        </div>
      )}

      {activeSubTab === 'users' && (
        <div className="space-y-8 animate-in fade-in">
          <div className="bg-white p-6 md:p-10 rounded-[2rem] border border-rose-50 shadow-sm">
            <h3 className="text-xl font-black text-rose-900 mb-6 flex items-center gap-3">
               <UserPlus className="text-rose-800" /> إضافة موظف جديد
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="space-y-1">
                <label className="text-[9px] font-black text-gray-400 mr-2 uppercase">الاسم الكامل (يظهر في السجلات)</label>
                <input className="w-full bg-slate-50 p-4 rounded-xl font-bold text-sm outline-none border-2 border-transparent focus:border-rose-200" placeholder="أدخل اسم الموظف" value={newUser.employeeName} onChange={e => setNewUser({...newUser, employeeName: e.target.value})}/>
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-gray-400 mr-2 uppercase">كود الموظف</label>
                <input className="w-full bg-slate-50 p-4 rounded-xl font-bold text-sm outline-none border-2 border-transparent focus:border-rose-200" placeholder="مثال: SR-001" value={newUser.employeeCode} onChange={e => setNewUser({...newUser, employeeCode: e.target.value})}/>
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-gray-400 mr-2 uppercase">المسمى الوظيفي</label>
                <select className="w-full bg-slate-50 p-4 rounded-xl font-bold text-sm outline-none border-2 border-transparent focus:border-rose-200 h-[56px]" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as any})}>
                  <option value="coordinator">منسق</option>
                  <option value="usher">أشر</option>
                  <option value="admin">مدير</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-gray-400 mr-2 uppercase">اسم المستخدم (للدخول)</label>
                <input className="w-full bg-slate-50 p-4 rounded-xl font-bold text-sm outline-none border-2 border-transparent focus:border-rose-200" placeholder="Username" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})}/>
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-gray-400 mr-2 uppercase">كلمة المرور</label>
                <input className="w-full bg-slate-50 p-4 rounded-xl font-bold text-sm outline-none border-2 border-transparent focus:border-rose-200" type="password" placeholder="••••••••" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})}/>
              </div>
            </div>
            <button onClick={() => {
              if(!newUser.username || !newUser.password || !newUser.employeeName) return alert("يرجى إكمال جميع البيانات الأساسية");
              const id = push(ref(db, 'users')).key || '';
              set(ref(db, `users/${id}`), { 
                ...newUser, 
                id, 
                isOnline: false, 
                vacationBalance: { annual: 14, casual: 7, sick: 0, exams: 0, absent_with_permission: 0, absent_without_permission: 0 },
                permissions: { 
                  registerSales: true,
                  viewSalesHistory: true, 
                  registerInventory: true, 
                  viewInventoryHistory: true, 
                  registerCompetitorPrices: true,
                  viewCompetitorReports: true,
                  viewVacationMgmt: true,
                  viewSettings: false,
                  viewColleaguesSales: false 
                } 
              });
              setNewUser({ username: '', password: '', employeeName: '', employeeCode: '', role: 'coordinator' });
              alert("تمت إضافة الموظف بنجاح");
            }} className="mt-6 bg-rose-800 text-white px-10 py-4 rounded-xl font-black shadow-lg shadow-rose-100 hover:bg-rose-900 transition-all flex items-center gap-2">
              <UserCheck size={20}/> تأكيد إضافة الحساب
            </button>
          </div>

          <div className="bg-white rounded-[2rem] border border-rose-50 overflow-hidden shadow-sm">
            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-slate-50 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                  <tr>
                    <th className="p-6">الموظف</th>
                    <th className="p-6">الكود</th>
                    <th className="p-6">الوظيفة</th>
                    <th className="p-6 text-center">الإجراءات</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {users.map(u => (
                    <tr key={u.id} className="hover:bg-rose-50/20">
                      <td className="p-6">
                        <div className="flex items-center gap-3">
                          <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black ${u.isOnline ? 'bg-blue-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                            {u.employeeName?.charAt(0) || '?'}
                          </div>
                          <div className="flex flex-col">
                            <span className="font-bold text-sm text-gray-800">{u.employeeName}</span>
                            <span className="text-[10px] text-gray-400 font-bold">@{u.username}</span>
                          </div>
                        </div>
                      </td>
                      <td className="p-6 font-bold text-xs text-slate-500">{u.employeeCode || '---'}</td>
                      <td className="p-6 font-bold text-xs text-rose-500">{getRoleLabel(u.role)}</td>
                      <td className="p-6">
                        <div className="flex gap-2 justify-center">
                          <button onClick={() => setMessageTarget(u)} className="p-2 bg-amber-50 text-amber-600 rounded-lg hover:bg-amber-600 hover:text-white transition-all" title="إرسال رسالة"><Mail size={16}/></button>
                          <button onClick={() => setEditingCredentials(u)} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-600 hover:text-white transition-all" title="تعديل بيانات الدخول"><Key size={16}/></button>
                          <button onClick={() => setEditingPermissions(u.id)} className="p-2 bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-600 hover:text-white transition-all" title="تعديل الصلاحيات"><Shield size={16}/></button>
                          <button onClick={() => handleDeleteUser(u.id, u.employeeName)} className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-600 hover:text-white transition-all" title="حذف"><Trash2 size={16}/></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {(activeSubTab === 'markets' || activeSubTab === 'companies') && (
        <div className="space-y-6 animate-in fade-in">
          <div className="bg-white p-6 md:p-10 rounded-[2.5rem] border border-rose-50 shadow-sm">
            <h3 className="text-xl font-black text-rose-900 mb-6">إضافة {activeSubTab === 'markets' ? 'ماركت' : 'شركة منافسة'}</h3>
            <div className="flex gap-4">
              <input 
                className="flex-1 bg-slate-50 p-4 rounded-xl font-bold outline-none border-2 border-transparent focus:border-rose-200" 
                placeholder={`أدخل اسم ${activeSubTab === 'markets' ? 'الماركت' : 'الشركة'} الجديد...`}
                value={newItemName}
                onChange={e => setNewItemName(e.target.value)}
              />
              <button 
                onClick={() => {
                  if(!newItemName.trim()) return;
                  push(ref(db, activeSubTab), { name: newItemName.trim(), creatorId: user.id });
                  setNewItemName('');
                  alert("تمت الإضافة بنجاح");
                }}
                className="bg-rose-800 text-white px-8 py-4 rounded-xl font-black shadow-lg shadow-rose-100"
              >إضافة</button>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {(activeSubTab === 'markets' ? markets : companies).map(item => (
              <div key={item.id} className="bg-white p-6 rounded-[2rem] border border-rose-50 shadow-sm flex items-center justify-between group hover:border-rose-200 transition-all">
                <span className="font-bold text-gray-700">{item.name}</span>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                  <button onClick={() => setEditItem({id: item.id, name: item.name, type: activeSubTab})} className="p-2 bg-blue-50 text-blue-600 rounded-lg"><Edit size={14}/></button>
                  <button onClick={() => handleDeleteItem(item.id, activeSubTab, item.name)} className="p-2 bg-red-50 text-red-500 rounded-lg"><Trash2 size={14}/></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Send Message Modal */}
      {messageTarget && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] p-8 max-w-md w-full shadow-2xl animate-in zoom-in-95">
            <div className="flex items-center justify-between mb-6">
              <h4 className="text-xl font-black text-rose-900 flex items-center gap-2"><Send size={20} /> إرسال رسالة للموظف</h4>
              <button onClick={() => setMessageTarget(null)}><X size={24} className="text-gray-400"/></button>
            </div>
            <p className="text-xs font-bold text-gray-400 mb-4">المستلم: {messageTarget.employeeName}</p>
