import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, MessageCircle, Calendar,
  Loader2, Wifi, WifiOff, Palette, Copy, Trash2, User as UserIcon, Trophy
} from 'lucide-react';
import { db, ref, onValue, set, update, push, remove } from './firebase';
import { User, AppSettings, Notification, AppTheme, Market, Company, DailySale } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [sales, setSales] = useState<DailySale[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<AppTheme>('standard');
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    window.addEventListener('online', () => setIsOnline(true));
    window.addEventListener('offline', () => setIsOnline(false));

    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) setUsers(Object.values(data));
    });

    onValue(ref(db, 'sales'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSales(Object.values(data));
      else setSales([]);
    });

    setIsLoading(false);
  }, []);

  const starOfMonthInfo = useMemo(() => {
    const now = new Date();
    const currentMonthSales = sales.filter(s => {
      const d = new Date(s.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });

    const userTotals: Record<string, {name: string, total: number}> = {};
    currentMonthSales.forEach(s => {
      if (!userTotals[s.userId]) userTotals[s.userId] = { name: s.userName, total: 0 };
      userTotals[s.userId].total += (s.total || 0);
    });

    const sorted = Object.values(userTotals).sort((a, b) => b.total - a.total);
    return sorted[0] || null;
  }, [sales]);

  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(m => user.role === 'admin' || m.creatorId === user.id || !m.creatorId);
          setMarkets(filtered);
        }
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(c => user.role === 'admin' || c.creatorId === user.id || !c.creatorId);
          setCompanies(filtered);
        }
      });
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      const notifRef = ref(db, 'notifications');
      onValue(notifRef, (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const allNotifs = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
          const myNotifs = allNotifs.filter(n => n.receiverId === 'all' || n.receiverId === user.id);
          setNotifications(myNotifs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
        } else {
          setNotifications([]);
        }
      });
    }
  }, [user]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user && user.id !== 'admin-id') {
      update(ref(db, `users/${user.id}`), { isOnline: false });
    }
    setUser(null);
  };

  const deleteNotification = (id: string) => {
    remove(ref(db, `notifications/${id}`));
  };

  const cycleTheme = () => {
    if (theme === 'standard') setTheme('glass');
    else if (theme === 'glass') setTheme('dark');
    else setTheme('standard');
  };

  const openWhatsApp = () => {
    if (settings?.whatsappNumber) {
      window.open(`https://wa.me/${settings.whatsappNumber}`, '_blank');
    } else {
      alert("رقم الواتساب غير مسجل في الإعدادات");
    }
  };

  if (isLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-rose-50">
      <Loader2 className="animate-spin text-rose-600 mb-4" size={48}/>
      <p className="text-rose-900 font-bold animate-pulse">جاري تحميل نظام Soft Rose...</p>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} />;

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: user.role === 'admin' || user.permissions?.registerSales },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: user.role === 'admin' || user.permissions?.viewSalesHistory },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: user.role === 'admin' || user.permissions?.registerInventory },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: user.role === 'admin' || user.permissions?.viewInventoryHistory },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: user.role === 'admin' || user.permissions?.registerCompetitorPrices },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: user.role === 'admin' || user.permissions?.viewCompetitorReports },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: user.role === 'admin' || user.permissions?.viewVacationMgmt },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user.role === 'admin' || user.permissions?.viewSettings },
  ].filter(i => i.visible);

  const getRoleLabel = (role: string) => {
    switch (role) {
      case 'admin': return 'مدير';
      case 'coordinator': return 'منسق';
      case 'usher': return 'أشر';
      default: return 'موظف';
    }
  };

  const constructedTickerText = useMemo(() => {
    let text = settings?.tickerText || '';
    if (settings?.showTopSalesInTicker && starOfMonthInfo) {
      text = `🏆 نجم الشهر الحالي: ${starOfMonthInfo.name} بمبيعات إجمالية ${starOfMonthInfo.total.toLocaleString()} ج.م 🏆 | ` + text;
    }
    return text;
  }, [settings, starOfMonthInfo]);

  return (
    <div className={`flex h-screen overflow-hidden theme-${theme} transition-all duration-300 relative`}>
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-40 md:hidden backdrop-blur-sm" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar Section */}
      <aside className={`bg-rose-900 text-white w-72 flex-shrink-0 transition-all duration-300 z-50 fixed md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:right-0'} ${theme === 'glass' ? 'bg-rose-900/70 backdrop-blur-xl border-l border-white/10' : ''} shadow-2xl`}>
        <div className="p-6 flex flex-col h-full">
          <div className="mb-8 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-widest text-rose-300">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 hover:bg-white/10 rounded-full"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-1.5 overflow-y-auto custom-scrollbar pr-2">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl transition-all duration-200 ${activeTab === item.id ? 'bg-white text-rose-900 font-bold shadow-xl shadow-black/10' : 'hover:bg-white/10 opacity-80 hover:opacity-100'}`}
              >
                <span className={activeTab === item.id ? 'text-rose-600' : 'text-white'}>{item.icon}</span>
                <span className="text-sm font-bold">{item.label}</span>
              </button>
            ))}

            {user.role === 'admin' && (
              <div className="mt-8 pt-6 border-t border-white/10">
                <p className="text-[10px] uppercase text-rose-400 px-5 mb-4 font-black tracking-widest">الموظفون المتصلون</p>
                <div className="space-y-2">
                  {users.map(u => (
                    <div key={u.id} className="flex items-center gap-3 px-5 py-1">
                      <div className="relative">
                        <div className={`w-2 h-2 rounded-full ${u.isOnline ? 'bg-blue-400 shadow-[0_0_8px_rgba(96,165,250,0.8)]' : 'bg-rose-800'}`}></div>
                      </div>
                      <span className={`text-[11px] font-bold ${u.isOnline ? 'text-white' : 'text-rose-400/60'}`}>{u.employeeName}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </nav>
        </div>
      </aside>

      <main className={`flex-1 flex flex-col min-w-0 overflow-hidden ${theme === 'dark' ? 'bg-[#0a0a0a]' : 'bg-[#F9FAFB]'}`}>

        {/* Ticker Section */}
        {constructedTickerText && (
          <div className="bg-rose-950 py-2 text-white text-[11px] md:text-[13px] overflow-hidden border-b border-rose-900/50 shadow-inner z-50">
            <div className="ticker-container">
              <div className="ticker-text font-bold opacity-90" style={{ animationDuration: '45s' }}>
                {constructedTickerText} &nbsp;&nbsp; ★ &nbsp;&nbsp; {constructedTickerText}
              </div>
            </div>
          </div>
        )}

        {/* Improved Header Section */}
        <header className={`h-16 md:h-20 flex items-center justify-between px-3 md:px-8 border-b transition-all duration-300 z-30 ${theme === 'glass' ? 'bg-white/40 backdrop-blur-md border-white/20 shadow-sm' : 'bg-white shadow-sm'} ${theme === 'dark' ? 'bg-[#121212] border-[#222]' : ''}`}>
          <div className="flex items-center gap-2 md:gap-4 flex-1 min-w-0">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 hover:bg-rose-50 rounded-xl transition-all">
              <Menu size={20} className="text-rose-800" />
            </button>
            <div className="flex flex-col truncate">
              <h2 className="font-black text-rose-900 text-sm md:text-xl tracking-tighter uppercase leading-tight truncate">
                {settings?.programName || 'Soft Rose Modern Trade'}
              </h2>
              <div className="flex items-center gap-1 mt-0.5">
                <span className="text-[9px] md:text-[10px] font-bold text-gray-400 uppercase tracking-widest truncate">
                  {user.employeeName} • {getRoleLabel(user.role)}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 md:gap-2">
            {/* Control Center Pill */}
            <div className="flex items-center bg-slate-100/70 p-1 rounded-xl md:rounded-2xl gap-0.5 md:gap-1 shadow-inner">
              <button onClick={openWhatsApp} className="p-2 md:p-3 hover:bg-green-50 text-green-600 rounded-lg md:rounded-xl transition-all" title="واتساب">
                <MessageCircle size={18} />
              </button>

              <button onClick={cycleTheme} className="p-2 md:p-3 hover:bg-white hover:shadow-md rounded-lg md:rounded-xl text-amber-500 transition-all" title="الاستايل">
                <Palette size={18} />
              </button>

              <div className={`p-2 md:p-3 rounded-lg md:rounded-xl ${isOnline ? 'text-blue-600' : 'text-red-500'}`} title={isOnline ? 'متصل' : 'غير متصل'}>
                {isOnline ? <Wifi size={18} /> : <WifiOff size={18} />}
              </div>

              <button onClick={() => setIsNotificationOpen(true)} className="relative p-2 md:p-3 hover:bg-rose-50 rounded-lg md:rounded-xl text-gray-500 transition-all" title="الإشعارات">
                <Bell size={18} />
                {unreadCount > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-red-600 border-2 border-white rounded-full"></span>
                )}
              </button>
            </div>

            <button onClick={handleLogout} className="p-2 md:p-3 bg-rose-50 text-rose-800 rounded-xl md:rounded-2xl hover:bg-rose-100 transition-all font-bold text-[11px] md:text-sm border border-rose-100 ml-1">
              <LogOut size={18} className="md:hidden" />
              <span className="hidden md:inline">خروج</span>
            </button>
          </div>
        </header>

        {/* Content Section */}
        <div className="flex-1 overflow-y-auto p-3 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto animate-in fade-in duration-500">
            {activeTab === 'daily-sales' && <DailySales user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} />}
            {activeTab === 'settings' && <Settings user={user} settings={settings} users={users} markets={markets} companies={companies} />}
          </div>
        </div>
      </main>

      {/* Notifications Modal */}
      {isNotificationOpen && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-[100] flex items-center justify-center p-4" onClick={() => setIsNotificationOpen(false)}>
          <div className="bg-white rounded-[2rem] w-full max-w-lg overflow-hidden shadow-2xl animate-in slide-in-from-bottom-10" onClick={e => e.stopPropagation()}>
            <div className="bg-rose-900 p-6 md:p-8 text-white flex justify-between items-center">
              <h3 className="text-xl font-black">صندوق الرسائل</h3>
              <button onClick={() => setIsNotificationOpen(false)} className="p-2 hover:bg-white/10 rounded-full"><X size={24}/></button>
            </div>
            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-4 bg-slate-50">
              {notifications.length === 0 ? (
                <div className="text-center py-12 text-gray-300 font-bold">لا توجد رسائل جديدة</div>
              ) : (
                notifications.map(n => (
                  <div key={n.id} className="p-5 bg-white rounded-2xl border border-rose-100 shadow-sm">
                    <p className="text-sm font-bold text-gray-800 mb-2">{n.message}</p>
                    <div className="flex justify-between items-center text-[10px] text-rose-300 font-bold uppercase">
                      <span>{new Date(n.timestamp).toLocaleString('ar-EG')}</span>
                      <button onClick={() => deleteNotification(n.id)} className="text-red-400 hover:text-red-600"><Trash2 size={14}/></button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { User, DailySale, SaleItem } from '../types';
import { Search, Trash2, Edit, Trophy, BarChart3, FileSpreadsheet, ListFilter, X, Clock, Calendar as CalendarIcon, User as UserIcon, Store, History, Package } from 'lucide-react';
import { db, ref, onValue, remove, update } from '../firebase';
import * as XLSX from 'xlsx';

interface Props {
  user: User;
  markets: string[];
  users: User[];
}

const SalesHistory: React.FC<Props> = ({ user, markets = [], users = [] }) => {
  const [sales, setSales] = useState<DailySale[]>([]);
  const [selectedSale, setSelectedSale] = useState<DailySale | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [filters, setFilters] = useState({
    dateStart: '',
    dateEnd: '',
    employeeId: '',
    marketName: ''
  });

  useEffect(() => {
    const salesRef = ref(db, 'sales');
    onValue(salesRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        let salesList = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));

        if (user.role === 'coordinator' || user.role === 'usher') {
           if (!user.permissions?.viewColleaguesSales) {
             salesList = salesList.filter(s => s.userId === user.id);
           }
        }
        setSales(salesList.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
      } else {
        setSales([]);
      }
    });
  }, [user]);

  const stats = useMemo(() => {
    const now = new Date();
    const currentMonthSales = sales.filter(s => {
      const d = new Date(s.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });

    const userTotals: Record<string, {name: string, total: number}> = {};
    const productTotals: Record<string, {quantity: number, total: number}> = {};

    currentMonthSales.forEach(s => {
      if (!userTotals[s.userId]) userTotals[s.userId] = { name: s.userName, total: 0 };
      userTotals[s.userId].total += (s.total || 0);

      s.items.forEach(item => {
        if (!productTotals[item.productName]) productTotals[item.productName] = { quantity: 0, total: 0 };
        productTotals[item.productName].quantity += Number(item.quantity);
        productTotals[item.productName].total += (Number(item.price) * Number(item.quantity));
      });
    });

    const star = Object.values(userTotals).sort((a, b) => b.total - a.total)[0] || null;
    const topProducts = Object.entries(productTotals)
      .sort((a, b) => b[1].quantity - a[1].quantity)
      .slice(0, 3);

    return { star, topProducts };
  }, [sales]);

  const handleDelete = (id: string) => {
    if (window.confirm("⚠️ هل أنت متأكد من حذف هذه العملية نهائياً؟ لا يمكن التراجع عن هذا الإجراء.")) {
      remove(ref(db, `sales/${id}`));
      alert("تم الحذف بنجاح");
    }
  };

  const filteredSales = sales.filter(s => {
    const sDate = s.date ? s.date.split('T')[0] : '';
    const matchStart = filters.dateStart ? sDate >= filters.dateStart : true;
    const matchEnd = filters.dateEnd ? sDate <= filters.dateEnd : true;
    const matchEmp = filters.employeeId ? s.userId === filters.employeeId : true;
    const matchMarket = filters.marketName ? s.marketName === filters.marketName : true;
    return matchStart && matchEnd && matchEmp && matchMarket;
  });

  const getDayName = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('ar-EG', { weekday: 'long' });
  };

  return (
    <div className="space-y-6 pb-20 px-1 md:px-0" dir="rtl">
      {/* Header Stats */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-5 rounded-[2rem] border border-rose-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="p-3 bg-rose-900 text-white rounded-2xl shadow-lg"><History size={24} /></div>
          <div>
            <h2 className="text-xl font-black text-rose-900 leading-none">سجل المبيعات التفصيلي</h2>
            <p className="text-[10px] font-bold text-gray-400 mt-1 uppercase tracking-widest">Detailed Transaction Log</p>
          </div>
        </div>
        <button onClick={() => {
              const data = filteredSales.flatMap(s => s.items.map(i => ({ 
                "الماركت": s.marketName, 
                "الموظف": s.userName, 
                "التاريخ": s.date.split('T')[0], 
                "الصنف": i.productName,
                "السعر": i.price,
                "الكمية": i.quantity,
                "الإجمالي": i.price * i.quantity
              })));
              const ws = XLSX.utils.json_to_sheet(data);
              const wb = XLSX.utils.book_new();
              XLSX.utils.book_append_sheet(wb, ws, "Sales");
              XLSX.writeFile(wb, "SoftRose_Detailed_Sales.xlsx");
        }} className="flex items-center justify-center gap-2 bg-green-600 text-white px-6 py-3 rounded-xl font-black text-xs hover:bg-green-700 transition-all">
          <FileSpreadsheet size={18}/> تصدير السجل بالكامل
        </button>
      </div>

      {/* Star of the Month & Top Items Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Star of the Month */}
        <div className="bg-gradient-to-br from-rose-800 to-rose-950 p-6 rounded-[2rem] text-white shadow-xl relative overflow-hidden">
          <Trophy className="absolute -right-4 -bottom-4 w-32 h-32 opacity-10 rotate-12" />
          <div className="relative z-10">
            <div className="flex items-center gap-2 mb-4">
              <Trophy className="text-amber-400" size={24} />
              <h3 className="font-black text-sm uppercase tracking-widest">نجم شهر {new Date().toLocaleDateString('ar-EG', {month: 'long'})}</h3>
            </div>
            {stats.star ? (
              <div>
                <p className="text-2xl font-black mb-1">{stats.star.name}</p>
                <div className="flex items-baseline gap-2">
                  <span className="text-3xl font-black text-amber-400">{stats.star.total.toLocaleString()}</span>
                  <span className="text-xs font-bold opacity-60">جنية مبيعات محققة</span>
                </div>
              </div>
            ) : (
              <p className="text-sm font-bold opacity-50 italic">جاري احتساب البيانات...</p>
            )}
            <p className="text-[9px] font-bold opacity-40 mt-4">* يتم التحديث لحظياً من يوم 1 حتى 30 من الشهر</p>
          </div>
        </div>

        {/* Top Products */}
        <div className="bg-white p-6 rounded-[2rem] border border-rose-100 shadow-sm">
          <div className="flex items-center gap-2 mb-4 text-rose-900">
            <BarChart3 size={24} />
            <h3 className="font-black text-sm uppercase tracking-widest">الأصناف الأكثر مبيعاً</h3>
          </div>
          <div className="space-y-3">
            {stats.topProducts.map(([name, data], idx) => (
              <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl border border-slate-100">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-rose-100 text-rose-600 flex items-center justify-center font-black text-xs">{idx + 1}</div>
                  <div>
                    <p className="text-xs font-black text-gray-800 leading-none">{name}</p>
                    <p className="text-[10px] font-bold text-gray-400 mt-1">{data.quantity} قطعة مباعة</p>
                  </div>
                </div>
                <div className="text-left">
                  <p className="text-sm font-black text-rose-700">{data.total.toLocaleString()} ج.م</p>
                </div>
              </div>
            ))}
            {stats.topProducts.length === 0 && (
              <p className="text-center py-6 text-gray-300 font-bold italic text-xs">لا توجد بيانات مبيعات لهذا الشهر</p>
            )}
          </div>
        </div>
      </div>

      {/* Filter Section */}
      <div className="bg-white p-4 md:p-6 rounded-[2rem] shadow-sm border border-rose-50">
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          <div className="space-y-1">
            <label className="text-[9px] font-black text-gray-400 mr-2">من تاريخ</label>
            <input type="date" className="w-full bg-slate-50 p-3 rounded-xl font-bold text-[11px] outline-none border-2 border-transparent focus:border-rose-200" value={filters.dateStart} onChange={e => setFilters({...filters, dateStart:e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-gray-400 mr-2">إلى تاريخ</label>
            <input type="date" className="w-full bg-slate-50 p-3 rounded-xl font-bold text-[11px] outline-none border-2 border-transparent focus:border-rose-200" value={filters.dateEnd} onChange={e => setFilters({...filters, dateEnd:e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-gray-400 mr-2">الموظف</label>
            <select className="w-full bg-slate-50 p-3 rounded-xl font-bold text-[11px] outline-none border-2 border-transparent focus:border-rose-200" value={filters.employeeId} onChange={e => setFilters({...filters, employeeId:e.target.value})}>
              <option value="">كل الموظفين</option>
              {users.map(u => <option key={u.id} value={u.id}>{u.employeeName}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-gray-400 mr-2">الماركت</label>
            <select className="w-full bg-slate-50 p-3 rounded-xl font-bold text-[11px] outline-none border-2 border-transparent focus:border-rose-200" value={filters.marketName} onChange={e => setFilters({...filters, marketName:e.target.value})}>
              <option value="">كل الماركت</option>
              {markets.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
        </div>
      </div>

      {/* Sales Cards - Mobile Optimized Grid */}
      <div className="grid grid-cols-1 gap-6">
        {filteredSales.map(sale => {
          const sDate = new Date(sale.date);
          return (
            <div key={sale.id} className="bg-white rounded-[2rem] border border-rose-50 shadow-md overflow-hidden animate-in fade-in slide-in-from-bottom-2">

              {/* Card Header: Market, Day, Employee */}
              <div className="bg-slate-50 p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex flex-wrap items-center gap-3 md:gap-6">
                  <div className="flex items-center gap-2">
                    <div className="p-2 bg-rose-100 text-rose-700 rounded-lg"><Store size={18}/></div>
                    <span className="font-black text-rose-900 text-sm md:text-lg">{sale.marketName}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="p-2 bg-blue-100 text-blue-700 rounded-lg"><CalendarIcon size={18}/></div>
                    <span className="font-bold text-slate-600 text-[11px] md:text-sm">
                      {getDayName(sale.date)} - {sDate.toLocaleDateString('ar-EG')}
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="p-2 bg-slate-200 text-slate-600 rounded-lg"><UserIcon size={18}/></div>
                    <span className="font-bold text-slate-600 text-[11px] md:text-sm">{sale.userName}</span>
                  </div>
                </div>

                {/* Edit/Delete Buttons on the Left (End) */}
                {user.role === 'admin' && (
                  <div className="flex items-center gap-2 self-end md:self-center">
                    <button 
                      onClick={() => { setSelectedSale(sale); setIsEditing(true); }}
                      className="flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all font-black text-xs"
                    >
                      <Edit size={14}/> تعديل
                    </button>
                    <button 
                      onClick={() => handleDelete(sale.id)}
                      className="flex items-center gap-2 px-4 py-2 bg-red-50 text-red-500 rounded-xl hover:bg-red-600 hover:text-white transition-all font-black text-xs"
                    >
                      <Trash2 size={14}/> حذف
                    </button>
                  </div>
                )}
              </div>

              {/* Card Body: Items Table */}
              <div className="p-4 md:p-6 overflow-x-auto">
                <table className="w-full text-right text-[10px] md:text-xs">
                  <thead className="bg-slate-50/50 text-gray-400 font-black uppercase tracking-widest">
                    <tr>
                      <th className="p-3">اسم الصنف</th>
                      <th className="p-3 text-center">السعر</th>
                      <th className="p-3 text-center">العدد</th>
                      <th className="p-3 text-center">الإجمالي</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {sale.items.map((item, idx) => (
                      <tr key={idx} className="hover:bg-slate-50/30">
                        <td className="p-3 font-bold text-gray-700">{item.productName}</td>
                        <td className="p-3 text-center font-bold text-rose-600">{item.price} ج.م</td>
                        <td className="p-3 text-center font-black text-blue-600">{item.quantity}</td>
                        <td className="p-3 text-center font-black text-gray-900">{(item.price * item.quantity).toLocaleString()} ج.م</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Card Footer: Final Total */}
              <div className="bg-rose-900 p-4 md:p-6 text-white flex justify-between items-center">
                <div className="flex items-center gap-2">
                  <Clock size={16} className="opacity-50" />
                  <span className="text-[10px] font-bold opacity-70">وقت التسجيل: {sDate.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })}</span>
                </div>
                <div className="flex items-center gap-3">
                  <span className="text-xs font-bold opacity-60">إجمالي الفاتورة:</span>
                  <span className="text-lg md:text-2xl font-black">{(sale.total || 0).toLocaleString()} <span className="text-xs opacity-50">ج.م</span></span>
                </div>
              </div>
            </div>
          );
        })}
        {filteredSales.length === 0 && (
          <div className="bg-white py-24 rounded-[3rem] text-center border-2 border-dashed border-rose-100">
            <div className="w-20 h-20 bg-rose-50 rounded-full flex items-center justify-center mx-auto mb-6 text-rose-200">
              <History size={40} />
            </div>
            <p className="text-gray-400 font-black text-sm">لا توجد عمليات بيع مسجلة ضمن هذه الفلاتر</p>
          </div>
        )}
      </div>

      {/* Edit Modal */}
      {selectedSale && isEditing && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-2xl overflow-hidden shadow-2xl animate-in zoom-in-95">
            <div className="bg-rose-900 p-6 text-white flex justify-between items-center">
              <div>
                <h3 className="text-lg font-black">تعديل سجل مبيعات</h3>
                <p className="text-[9px] font-bold text-rose-300 uppercase mt-1">{selectedSale.marketName} • {new Date(selectedSale.date).toLocaleString('ar-EG')}</p>
              </div>
              <button onClick={() => { setSelectedSale(null); setIsEditing(false); }} className="p-2 hover:bg-white/10 rounded-full"><X size={24}/></button>
            </div>

            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-3">
              <div className="grid grid-cols-4 gap-2 text-[9px] font-black text-gray-400 uppercase text-center">
                <span className="text-right">الصنف</span>
                <span>السعر</span>
                <span>العدد</span>
                <span>الإجمالي</span>
              </div>

              {selectedSale.items?.map((item, idx) => (
                <div key={idx} className="grid grid-cols-4 gap-2 p-3 bg-slate-50 rounded-xl items-center text-[11px] font-bold">
                  <span className="text-gray-800 leading-tight">{item.productName}</span>
                  <input 
                    type="number" 
                    className="w-16 bg-white border border-slate-200 rounded p-1 text-center"
                    value={item.price}
                    onChange={(e) => {
                      const newItems = [...selectedSale.items];
                      newItems[idx].price = Number(e.target.value);
                      setSelectedSale({...selectedSale, items: newItems});
                    }}
                  />
                  <input 
                    type="number" 
                    className="w-16 bg-white border border-slate-200 rounded p-1 text-center"
                    value={item.quantity}
                    onChange={(e) => {
                      const newItems = [...selectedSale.items];
                      newItems[idx].quantity = Number(e.target.value);
                      setSelectedSale({...selectedSale, items: newItems});
                    }}
                  />
                  <span className="text-center text-rose-600 font-black">{(item.price * item.quantity).toLocaleString()}</span>
                </div>
              ))}
            </div>

            <div className="p-6 bg-rose-50 border-t flex justify-between items-center">
               <span className="font-black text-rose-900 text-sm">الإجمالي المحدث</span>
               <div className="flex items-center gap-4">
                  <span className="text-xl font-black text-rose-900">
                    {selectedSale.items.reduce((acc, i) => acc + (i.price * i.quantity), 0).toLocaleString()} ج.م
                  </span>
                  <button 
                    onClick={async () => {
                      const newTotal = selectedSale.items.reduce((acc, i) => acc + (i.price * i.quantity), 0);
                      await update(ref(db, `sales/${selectedSale.id}`), {
                        items: selectedSale.items,
                        total: newTotal
                      });
                      alert("تم تحديث البيانات بنجاح");
                      setSelectedSale(null);
                      setIsEditing(false);
                    }}
                    className="bg-rose-800 text-white px-6 py-2 rounded-xl font-black text-sm shadow-lg shadow-rose-100"
                  >حفظ التغييرات</button>
               </div>
            </div>
          </div>
        </div>
      )}

      {/* Detail Modal (Non-Edit View) */}
      {selectedSale && !isEditing && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4" onClick={() => setSelectedSale(null)}>
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-rose-900">تفاصيل السجل</h3>
                <button onClick={() => setSelectedSale(null)} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button>
             </div>
             <div className="space-y-4">
                {selectedSale.items.map((item, idx) => (
                  <div key={idx} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl">
                    <div>
                      <p className="font-black text-rose-900 text-sm">{item.productName}</p>
                      <p className="text-[10px] text-gray-400 font-bold">{item.quantity} قطعة × {item.price} ج.م</p>
                    </div>
                    <span className="font-black text-slate-800">{(item.price * item.quantity).toLocaleString()} ج.م</span>
                  </div>
                ))}
                <div className="pt-4 mt-2 border-t flex justify-between items-center">
                  <span className="font-black text-rose-900">إجمالي العملية</span>
                  <span className="text-2xl font-black text-rose-900">{selectedSale.total?.toLocaleString()} ج.م</span>
                </div>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SalesHistory;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Vacation } from '../types';
import { db, ref, onValue, push, set, remove, update } from '../firebase';
import { Calendar, Plus, Trash2, Clock, ChevronRight, ChevronLeft, X, Edit, User as UserIcon } from 'lucide-react';

interface Props {
  user: User;
  users: User[];
}

const VacationManagement: React.FC<Props> = ({ user, users }) => {
  const [vacations, setVacations] = useState<Vacation[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDetails, setSelectedDetails] = useState<{ userId: string, type: string, userName: string } | null>(null);
  const [editingUserBalance, setEditingUserBalance] = useState<User | null>(null);
  const [currentPeriodDate, setCurrentPeriodDate] = useState(new Date());

  const [newVacation, setNewVacation] = useState({
    date: new Date().toISOString().split('T')[0],
    days: 1,
    type: 'annual' as const,
    targetUserId: user.id
  });

  useEffect(() => {
    const vRef = ref(db, 'vacations');
    onValue(vRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setVacations(Object.entries(data).map(([id, val]: any) => ({ ...val, id })));
      } else {
        setVacations([]);
      }
    });
  }, []);

  const handleAddVacation = async () => {
    const vRef = ref(db, 'vacations');
    // For non-admins, ensure they only register for themselves
    const targetUserId = user.role === 'admin' ? newVacation.targetUserId : user.id;
    const targetUser = users.find(u => u.id === targetUserId) || user;

    // Deduction logic for Annual/Casual/AbsentWithPermission
    const currentBalance = targetUser.vacationBalance || { annual: 14, casual: 7, sick: 0, exams: 0 };
    let updatedBalance = { ...currentBalance };

    if (newVacation.type === 'annual') updatedBalance.annual -= newVacation.days;
    else if (newVacation.type === 'casual') updatedBalance.casual -= newVacation.days;
    else if (newVacation.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) - newVacation.days;

    // Save deduction to user object
    await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });

    // Push vacation record
    await push(vRef, {
      ...newVacation,
      userId: targetUser.id,
      userName: targetUser.employeeName,
      createdAt: new Date().toISOString()
    });

    setIsModalOpen(false);
    alert("تم تسجيل الإجازة وخصمها من الرصيد بنجاح");
  };

  const handleDeleteVacation = async (id: string) => {
    if (window.confirm("⚠️ هل أنت متأكد من حذف هذا السجل؟ سيتم إعادة الأيام للرصيد.")) {
      const vToDelete = vacations.find(v => v.id === id);
      if (vToDelete) {
        const targetUser = users.find(u => u.id === vToDelete.userId);
        if (targetUser) {
          const currentBalance = targetUser.vacationBalance || { annual: 14, casual: 7 };
          let updatedBalance = { ...currentBalance };

          if (vToDelete.type === 'annual') updatedBalance.annual += Number(vToDelete.days);
          else if (vToDelete.type === 'casual') updatedBalance.casual += Number(vToDelete.days);
          else if (vToDelete.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) + Number(vToDelete.days);

          await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });
        }
      }
      await remove(ref(db, `vacations/${id}`));
      alert("تم الحذف وإرجاع الرصيد بنجاح");
    }
  };

  const handleSaveBalanceEdit = async () => {
    if (!editingUserBalance) return;
    await update(ref(db, `users/${editingUserBalance.id}`), {
      vacationBalance: editingUserBalance.vacationBalance
    });
    alert("تم تحديث الرصيد بنجاح");
    setEditingUserBalance(null);
  };

  // Helper to get financial month period (21 to 20)
  const getPeriodRange = (baseDate: Date) => {
    let year = baseDate.getFullYear();
    let month = baseDate.getMonth(); // 0-11

    const start = new Date(year, month - 1, 21);
    const end = new Date(year, month, 20);
    return { start, end };
  };

  const currentRange = useMemo(() => getPeriodRange(currentPeriodDate), [currentPeriodDate]);

  const changePeriod = (direction: 'prev' | 'next') => {
    const newDate = new Date(currentPeriodDate);
    if (direction === 'prev') newDate.setMonth(newDate.getMonth() - 1);
    else newDate.setMonth(newDate.getMonth() + 1);
