import React, { useState, useEffect, useMemo } from 'react';
import { User, DailySale } from '../types';
import { Trash2, Edit, Trophy, BarChart3, FileSpreadsheet, X, Clock, Calendar as CalendarIcon, User as UserIcon, Store, History } from 'lucide-react';
import { db, ref, onValue, remove, update } from '../firebase';
import * as XLSX from 'xlsx';

interface Props {
  user: User;
  markets: string[];
  users: User[];
}

const SalesHistory: React.FC<Props> = ({ user, markets = [], users = [] }) => {
  const [sales, setSales] = useState<DailySale[]>([]);
  const [selectedSale, setSelectedSale] = useState<DailySale | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [filters, setFilters] = useState({
    dateStart: '',
    dateEnd: '',
    employeeId: '',
    marketName: ''
  });

  useEffect(() => {
    const salesRef = ref(db, 'sales');
    onValue(salesRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        let salesList = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
        if (user.role === 'coordinator' || user.role === 'usher') {
           if (!user.permissions?.viewColleaguesSales) {
             salesList = salesList.filter(s => s.userId === user.id);
           }
        }
        setSales(salesList.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
      } else {
        setSales([]);
      }
    });
  }, [user]);

  const stats = useMemo(() => {
    const now = new Date();
    const currentMonthSales = sales.filter(s => {
      if (!s.date) return false;
      const d = new Date(s.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });

    const userTotals: Record<string, {name: string, total: number}> = {};
    const productTotals: Record<string, {quantity: number, total: number}> = {};

    currentMonthSales.forEach(s => {
      const uid = s.userId || 'unknown';
      if (!userTotals[uid]) userTotals[uid] = { name: s.userName || 'غير معروف', total: 0 };
      userTotals[uid].total += (Number(s.total) || 0);

      (s.items || []).forEach(item => {
        const pname = item.productName || 'غير معروف';
        if (!productTotals[pname]) productTotals[pname] = { quantity: 0, total: 0 };
        const q = Number(item.quantity) || 0;
        const p = Number(item.price) || 0;
        productTotals[pname].quantity += q;
        productTotals[pname].total += (q * p);
      });
    });

    const star = Object.values(userTotals).sort((a, b) => b.total - a.total)[0] || null;
    const topProducts = Object.entries(productTotals)
      .sort((a, b) => b[1].quantity - a[1].quantity)
      .slice(0, 3);

    return { star, topProducts };
  }, [sales]);

  const handleDelete = (id: string) => {
    if (window.confirm("⚠️ هل أنت متأكد من حذف هذه العملية؟")) {
      remove(ref(db, `sales/${id}`));
    }
  };

  const filteredSales = sales.filter(s => {
    const sDate = s.date ? s.date.split('T')[0] : '';
    const matchStart = filters.dateStart ? sDate >= filters.dateStart : true;
    const matchEnd = filters.dateEnd ? sDate <= filters.dateEnd : true;
    const matchEmp = filters.employeeId ? s.userId === filters.employeeId : true;
    const matchMarket = filters.marketName ? s.marketName === filters.marketName : true;
    return matchStart && matchEnd && matchEmp && matchMarket;
  });

  return (
    <div className="space-y-6 pb-20" dir="rtl">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-5 rounded-[2rem] border border-rose-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="p-3 bg-rose-900 text-white rounded-2xl"><History size={24} /></div>
          <h2 className="text-xl font-black text-rose-900">سجل المبيعات التفصيلي</h2>
        </div>
        <button onClick={() => {
              const data = filteredSales.flatMap(s => (s.items || []).map(i => ({ 
                "الماركت": s.marketName, "الموظف": s.userName, "التاريخ": s.date?.split('T')[0], 
                "الصنف": i.productName, "السعر": i.price, "الكمية": i.quantity, "الإجمالي": (i.price || 0) * (i.quantity || 0)
              })));
              const ws = XLSX.utils.json_to_sheet(data);
              const wb = XLSX.utils.book_new();
              XLSX.utils.book_append_sheet(wb, ws, "Sales");
              XLSX.writeFile(wb, "SoftRose_Sales.xlsx");
        }} className="flex items-center justify-center gap-2 bg-green-600 text-white px-6 py-3 rounded-xl font-black text-xs">
          <FileSpreadsheet size={18}/> تصدير السجل
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-rose-800 to-rose-950 p-6 rounded-[2rem] text-white shadow-xl relative overflow-hidden">
          <Trophy className="absolute -right-4 -bottom-4 w-32 h-32 opacity-10 rotate-12" />
          <div className="relative z-10">
            <h3 className="font-black text-sm uppercase mb-4 flex items-center gap-2">
              <Trophy className="text-amber-400" size={20} /> نجم شهر {new Date().toLocaleDateString('ar-EG', {month: 'long'})}
            </h3>
            {stats.star ? (
              <div>
                <p className="text-2xl font-black mb-1">{stats.star.name}</p>
                <p className="text-3xl font-black text-amber-400">{(stats.star.total || 0).toLocaleString()} <span className="text-xs font-bold opacity-60">ج.م مبيعات</span></p>
              </div>
            ) : <p className="text-sm font-bold opacity-50">لا توجد بيانات مبيعات حالية</p>}
            <p className="text-[9px] font-bold opacity-40 mt-4">* يتم التحديث تلقائياً من يوم 1 حتى 30</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] border border-rose-100 shadow-sm">
          <h3 className="font-black text-sm text-rose-900 mb-4 flex items-center gap-2">
            <BarChart3 size={20} /> الأصناف الأكثر مبيعاً
          </h3>
          <div className="space-y-3">
            {stats.topProducts.map(([name, data], idx) => (
              <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl border border-slate-100">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-rose-100 text-rose-600 flex items-center justify-center font-black text-xs">{idx + 1}</div>
                  <div>
                    <p className="text-xs font-black text-gray-800 leading-none">{name}</p>
                    <p className="text-[10px] font-bold text-gray-400 mt-1">{data.quantity} قطعة</p>
                  </div>
                </div>
                <p className="text-sm font-black text-rose-700">{(data.total || 0).toLocaleString()} ج.م</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {filteredSales.map(sale => (
          <div key={sale.id} className="bg-white rounded-[2rem] border border-rose-50 shadow-md overflow-hidden">
            <div className="bg-slate-50 p-4 md:p-6 border-b flex flex-col md:flex-row justify-between gap-4">
              <div className="flex flex-wrap items-center gap-3">
                <div className="flex items-center gap-2"><Store size={18}/><span className="font-black text-rose-900 text-sm">{sale.marketName}</span></div>
                <div className="flex items-center gap-2"><CalendarIcon size={18}/><span className="font-bold text-slate-600 text-[11px]">{sale.date?.split('T')[0]}</span></div>
                <div className="flex items-center gap-2"><UserIcon size={18}/><span className="font-bold text-slate-600 text-[11px]">{sale.userName}</span></div>
              </div>
              {user.role === 'admin' && (
                <div className="flex gap-2">
                  <button onClick={() => { setSelectedSale(sale); setIsEditing(true); }} className="px-4 py-2 bg-blue-50 text-blue-600 rounded-xl font-black text-xs">تعديل</button>
                  <button onClick={() => handleDelete(sale.id)} className="px-4 py-2 bg-red-50 text-red-500 rounded-xl font-black text-xs">حذف</button>
                </div>
              )}
            </div>
            <div className="p-4 md:p-6 overflow-x-auto">
              <table className="w-full text-right text-[10px] md:text-xs">
                <thead className="text-gray-400 font-black"><tr><th className="p-3">الصنف</th><th className="p-3 text-center">السعر</th><th className="p-3 text-center">العدد</th><th className="p-3 text-center">الإجمالي</th></tr></thead>
                <tbody className="divide-y">{ (sale.items || []).map((item, idx) => (
                  <tr key={idx}><td className="p-3 font-bold">{item.productName}</td><td className="p-3 text-center">{(item.price || 0)}</td><td className="p-3 text-center">{item.quantity}</td><td className="p-3 text-center font-black">{( (item.price || 0) * (item.quantity || 0) ).toLocaleString()}</td></tr>
                ))}</tbody>
              </table>
            </div>
            <div className="bg-rose-900 p-4 md:p-6 text-white flex justify-between items-center">
              <Clock size={16} className="opacity-50" />
              <div className="flex items-center gap-3"><span className="text-xs opacity-60">الإجمالي:</span><span className="text-lg md:text-2xl font-black">{(sale.total || 0).toLocaleString()} ج.م</span></div>
            </div>
          </div>
        ))}
      </div>

      {selectedSale && isEditing && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-2xl overflow-hidden shadow-2xl">
            <div className="bg-rose-900 p-6 text-white flex justify-between items-center">
              <h3 className="text-lg font-black">تعديل سجل</h3>
              <button onClick={() => setIsEditing(false)}><X size={24}/></button>
            </div>
            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-3">
              {(selectedSale.items || []).map((item, idx) => (
                <div key={idx} className="grid grid-cols-4 gap-2 p-3 bg-slate-50 rounded-xl items-center text-[11px] font-bold">
                  <span className="text-gray-800">{item.productName}</span>
                  <input type="number" className="w-16 bg-white border p-1 rounded text-center" value={item.price} onChange={(e) => {
                    const newItems = [...(selectedSale.items || [])];
                    newItems[idx].price = Number(e.target.value);
                    setSelectedSale({...selectedSale, items: newItems});
                  }}/>
                  <input type="number" className="w-16 bg-white border p-1 rounded text-center" value={item.quantity} onChange={(e) => {
                    const newItems = [...(selectedSale.items || [])];
                    newItems[idx].quantity = Number(e.target.value);
                    setSelectedSale({...selectedSale, items: newItems});
                  }}/>
                  <span className="text-center text-rose-600">{( (item.price || 0) * (item.quantity || 0) ).toLocaleString()}</span>
                </div>
              ))}
            </div>
            <div className="p-6 bg-rose-50 flex justify-between items-center">
               <span className="text-xl font-black text-rose-900">{(selectedSale.items || []).reduce((acc, i) => acc + ( (i.price || 0) * (i.quantity || 0) ), 0).toLocaleString()} ج.م</span>
               <button onClick={async () => {
                 const newTotal = (selectedSale.items || []).reduce((acc, i) => acc + ( (i.price || 0) * (i.quantity || 0) ), 0);
                 await update(ref(db, `sales/${selectedSale.id}`), { items: selectedSale.items, total: newTotal });
                 setIsEditing(false);
               }} className="bg-rose-800 text-white px-8 py-3 rounded-xl font-black">حفظ التغييرات</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SalesHistory;

import React, { useState } from 'react';
import { User } from '../types';
import { db, ref, onValue } from '../firebase';
import { ShieldAlert, AlertCircle } from 'lucide-react';

interface Props {
  onLogin: (user: User) => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (username === 'admin' && password === 'admin') {
      onLogin({
        id: 'admin-id',
        username: 'admin',
        employeeName: 'مدير النظام',
        role: 'admin',
        employeeCode: '001',
        phone: '',
        isOnline: true,
        permissions: {
          registerSales: true,
          viewSalesHistory: true,
          registerInventory: true,
          viewInventoryHistory: true,
          registerCompetitorPrices: true,
          viewCompetitorReports: true,
          viewVacationMgmt: true,
          viewSettings: true,
          viewColleaguesSales: true
        },
        vacationBalance: { annual: 30, casual: 7, sick: 15, exams: 0 }
      });
      return;
    }

    try {
      const usersRef = ref(db, 'users');
      onValue(usersRef, (snapshot) => {
        const usersData = snapshot.val();
        if (usersData) {
          const entries = Object.entries(usersData);
          const foundEntry = entries.find(([id, u]: any) => u.username === username && u.password === password);

          if (foundEntry) {
            const [id, data]: [string, any] = foundEntry;
            const userWithId = { ...data, id: data.id || id };
            onLogin(userWithId as User);
          } else {
            setError('اسم المستخدم أو كلمة المرور غير صحيحة');
            setLoading(false);
          }
        } else {
          setError('قاعدة البيانات فارغة أو غير متصلة.');
          setLoading(false);
        }
      }, { onlyOnce: true });
    } catch (err) {
      setError('خطأ في الاتصال بالسيرفر.');
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#FFF0F3] flex items-center justify-center p-4">
      <div className="bg-white p-8 md:p-12 rounded-[2rem] shadow-2xl w-full max-w-lg border border-rose-100 relative overflow-hidden">
        <div className="relative z-10">
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center w-20 h-20 bg-rose-800 text-white rounded-3xl shadow-xl mb-6 transform rotate-3">
              <span className="text-3xl font-black">SR</span>
            </div>
            <h1 className="text-4xl font-black text-rose-900 mb-2 tracking-tighter">SOFT ROSE</h1>
            <p className="text-rose-400 font-medium uppercase text-xs tracking-[0.2em]">Modern Trade Management</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-xs font-bold mb-2 text-rose-900/40 uppercase tracking-widest mr-1">اسم المستخدم</label>
              <input className="w-full bg-slate-50 border-2 border-transparent focus:border-rose-200 rounded-2xl p-4 outline-none transition-all text-rose-900 font-bold" placeholder="ادخل اسم المستخدم" value={username} onChange={(e) => setUsername(e.target.value)} required />
            </div>
            <div>
              <label className="block text-xs font-bold mb-2 text-rose-900/40 uppercase tracking-widest mr-1">كلمة المرور</label>
              <input type="password" className="w-full bg-slate-50 border-2 border-transparent focus:border-rose-200 rounded-2xl p-4 outline-none transition-all text-rose-900 font-bold" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            {error && <div className="flex items-center gap-3 bg-red-50 text-red-600 p-4 rounded-2xl border border-red-100"><ShieldAlert size={20}/><p className="text-sm font-bold">{error}</p></div>}
            <button type="submit" disabled={loading} className="w-full bg-rose-800 text-white font-black py-5 rounded-2xl hover:bg-rose-900 shadow-xl disabled:opacity-50 flex items-center justify-center gap-3">
              {loading ? <div className="w-5 h-5 border-4 border-white/20 border-t-white rounded-full animate-spin"></div> : 'دخول النظام'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, MessageCircle, Calendar,
  Loader2, Wifi, WifiOff, Palette, Trophy
} from 'lucide-react';
import { db, ref, onValue, update, remove } from './firebase';
import { User, AppSettings, Notification, AppTheme, Market, Company, DailySale } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [sales, setSales] = useState<DailySale[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<AppTheme>('standard');
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    window.addEventListener('online', () => setIsOnline(true));
    window.addEventListener('offline', () => setIsOnline(false));

    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const usersList = Object.entries(data).map(([id, val]: any) => ({ ...val, id: val.id || id }));
        setUsers(usersList);
      }
    });

    onValue(ref(db, 'sales'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSales(Object.values(data));
      else setSales([]);
    });

    setIsLoading(false);
  }, []);

  const starOfMonthInfo = useMemo(() => {
    if (!sales || sales.length === 0) return null;
    const now = new Date();
    const currentMonthSales = sales.filter(s => {
      if (!s.date) return false;
      const d = new Date(s.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });

    const userTotals: Record<string, {name: string, total: number}> = {};
    currentMonthSales.forEach(s => {
      const uid = s.userId || 'unknown';
      if (!userTotals[uid]) userTotals[uid] = { name: s.userName || 'غير معروف', total: 0 };
      userTotals[uid].total += (Number(s.total) || 0);
    });

    const sorted = Object.values(userTotals).sort((a, b) => b.total - a.total);
    return sorted[0] || null;
  }, [sales]);

  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(m => user.role === 'admin' || m.creatorId === user.id || !m.creatorId);
          setMarkets(filtered);
        }
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.entries(data).map(([id, val]: any) => ({ id, ...val }));
          const filtered = list.filter(c => user.role === 'admin' || c.creatorId === user.id || !c.creatorId);
          setCompanies(filtered);
        }
      });
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      const notifRef = ref(db, 'notifications');
      onValue(notifRef, (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const allNotifs = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
          const myNotifs = allNotifs.filter(n => n.receiverId === 'all' || n.receiverId === user.id);
          setNotifications(myNotifs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
        } else {
          setNotifications([]);
        }
      });
    }
  }, [user]);

  const handleLogin = (loggedUser: User) => {
    // Ensuring safety defaults to fix the white screen issue
    const safeUser = {
      ...loggedUser,
      permissions: loggedUser.permissions || {
        registerSales: true,
        viewSalesHistory: true,
        registerInventory: true,
        viewInventoryHistory: true,
        registerCompetitorPrices: true,
        viewCompetitorReports: true,
        viewVacationMgmt: true,
        viewSettings: false,
        viewColleaguesSales: false
      },
      vacationBalance: loggedUser.vacationBalance || { annual: 14, casual: 7, sick: 0, exams: 0, absent_with_permission: 0, absent_without_permission: 0 }
    };
    setUser(safeUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user && user.id !== 'admin-id') {
      update(ref(db, `users/${user.id}`), { isOnline: false });
    }
    setUser(null);
  };

  const cycleTheme = () => {
    if (theme === 'standard') setTheme('glass');
    else if (theme === 'glass') setTheme('dark');
    else setTheme('standard');
  };

  const openWhatsApp = () => {
    if (settings?.whatsappNumber) {
      window.open(`https://wa.me/${settings.whatsappNumber}`, '_blank');
    } else {
      alert("رقم الواتساب غير مسجل في الإعدادات");
    }
  };

  if (isLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-rose-50">
      <Loader2 className="animate-spin text-rose-600 mb-4" size={48}/>
      <p className="text-rose-900 font-bold animate-pulse">جاري تحميل نظام Soft Rose...</p>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} />;

  const unreadCount = notifications.filter(n => !n.isRead).length;
  const up = user.permissions || {
    registerSales: true, viewSalesHistory: true, registerInventory: true, 
    viewInventoryHistory: true, registerCompetitorPrices: true, 
    viewCompetitorReports: true, viewVacationMgmt: true, viewSettings: false, viewColleaguesSales: false
  };

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: user.role === 'admin' || up.registerSales },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: user.role === 'admin' || up.viewSalesHistory },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: user.role === 'admin' || up.registerInventory },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: user.role === 'admin' || up.viewInventoryHistory },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: user.role === 'admin' || up.registerCompetitorPrices },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: user.role === 'admin' || up.viewCompetitorReports },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: user.role === 'admin' || up.viewVacationMgmt },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user.role === 'admin' || up.viewSettings },
  ].filter(i => i.visible);

  const constructedTickerText = useMemo(() => {
    let text = settings?.tickerText || '';
    if (settings?.showTopSalesInTicker && starOfMonthInfo) {
      const topSalesMsg = `🏆 نجم الشهر الحالي: ${starOfMonthInfo.name} بمبيعات إجمالية ${(starOfMonthInfo.total || 0).toLocaleString()} ج.م 🏆`;
      text = topSalesMsg + (text ? ` | ${text}` : '');
    }
    return text;
  }, [settings, starOfMonthInfo]);

  return (
    <div className={`flex h-screen overflow-hidden theme-${theme} transition-all duration-300 relative`}>
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/60 z-40 md:hidden backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}/>
      )}

      <aside className={`bg-rose-900 text-white w-72 flex-shrink-0 transition-all duration-300 z-50 fixed md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:right-0'} shadow-2xl`}>
        <div className="p-6 flex flex-col h-full">
          <div className="mb-8 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-widest text-rose-300">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 hover:bg-white/10 rounded-full"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-1.5 overflow-y-auto custom-scrollbar">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl transition-all duration-200 ${activeTab === item.id ? 'bg-white text-rose-900 font-bold shadow-xl' : 'hover:bg-white/10 opacity-80'}`}
              >
                <span className={activeTab === item.id ? 'text-rose-600' : 'text-white'}>{item.icon}</span>
                <span className="text-sm font-bold">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 overflow-hidden bg-[#F9FAFB]">
        {constructedTickerText && (
          <div className="bg-rose-950 py-2 text-white text-[11px] md:text-[13px] overflow-hidden border-b border-rose-900/50 shadow-inner z-50">
            <div className="ticker-container">
              <div className="ticker-text font-bold opacity-90" style={{ animationDuration: '45s' }}>
                {constructedTickerText} &nbsp;&nbsp; ★ &nbsp;&nbsp; {constructedTickerText}
              </div>
            </div>
          </div>
        )}

        <header className="h-16 md:h-20 flex items-center justify-between px-3 md:px-8 bg-white shadow-sm z-30">
          <div className="flex items-center gap-2 md:gap-4 flex-1">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 hover:bg-rose-50 rounded-xl transition-all">
              <Menu size={20} className="text-rose-800" />
            </button>
            <div className="flex flex-col">
              <h2 className="font-black text-rose-900 text-sm md:text-xl truncate">
                {settings?.programName || 'Soft Rose Modern Trade'}
              </h2>
              <span className="text-[9px] md:text-[10px] font-bold text-gray-400 uppercase tracking-widest truncate">
                {user.employeeName}
              </span>
            </div>
          </div>

          <div className="flex items-center gap-1 md:gap-2">
            <div className="flex items-center bg-slate-100/70 p-1 rounded-xl gap-1 shadow-inner">
              <button onClick={openWhatsApp} className="p-2 md:p-3 text-green-600 hover:bg-white rounded-lg transition-all"><MessageCircle size={18} /></button>
              <button onClick={cycleTheme} className="p-2 md:p-3 text-amber-500 hover:bg-white rounded-lg transition-all"><Palette size={18} /></button>
              <div className={`p-2 md:p-3 rounded-lg ${isOnline ? 'text-blue-600' : 'text-red-500'}`}>{isOnline ? <Wifi size={18} /> : <WifiOff size={18} />}</div>
              <button onClick={() => setIsNotificationOpen(true)} className="relative p-2 md:p-3 text-gray-500 hover:bg-white rounded-lg transition-all">
                <Bell size={18} />
                {unreadCount > 0 && <span className="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-red-600 border-2 border-white rounded-full"></span>}
              </button>
            </div>
            <button onClick={handleLogout} className="p-2 md:p-3 bg-rose-50 text-rose-800 rounded-xl hover:bg-rose-100 transition-all font-bold text-[11px] md:text-sm border border-rose-100 ml-1">
              <LogOut size={18} className="md:hidden" />
              <span className="hidden md:inline">خروج</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-3 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto">
            {activeTab === 'daily-sales' && <DailySales user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets.map(m => m.name)} users={users} />}
            {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets.map(m => m.name)} />}
            {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} />}
            {activeTab === 'settings' && <Settings user={user} settings={settings} users={users} markets={markets} companies={companies} />}
          </div>
        </div>
      </main>

      {isNotificationOpen && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-[100] flex items-center justify-center p-4" onClick={() => setIsNotificationOpen(false)}>
          <div className="bg-white rounded-[2rem] w-full max-w-lg overflow-hidden shadow-2xl animate-in slide-in-from-bottom-10" onClick={e => e.stopPropagation()}>
            <div className="bg-rose-900 p-6 text-white flex justify-between items-center">
              <h3 className="text-xl font-black">صندوق الرسائل</h3>
              <button onClick={() => setIsNotificationOpen(false)} className="p-2 hover:bg-white/10 rounded-full"><X size={24}/></button>
            </div>
            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-4 bg-slate-50">
              {notifications.length === 0 ? (
                <div className="text-center py-12 text-gray-300 font-bold">لا توجد رسائل جديدة</div>
              ) : (
                notifications.map(n => (
                  <div key={n.id} className="p-5 bg-white rounded-2xl border border-rose-100 shadow-sm">
                    <p className="text-sm font-bold text-gray-800 mb-2">{n.message}</p>
                    <div className="flex justify-between items-center text-[10px] text-rose-300 font-bold uppercase">
                      <span>{new Date(n.timestamp).toLocaleString('ar-EG')}</span>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

