import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, Calendar,
  Loader2, Sparkles
} from 'lucide-react';
import { db, ref, onValue, update } from './firebase';
import { User, AppSettings, Notification, AppTheme, Market, Company, DailySale, InventoryRecord, Vacation } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';
import AIChatbot from './views/AIChatbot';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [sales, setSales] = useState<DailySale[]>([]);
  const [inventory, setInventory] = useState<InventoryRecord[]>([]);
  const [vacations, setVacations] = useState<Vacation[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<AppTheme>('standard');
  const [isAIChatOpen, setIsAIChatOpen] = useState(false);

  useEffect(() => {
    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const usersList = Object.entries(data).map(([id, val]: any) => ({ ...val, id: val.id || id }));
        setUsers(usersList);
      }
    });

    onValue(ref(db, 'sales'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSales(Object.values(data));
    });

    onValue(ref(db, 'inventory'), (snapshot) => {
      const data = snapshot.val();
      if (data) setInventory(Object.values(data));
    });

    onValue(ref(db, 'vacations'), (snapshot) => {
      const data = snapshot.val();
      if (data) setVacations(Object.values(data));
    });

    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) setMarkets(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) setCompanies(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
      onValue(ref(db, 'notifications'), (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const allNotifs = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
          setNotifications(allNotifs.filter(n => n.receiverId === 'all' || n.receiverId === user.id));
        }
      });
    }
  }, [user]);

  const starOfMonthInfo = useMemo(() => {
    if (!sales || sales.length === 0) return null;
    const now = new Date();
    const currentMonthSales = sales.filter(s => {
      const d = new Date(s.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });
    const userTotals: Record<string, {name: string, total: number}> = {};
    currentMonthSales.forEach(s => {
      if (!userTotals[s.userId]) userTotals[s.userId] = { name: s.userName, total: 0 };
      userTotals[s.userId].total += (Number(s.total) || 0);
    });
    return Object.values(userTotals).sort((a, b) => b.total - a.total)[0] || null;
  }, [sales]);

  const tickerText = useMemo(() => {
    let text = settings?.tickerText || '';
    if (settings?.showTopSalesInTicker && starOfMonthInfo) {
      text = `🏆 نجم الشهر: ${starOfMonthInfo.name} بمبيعات ${starOfMonthInfo.total.toLocaleString()} ج.م 🏆 | ` + text;
    }
    return text;
  }, [settings, starOfMonthInfo]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user) update(ref(db, `users/${user.id}`), { isOnline: false });
    setUser(null);
  };

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={22}/>, visible: true },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={22}/>, visible: true },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={22}/>, visible: true },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={22}/>, visible: true },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={22}/>, visible: true },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={22}/>, visible: true },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={22}/>, visible: true },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={22}/>, visible: user?.role === 'admin' },
  ].filter(i => i.visible);

  if (isLoading) return <div className="h-screen flex items-center justify-center bg-transparent"><Loader2 className="animate-spin text-rose-900" size={48}/></div>;
  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className={`flex h-screen overflow-hidden theme-${theme} transition-all duration-300 relative bg-transparent`}>
      {/* Sidebar overlay for mobile */}
      {isSidebarOpen && <div className="fixed inset-0 bg-rose-950/20 z-[60] md:hidden backdrop-blur-md transition-all" onClick={() => setIsSidebarOpen(false)}/>}

      {/* Transparent Glass Sidebar */}
      <aside className={`glass-sidebar text-white w-72 flex-shrink-0 transition-all duration-500 z-[70] fixed md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:right-0'} shadow-2xl`}>
        <div className="p-8 flex flex-col h-full">
          <div className="mb-12 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[11px] uppercase font-black tracking-[0.3em] text-rose-100 opacity-80">SOFT ROSE</span>
              <h1 className="text-2xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 hover:bg-white/20 rounded-xl transition-all"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-3 overflow-y-auto custom-scrollbar pr-1">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-5 px-6 py-4 rounded-2xl transition-all duration-300 relative group ${activeTab === item.id ? 'bg-white text-rose-950 font-black shadow-xl scale-[1.02]' : 'hover:bg-white/10 text-white/90 font-bold'}`}
              >
                <span className={`${activeTab === item.id ? 'text-rose-700' : 'text-rose-100/70 group-hover:text-white'}`}>{item.icon}</span>
                <span className="text-sm tracking-tight">{item.label}</span>
                {activeTab === item.id && <div className="absolute left-3 w-1.5 h-6 bg-rose-700 rounded-full animate-pulse"></div>}
              </button>
            ))}
          </nav>

          <div className="mt-8 pt-8 border-t border-white/10">
             <button onClick={handleLogout} className="w-full flex items-center gap-5 px-6 py-4 rounded-2xl text-rose-100 hover:bg-rose-500/30 transition-all font-black text-sm">
                <LogOut size={22} className="opacity-70" />
                <span>تسجيل الخروج</span>
             </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-0 overflow-hidden relative">
        {tickerText && (
          <div className="bg-rose-950/80 backdrop-blur-md py-2.5 text-white text-[11px] font-black overflow-hidden z-[50] border-b border-white/10">
            <div className="ticker-container">
              <div className="ticker-text opacity-90 tracking-wide">
                {tickerText} &nbsp;&nbsp; • &nbsp;&nbsp; {tickerText}
              </div>
            </div>
          </div>
        )}

        <header className="h-20 flex items-center justify-between px-8 bg-white/30 backdrop-blur-xl border-b border-white/20 z-[40] shadow-sm">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2.5 bg-rose-900/10 text-rose-950 rounded-xl hover:bg-rose-900/20 transition-all"><Menu size={22} /></button>
            <h2 className="font-black text-rose-950 text-xl tracking-tighter">
              {settings?.programName || 'Soft Rose Modern Trade'}
            </h2>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex flex-col items-end">
                <span className="text-rose-950 font-black text-sm leading-none">{user.employeeName}</span>
                <span className="text-[9px] font-bold text-rose-800/50 uppercase tracking-widest mt-1">{user.role}</span>
             </div>
             <div className="w-12 h-12 bg-rose-900 text-white rounded-2xl flex items-center justify-center font-black shadow-lg shadow-rose-900/20">
                {user.employeeName.charAt(0)}
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar bg-transparent">
          <div className="max-w-7xl mx-auto h-full">
            <div className="glass-card rounded-[2.5rem] p-6 md:p-10 min-h-full">
              {activeTab === 'daily-sales' && <DailySales user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets.map(m => m.name)} users={users} />}
              {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets.map(m => m.name)} users={users} />}
              {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} />}
              {activeTab === 'settings' && <Settings user={user} settings={settings} users={users} markets={markets} companies={companies} />}
            </div>
          </div>
        </div>

        {/* Floating AI - Glass Style */}
        <div className="fixed bottom-8 left-8 z-[1000] flex flex-col items-end gap-5 pointer-events-none">
          {isAIChatOpen && (
            <div className="w-[90vw] md:w-[400px] h-[550px] pointer-events-auto animate-in slide-in-from-bottom-10 fade-in duration-500 shadow-2xl">
              <AIChatbot 
                user={user} 
                onClose={() => setIsAIChatOpen(false)}
