          )}
          <button 
            onClick={() => setIsAIChatOpen(!isAIChatOpen)}
            className={`w-16 h-16 rounded-[1.8rem] bg-rose-900 text-white flex items-center justify-center shadow-2xl pointer-events-auto transition-all duration-500 hover:scale-110 active:scale-95 group ${isAIChatOpen ? 'rotate-90 bg-rose-950 scale-90' : 'animate-bounce'}`}
          >
            {isAIChatOpen ? <X size={28}/> : (
              <div className="relative">
                <Sparkles size={32} className="text-amber-300 group-hover:animate-spin" />
                <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-rose-900 animate-ping"></div>
              </div>
            )}
          </button>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { User, DailySale, InventoryRecord, Vacation, Market, AppSettings } from '../types';
import { Send, Bot, User as UserIcon, Loader2, Sparkles, MessageSquare, Trash2, X } from 'lucide-react';

interface Props {
  user: User;
  onClose: () => void;
  appData: {
    sales: DailySale[];
    inventory: InventoryRecord[];
    vacations: Vacation[];
    users: User[];
    markets: Market[];
    settings: AppSettings | null;
  };
}

interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

const AIChatbot: React.FC<Props> = ({ user, appData, onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const generateDataSummary = () => {
    const totalSales = appData.sales.reduce((acc, s) => acc + (Number(s.total) || 0), 0);
    const userPerformance: Record<string, number> = {};
    appData.sales.forEach(s => {
      const name = s.userName || 'غير معروف';
      userPerformance[name] = (userPerformance[name] || 0) + Number(s.total || 0);
    });
    const sortedPerformers = Object.entries(userPerformance).sort((a, b) => b[1] - a[1]);
    const topPerformer = sortedPerformers[0] ? `${sortedPerformers[0][0]} بمبيعات ${sortedPerformers[0][1].toLocaleString()}` : 'لا يوجد مبيعات';

    return `
      ملخص بيانات Soft Rose:
      - اسم البرنامج: ${appData.settings?.programName || 'Soft Rose'}
      - الموظفين: ${appData.users.length}
      - الماركتات: ${appData.markets.length}
      - إجمالي المبيعات: ${totalSales.toLocaleString()} ج.م
      - المتصدر: ${topPerformer}
    `;
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const systemInstruction = `
        أنت المساعد الذكي الرسمي "روزي" لنظام Soft Rose. 
        تحدث بالعربية باختصار واحترافية.
        البيانات المتاحة: ${generateDataSummary()}
        المستخدم الحالي: ${user.employeeName}.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })),
          { role: 'user', parts: [{ text: userMessage }] }
        ],
        config: { systemInstruction, temperature: 0.7 },
      });

      setMessages(prev => [...prev, { role: 'model', text: response.text || "لا يمكنني الرد الآن." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "خطأ في الاتصال بالذكاء الاصطناعي." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white/40 backdrop-blur-3xl rounded-[3rem] shadow-2xl border border-white/40 overflow-hidden" dir="rtl">
      {/* Header */}
      <div className="bg-rose-900/80 backdrop-blur-md p-5 text-white flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md">
            <Sparkles className="text-amber-300" size={20}/>
          </div>
          <div>
            <h3 className="text-sm font-black">المساعدة روزي</h3>
            <p className="text-[9px] font-bold text-rose-200 uppercase tracking-widest">Soft Rose AI Assistant</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setMessages([])} className="p-2.5 hover:bg-white/10 rounded-xl transition-all"><Trash2 size={16}/></button>
          <button onClick={onClose} className="p-2.5 hover:bg-white/10 rounded-xl transition-all"><X size={16}/></button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-5 space-y-5 bg-transparent custom-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center opacity-40">
            <div className="p-8 bg-rose-900/10 rounded-[2.5rem] mb-5">
              <MessageSquare size={54} className="text-rose-900" />
            </div>
            <p className="text-sm font-black text-rose-950 px-10 leading-relaxed">أهلاً بك في نظام روزي الذكي. أنا جاهزة لتحليل مبيعاتك وأرصدة الماركت.</p>
          </div>
        )}

        {messages.map((m, idx) => (
          <div key={idx} className={`flex ${m.role === 'user' ? 'justify-start' : 'justify-end'}`}>
            <div className={`flex gap-3 max-w-[88%] ${m.role === 'user' ? 'flex-row' : 'flex-row-reverse'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0 shadow-lg ${m.role === 'user' ? 'bg-rose-900 text-white' : 'bg-white/80 text-rose-900 backdrop-blur-md border border-white/50'}`}>
                {m.role === 'user' ? <UserIcon size={16}/> : <Bot size={16}/>}
              </div>
              <div className={`p-4 rounded-[1.5rem] font-bold text-xs leading-relaxed shadow-sm ${m.role === 'user' ? 'bg-rose-900 text-white rounded-tr-none' : 'bg-white/90 text-gray-800 rounded-tl-none border border-white/50 shadow-rose-900/5'}`}>
                {m.text}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-end">
            <div className="bg-white/60 backdrop-blur-md p-4 rounded-2xl border border-white/50 shadow-sm flex items-center gap-3">
              <Loader2 className="animate-spin text-rose-900" size={16}/>
              <span className="text-[10px] font-black text-rose-900/60 uppercase tracking-widest">تحليل البيانات...</span>
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </div>

      {/* Input */}
      <div className="p-5 bg-white/20 backdrop-blur-xl border-t border-white/20">
        <div className="relative">
          <input 
            className="w-full bg-white/60 backdrop-blur-md rounded-2xl py-5 px-14 pr-6 outline-none font-black text-xs text-rose-950 border border-white/50 focus:bg-white/95 transition-all shadow-inner placeholder-rose-900/30"
            placeholder="اسألني عن أي شيء في النظام..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className="absolute left-3 top-1/2 -translate-y-1/2 p-3 bg-rose-900 text-white rounded-[1rem] hover:bg-rose-950 disabled:opacity-30 transition-all shadow-lg shadow-rose-900/20 active:scale-90"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChatbot;

import React, { useState } from 'react';
import { User } from '../types';
import { db, ref, onValue } from '../firebase';
import { ShieldAlert, User as UserIcon, Lock, Sparkles, ChevronLeft, ArrowLeft } from 'lucide-react';

interface Props {
  onLogin: (user: User) => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (username === 'admin' && password === 'admin') {
      onLogin({
        id: 'admin-id',
        username: 'admin',
        employeeName: 'مدير النظام',
        role: 'admin',
        employeeCode: '001',
        phone: '',
        isOnline: true,
        permissions: {
          registerSales: true,
          viewSalesHistory: true,
          registerInventory: true,
          viewInventoryHistory: true,
          registerCompetitorPrices: true,
          viewCompetitorReports: true,
          viewVacationMgmt: true,
          viewSettings: true,
          viewColleaguesSales: true
        },
        vacationBalance: { annual: 30, casual: 7, sick: 15, exams: 0 }
      });
      return;
    }

    try {
      const usersRef = ref(db, 'users');
      onValue(usersRef, (snapshot) => {
        const usersData = snapshot.val();
        if (usersData) {
          const entries = Object.entries(usersData);
          const foundEntry = entries.find(([id, u]: any) => u.username === username && u.password === password);

          if (foundEntry) {
            const [id, data]: [string, any] = foundEntry;
            const userWithId = { ...data, id: data.id || id };
            onLogin(userWithId as User);
          } else {
            setError('خطأ في بيانات الدخول');
            setLoading(false);
          }
        } else {
          setError('السيرفر غير مستجيب');
          setLoading(false);
        }
      }, { onlyOnce: true });
    } catch (err) {
      setError('خطأ في الاتصال');
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="glass-login w-full max-w-md rounded-[2.5rem] p-8 md:p-12 relative overflow-hidden group">

        {/* Decorative Inner Glows */}
        <div className="absolute -top-24 -left-24 w-48 h-48 bg-rose-500/10 rounded-full blur-3xl group-hover:bg-rose-500/20 transition-all duration-700"></div>
        <div className="absolute -bottom-24 -right-24 w-48 h-48 bg-purple-500/10 rounded-full blur-3xl group-hover:bg-purple-500/20 transition-all duration-700"></div>

        <div className="relative z-10">
          {/* Logo Section */}
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center w-20 h-20 bg-gradient-to-tr from-rose-900 to-rose-600 rounded-3xl shadow-2xl mb-6 transform hover:scale-110 transition-transform duration-500">
              <Sparkles className="w-10 h-10 text-white animate-pulse" />
            </div>
            <h1 className="text-3xl font-black text-white mb-2 tracking-tight">SOFT ROSE</h1>
            <div className="flex items-center justify-center gap-2">
              <div className="h-[1px] w-8 bg-rose-500/30"></div>
              <p className="text-rose-400 font-bold uppercase text-[9px] tracking-[0.3em]">Modern Trade Portal</p>
              <div className="h-[1px] w-8 bg-rose-500/30"></div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Username Input */}
            <div className="input-glow-wrapper">
              <div className="flex items-center bg-white/5 border border-white/10 rounded-2xl px-4 group-focus-within:bg-white/10 transition-all">
                <UserIcon className="text-rose-400 group-focus-within:text-rose-300" size={18} />
                <input 
                  className="w-full bg-transparent p-4 outline-none font-bold text-white placeholder-white/20 text-sm" 
                  placeholder="اسم المستخدم" 
                  value={username} 
                  onChange={(e) => setUsername(e.target.value)} 
                  required 
                />
              </div>
            </div>

            {/* Password Input */}
            <div className="input-glow-wrapper">
              <div className="flex items-center bg-white/5 border border-white/10 rounded-2xl px-4 group-focus-within:bg-white/10 transition-all">
                <Lock className="text-rose-400 group-focus-within:text-rose-300" size={18} />
                <input 
                  type="password" 
                  className="w-full bg-transparent p-4 outline-none font-bold text-white placeholder-white/20 text-sm" 
                  placeholder="كلمة المرور" 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)} 
                  required 
                />
              </div>
            </div>

            {error && (
              <div className="flex items-center gap-3 bg-red-500/10 text-red-400 p-4 rounded-2xl border border-red-500/20 backdrop-blur-md animate-in slide-in-from-top-2">
                <ShieldAlert size={18}/>
                <p className="text-[11px] font-black">{error}</p>
              </div>
            )}

            <button 
              type="submit" 
              disabled={loading} 
              className="w-full bg-rose-700 hover:bg-rose-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-rose-950/50 disabled:opacity-50 flex items-center justify-center gap-3 transition-all duration-300 active:scale-[0.98] group/btn"
            >
              {loading ? (
                <div className="w-6 h-6 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>
                  <span className="tracking-wide">الدخول الآمن</span>
                  <ArrowLeft size={18} className="group-hover/btn:-translate-x-1 transition-transform" />
                </>
              )}
            </button>
          </form>

          {/* Footer Info */}
          <div className="mt-12 text-center opacity-30">
             <p className="text-[9px] font-black text-white uppercase tracking-[0.4em]">Integrated Management System v2.0</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

