              <label className="text-[10px] font-black text-white/30 uppercase tracking-widest mr-2">رقم الواتساب</label>
              <input className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10" value={whatsapp} onChange={e => setWhatsapp(e.target.value)}/>
