              <input type="password" className="w-full glass-input-dark p-4 rounded-xl font-bold border border-white/10 outline-none" placeholder="كلمة المرور" value={editingCredentials.password} onChange={e => setEditingCredentials({...editingCredentials, password: e.target.value})}/>
