import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, Calendar,
  Loader2, Sparkles, ChevronRight
} from 'lucide-react';
import { db, ref, onValue, update } from './firebase';
import { User, AppSettings, Notification, AppTheme, Market, Company, DailySale, InventoryRecord, Vacation } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';
import AIChatbot from './views/AIChatbot';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [sales, setSales] = useState<DailySale[]>([]);
  const [inventory, setInventory] = useState<InventoryRecord[]>([]);
  const [vacations, setVacations] = useState<Vacation[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isAIChatOpen, setIsAIChatOpen] = useState(false);

  // Monthly Reset Logic for "Absent without Permission"
  useEffect(() => {
    if (user?.role === 'admin' && users.length > 0) {
      const currentMonth = new Date().getMonth();
      const lastResetMonth = localStorage.getItem('lastResetMonth');

      if (lastResetMonth === null || parseInt(lastResetMonth) !== currentMonth) {
        users.forEach(u => {
          if (u.id && u.vacationBalance) {
            update(ref(db, `users/${u.id}/vacationBalance`), {
              absent_without_permission: 0
            });
          }
        });
        localStorage.setItem('lastResetMonth', currentMonth.toString());
      }
    }
  }, [user, users]);

  useEffect(() => {
    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const usersList = Object.entries(data).map(([id, val]: any) => ({ ...val, id: val.id || id }));
        setUsers(usersList);
      }
    });

    onValue(ref(db, 'sales'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSales(Object.values(data));
    });

    onValue(ref(db, 'inventory'), (snapshot) => {
      const data = snapshot.val();
      if (data) setInventory(Object.values(data));
    });

    onValue(ref(db, 'vacations'), (snapshot) => {
      const data = snapshot.val();
      if (data) setVacations(Object.values(data));
    });

    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) setMarkets(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) setCompanies(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
    }
  }, [user]);

  const starOfMonthInfo = useMemo(() => {
    if (!sales || sales.length === 0) return null;
    const now = new Date();
    const currentMonthSales = sales.filter(s => {
      const d = new Date(s.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });
    const userTotals: Record<string, {name: string, total: number}> = {};
    currentMonthSales.forEach(s => {
      if (!userTotals[s.userId]) userTotals[s.userId] = { name: s.userName, total: 0 };
      userTotals[s.userId].total += (Number(s.total) || 0);
    });
    return Object.values(userTotals).sort((a, b) => b.total - a.total)[0] || null;
  }, [sales]);

  const tickerText = useMemo(() => {
    let text = settings?.tickerText || '';
    if (settings?.showTopSalesInTicker && starOfMonthInfo) {
      text = `🏆 نجم الشهر: ${starOfMonthInfo.name} بمبيعات ${starOfMonthInfo.total.toLocaleString()} ج.م 🏆 | ` + text;
    }
    return text;
  }, [settings, starOfMonthInfo]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user) update(ref(db, `users/${user.id}`), { isOnline: false });
    setUser(null);
  };

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: true },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: true },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: true },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: true },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: true },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: true },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: true },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user?.role === 'admin' },
  ].filter(i => i.visible);

  if (isLoading) return <div className="h-screen flex items-center justify-center bg-transparent"><Loader2 className="animate-spin text-rose-50" size={48}/></div>;
  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="flex h-screen overflow-hidden relative bg-transparent text-white">
      {/* Sidebar Overlay - Closes when clicking anywhere outside on mobile or desktop */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-[60] backdrop-blur-md transition-all duration-300" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Glass Sidebar */}
      <aside className={`glass-sidebar-inner text-white w-72 flex-shrink-0 transition-all duration-500 z-[70] fixed md:absolute md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:-right-72'} shadow-2xl`}>
        <div className="p-8 flex flex-col h-full">
          <div className="mb-12 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-[0.4em] text-rose-500">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="p-2 hover:bg-white/10 rounded-xl transition-all"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-2 overflow-y-auto custom-scrollbar">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all duration-300 relative group ${activeTab === item.id ? 'bg-rose-600/20 text-white font-black active-glow' : 'hover:bg-white/5 text-white/60 font-medium'}`}
              >
                <span className={`${activeTab === item.id ? 'text-rose-400' : 'group-hover:text-white'}`}>{item.icon}</span>
                <span className="text-sm">{item.label}</span>
                {activeTab === item.id && <div className="absolute left-3 w-1.5 h-6 bg-rose-500 rounded-full"></div>}
              </button>
            ))}
          </nav>

          <div className="mt-8 pt-8 border-t border-white/5">
             <button onClick={handleLogout} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-rose-400 hover:bg-rose-500/10 transition-all font-black text-sm">
                <LogOut size={20} />
                <span>تسجيل الخروج</span>
             </button>
          </div>
        </div>
      </aside>

      {/* Main Content Area - Clicking here also closes sidebar if open */}
      <main 
        className="flex-1 flex flex-col min-w-0 overflow-hidden"
        onClick={() => isSidebarOpen && setIsSidebarOpen(false)}
      >
        {tickerText && (
          <div className="bg-rose-950/40 backdrop-blur-md py-2.5 text-rose-100 text-[11px] font-black overflow-hidden z-[50] border-b border-white/5">
            <div className="ticker-container">
              <div className="ticker-text opacity-90 tracking-wide">
                {tickerText} &nbsp;&nbsp; • &nbsp;&nbsp; {tickerText}
              </div>
            </div>
          </div>
        )}

        <header className="h-20 flex items-center justify-between px-8 glass-header-inner z-[40]">
          <div className="flex items-center gap-4">
            <button 
              onClick={(e) => { e.stopPropagation(); setIsSidebarOpen(!isSidebarOpen); }} 
              className="p-2.5 bg-white/5 text-white rounded-xl hover:bg-white/10 transition-all active:scale-95"
            >
              <Menu size={22} />
            </button>
            <h2 className="font-black text-white text-lg tracking-tight">
              {settings?.programName || 'Soft Rose Modern Trade'}
            </h2>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex flex-col items-end">
                <span className="text-white font-black text-sm">{user.employeeName}</span>
                <span className="text-[9px] font-bold text-rose-500/60 uppercase tracking-widest">{user.role}</span>
             </div>
             <div className="w-11 h-11 bg-rose-700/80 text-white rounded-2xl flex items-center justify-center font-black shadow-xl shadow-rose-900/20 border border-white/10">
                {user.employeeName.charAt(0)}
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto h-full">
            <div className="glass-card-dark rounded-[2.5rem] p-6 md:p-10 min-h-full">
              {activeTab === 'daily-sales' && <DailySales user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets.map(m => m.name)} users={users} />}
              {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets.map(m => m.name)} users={users} />}
              {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} />}
              {activeTab === 'settings' && <Settings user={user} settings={settings} users={users} markets={markets} companies={companies} />}
            </div>
          </div>
        </div>

        {/* Floating AI - Glass Style */}
        <div className="fixed bottom-8 left-8 z-[1000] flex flex-col items-end gap-5 pointer-events-none">
          {isAIChatOpen && (
            <div className="w-[90vw] md:w-[420px] h-[600px] pointer-events-auto animate-in slide-in-from-bottom-10 fade-in duration-500 shadow-2xl">
              <AIChatbot 
                user={user} 
                onClose={() => setIsAIChatOpen(false)}
                appData={{ sales, inventory, vacations, users, markets, settings }}
              />
            </div>
          )}
          <button 
            onClick={(e) => { e.stopPropagation(); setIsAIChatOpen(!isAIChatOpen); }}
            className={`w-14 h-14 rounded-2xl bg-rose-600 text-white flex items-center justify-center shadow-2xl pointer-events-auto transition-all duration-500 hover:scale-110 group ${isAIChatOpen ? 'rotate-90 bg-slate-900' : 'animate-bounce active-glow'}`}
          >
            {isAIChatOpen ? <X size={24}/> : <Sparkles size={28} className="text-amber-300" />}
          </button>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, SaleItem, DailySale } from '../types';
import { PRODUCT_GROUPS } from '../constants';
import { Plus, Trash2, Save, ShoppingBag, PlusCircle, Sparkles } from 'lucide-react';
import { db, ref, push } from '../firebase';

interface Props {
  user: User;
  markets: string[];
}

const DailySales: React.FC<Props> = ({ user, markets }) => {
  const [selectedMarket, setSelectedMarket] = useState('');
  const [items, setItems] = useState<SaleItem[]>([]);
  const [isAddMarketModalOpen, setIsAddMarketModalOpen] = useState(false);
  const [newMarketName, setNewMarketName] = useState('');

  // Fixed products logic: they appear when market is selected
  useEffect(() => {
    if (selectedMarket) {
      const allItems: SaleItem[] = [];
      Object.entries(PRODUCT_GROUPS).forEach(([cat, products]) => {
        products.forEach(p => {
          allItems.push({
            id: `${cat}-${p}-${Date.now()}-${Math.random()}`,
            category: cat,
            productName: p,
            price: 0,
            quantity: 0
          });
        });
      });
      setItems(allItems);
    } else {
      setItems([]); // Clear screen when no market is selected
    }
  }, [selectedMarket]);

  const updateItem = (id: string, field: keyof SaleItem, value: any) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const addItemManual = (category: string) => {
    const newItem: SaleItem = {
      id: `manual-${category}-${Date.now()}-${Math.random()}`,
      category,
      productName: '',
      price: 0,
      quantity: 0
    };
    setItems([...items, newItem]);
  };

  const calculateTotal = () => {
    return items.reduce((sum, item) => sum + (Number(item.price || 0) * Number(item.quantity || 0)), 0);
  };

  const handleSave = async () => {
    if (!selectedMarket) {
      alert("يرجى اختيار الماركت أولاً");
      return;
    }
    const finalItems = items.filter(i => i.quantity > 0 && i.productName && i.productName.trim() !== '');
    if (finalItems.length === 0) {
      alert("يرجى إدخال كمية لمنتج واحد على الأقل");
      return;
    }

    const sale: Partial<DailySale> = {
      userId: user.id,
      userName: user.employeeName,
      marketName: selectedMarket,
      date: new Date().toISOString(),
      items: finalItems,
      total: calculateTotal()
    };

    try {
      await push(ref(db, 'sales'), sale);
      alert("تم الحفظ والترحيل بنجاح");

      // Full screen reset after success
      setSelectedMarket(''); 
      setItems([]);
    } catch (e) {
      alert("خطأ في الاتصال بالشبكة");
    }
  };

  const getCategoryLabel = (cat: string) => {
    const labels: Record<string, string> = {
      facial: 'مناديل سحب (Facial)',
      kitchen: 'مناديل مطبخ (Kitchen)',
      hotel_toilet: 'تواليت فنادق (Hotel Toilet)',
      dolphin: 'دولفن (Dolphin)'
    };
    return labels[cat] || cat;
  };

  return (
    <div className="max-w-7xl mx-auto pb-20">
      <div className="space-y-8">
        {/* Total Summary Header */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 p-8 md:p-12 rounded-[2.5rem] bg-gradient-to-br from-rose-900/60 to-rose-700/20 backdrop-blur-3xl border border-white/10 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-rose-500/20 blur-[80px]"></div>
          <div className="flex items-center gap-5 relative z-10">
            <div className="p-4 bg-white/5 rounded-3xl border border-white/10">
              <ShoppingBag className="w-8 h-8 text-rose-400" />
            </div>
            <div>
              <h2 className="text-xl md:text-3xl font-black text-white">إجمالي المبيعات</h2>
              <p className="text-[10px] font-bold text-rose-300 uppercase tracking-widest mt-1 opacity-60">Daily Performance Tracking</p>
            </div>
          </div>
          <div className="text-4xl md:text-7xl font-black tracking-tighter text-white relative z-10">
            {calculateTotal().toLocaleString()} <span className="text-sm md:text-xl opacity-40">ج.م</span>
          </div>
        </div>

        {/* Branch Selection */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 p-6 bg-white/5 rounded-[2rem] border border-white/5 backdrop-blur-xl">
          <div className="md:col-span-3">
            <label className="block text-[10px] font-black text-rose-400 uppercase tracking-widest mb-3 mr-2">اختيار الماركت الحالي</label>
            <select 
              className="w-full bg-white/5 border border-white/10 focus:border-rose-500/50 rounded-2xl p-4 outline-none font-bold text-white shadow-inner transition-all appearance-none"
              value={selectedMarket}
              onChange={(e) => setSelectedMarket(e.target.value)}
            >
              <option value="" className="bg-slate-900">-- اضغط لاختيار الماركت --</option>
              {markets && markets.map(m => <option key={m} value={m} className="bg-slate-900">{m}</option>)}
            </select>
          </div>
          <button 
            onClick={() => setIsAddMarketModalOpen(true)}
            className="self-end p-4 bg-rose-600/20 text-rose-400 border border-rose-500/30 rounded-2xl hover:bg-rose-600 hover:text-white transition-all shadow-lg flex items-center justify-center gap-2 font-black text-sm"
          >
            <Plus size={20} /> إضافة ماركت
          </button>
        </div>

        {selectedMarket && (
          <div className="space-y-12 animate-in fade-in duration-500">
            {['facial', 'kitchen', 'hotel_toilet', 'dolphin'].map(cat => (
              <div key={cat} className="space-y-4">
                <div className="flex items-center gap-3 px-2">
                  <div className="w-2 h-6 bg-rose-500 rounded-full"></div>
                  <h3 className="text-sm font-black text-rose-100 uppercase tracking-wide">{getCategoryLabel(cat)}</h3>
                </div>

                <div className="space-y-2">
                  <div className="grid grid-cols-[2fr,1fr,1fr,1.2fr] gap-4 px-6 py-2 text-[10px] font-black text-white/30 uppercase tracking-widest">
                    <span>اسم الصنف</span>
                    <span className="text-center">السعر</span>
                    <span className="text-center">العدد</span>
                    <span className="text-center">الإجمالي</span>
                  </div>

                  {items.filter(i => i.category === cat).map(item => (
                    <div key={item.id} className="p-4 bg-white/[0.02] border border-white/[0.05] rounded-2xl hover:bg-white/[0.05] hover:border-rose-500/30 transition-all group">
                      <div className="grid grid-cols-[2fr,1fr,1fr,1.2fr] gap-4 items-center">
                        <div className="font-bold text-white text-sm">
                          {item.id.includes('manual') ? (
                            <input 
                              placeholder="اسم المنتج..."
                              className="w-full bg-transparent border-b border-white/10 focus:border-rose-500 outline-none p-1 text-sm font-bold text-rose-200"
                              value={item.productName}
                              onChange={(e) => updateItem(item.id, 'productName', e.target.value)}
                            />
                          ) : item.productName}
                        </div>
                        <input 
                          type="number" placeholder="0" 
                          className="w-full glass-input-dark rounded-xl p-3 text-center font-bold text-rose-400 outline-none text-sm"
                          value={item.price || ''} onChange={(e) => updateItem(item.id, 'price', e.target.value)}
                        />
                        <input 
                          type="number" placeholder="0" 
                          className={`w-full rounded-xl p-3 text-center font-black outline-none text-sm transition-all border ${item.quantity > 0 ? 'bg-rose-600 border-rose-400 text-white shadow-[0_0_15px_rgba(225,29,72,0.3)]' : 'bg-white/5 border-white/10 text-white/40'}`}
                          value={item.quantity || ''} onChange={(e) => updateItem(item.id, 'quantity', e.target.value)}
                        />
                        <div className="bg-white/5 rounded-xl p-3 text-center font-black text-rose-100/80 text-sm border border-white/5">
                          {(Number(item.price || 0) * Number(item.quantity || 0)).toLocaleString()}
                          <span className="text-[9px] opacity-40 mr-1">ج.م</span>
                        </div>
                      </div>
                    </div>
                  ))}

                  <button 
                    onClick={() => addItemManual(cat)}
                    className="w-full py-4 border border-dashed border-white/10 rounded-2xl text-white/30 font-black text-[11px] flex items-center justify-center gap-2 hover:bg-white/5 hover:text-rose-400 hover:border-rose-500/30 transition-all"
                  >
                    <PlusCircle size={16}/> إضافة منتج يدوي لقسم {getCategoryLabel(cat)}
                  </button>
                </div>
              </div>
            ))}

            <button 
              onClick={handleSave}
              className="w-full py-6 bg-rose-600 text-white rounded-[2rem] font-black text-xl flex items-center justify-center gap-4 hover:bg-rose-500 transition-all shadow-2xl active:scale-[0.98] group relative overflow-hidden"
            >
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-[shimmer_2s_infinite]"></div>
              <Save size={28}/> 
              <span>ترحيل وحفظ البيانات النهائية</span>
            </button>
          </div>
        )}

        {!selectedMarket && (
          <div className="py-32 text-center">
            <div className="w-24 h-24 bg-white/5 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 border border-white/10 text-rose-500/20">
              <ShoppingBag size={48} />
            </div>
            <p className="text-white/30 font-black text-lg">يرجى اختيار ماركت لبدء تسجيل المبيعات اليومية</p>
          </div>
        )}
      </div>

      {isAddMarketModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[1000] flex items-center justify-center p-4">
          <div className="glass-card-dark p-8 md:p-12 rounded-[3rem] max-w-md w-full animate-in zoom-in-95">
            <h3 className="text-2xl font-black text-white mb-6">إضافة ماركت جديد</h3>
            <input 
              className="w-full glass-input-dark rounded-2xl p-5 outline-none font-bold text-lg mb-8"
              placeholder="اسم الماركت الجديد..."
              value={newMarketName}
              onChange={(e) => setNewMarketName(e.target.value)}
              autoFocus
            />
            <div className="flex gap-4">
              <button onClick={() => {
                if(newMarketName.trim()){
                  push(ref(db, 'markets'), { name: newMarketName.trim(), creatorId: user.id });
                  setNewMarketName('');
                  setIsAddMarketModalOpen(false);
                }
              }} className="flex-1 bg-rose-600 text-white py-4 rounded-2xl font-black text-sm active-glow transition-all">إضافة الماركت</button>
              <button onClick={() => setIsAddMarketModalOpen(false)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-2xl font-black text-sm hover:bg-white/10 transition-all">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DailySales;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Vacation } from '../types';
import { db, ref, onValue, push, set, remove, update } from '../firebase';
import { Calendar, Plus, Trash2, Clock, ChevronRight, ChevronLeft, X, Edit, User as UserIcon, ListFilter, History, RotateCcw } from 'lucide-react';

interface Props {
  user: User;
  users: User[];
}

const VacationManagement: React.FC<Props> = ({ user, users }) => {
  const [vacations, setVacations] = useState<Vacation[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDetails, setSelectedDetails] = useState<{ userId: string, type: string, userName: string } | null>(null);
  const [editingUserBalance, setEditingUserBalance] = useState<User | null>(null);

  // Date State for History Navigation
  const [currentPeriodDate, setCurrentPeriodDate] = useState(new Date());

  const [newVacation, setNewVacation] = useState({
    date: new Date().toISOString().split('T')[0],
    days: 1,
    type: 'annual' as const,
    targetUserId: user.id
  });

  useEffect(() => {
    const vRef = ref(db, 'vacations');
    onValue(vRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setVacations(Object.entries(data).map(([id, val]: any) => ({ ...val, id })));
      } else {
        setVacations([]);
      }
    });
  }, []);

  const handleAddVacation = async () => {
    const vRef = ref(db, 'vacations');
    const targetUserId = user.role === 'admin' ? newVacation.targetUserId : user.id;
    const targetUser = users.find(u => u.id === targetUserId) || user;

    const up = targetUser.vacationBalance || { annual: 14, casual: 7, sick: 0, exams: 0, absent_with_permission: 0, absent_without_permission: 0 };
    let updatedBalance = { ...up };

    if (newVacation.type === 'annual') updatedBalance.annual -= newVacation.days;
    else if (newVacation.type === 'casual') updatedBalance.casual -= newVacation.days;
    else if (newVacation.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) - newVacation.days;
    else if (newVacation.type === 'absent_without_permission') updatedBalance.absent_without_permission = (updatedBalance.absent_without_permission || 0) + newVacation.days;

    await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });

    await push(vRef, {
      ...newVacation,
      userId: targetUser.id,
      userName: targetUser.employeeName,
      createdAt: new Date().toISOString()
    });

    setIsModalOpen(false);
    alert("تم تسجيل الإجازة بنجاح");
  };

  const handleDeleteVacation = async (id: string) => {
    if (window.confirm("⚠️ هل أنت متأكد من حذف هذا السجل؟ سيتم إعادة الأيام للرصيد.")) {
      const vToDelete = vacations.find(v => v.id === id);
      if (vToDelete) {
        const targetUser = users.find(u => u.id === vToDelete.userId);
        if (targetUser) {
          const up = targetUser.vacationBalance || { annual: 14, casual: 7 };
          let updatedBalance = { ...up };

          if (vToDelete.type === 'annual') updatedBalance.annual += Number(vToDelete.days);
          else if (vToDelete.type === 'casual') updatedBalance.casual += Number(vToDelete.days);
          else if (vToDelete.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) + Number(vToDelete.days);
          else if (vToDelete.type === 'absent_without_permission') updatedBalance.absent_without_permission = (updatedBalance.absent_without_permission || 0) - Number(vToDelete.days);

          await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });
        }
      }
      await remove(ref(db, `vacations/${id}`));
    }
  };

  const getPeriodRange = (baseDate: Date) => {
    const d = new Date(baseDate);
    const day = d.getDate();
    let start, end;

    // Default Period Logic: 21st to 20th
    if (day >= 21) {
      start = new Date(d.getFullYear(), d.getMonth(), 21);
      end = new Date(d.getFullYear(), d.getMonth() + 1, 20, 23, 59, 59);
    } else {
      start = new Date(d.getFullYear(), d.getMonth() - 1, 21);
      end = new Date(d.getFullYear(), d.getMonth(), 20, 23, 59, 59);
    }
    return { start, end };
  };

  const currentRange = useMemo(() => getPeriodRange(currentPeriodDate), [currentPeriodDate]);

  const changePeriod = (direction: 'prev' | 'next') => {
    const newDate = new Date(currentPeriodDate);
    if (direction === 'prev') newDate.setMonth(newDate.getMonth() - 1);
    else newDate.setMonth(newDate.getMonth() + 1);
    setCurrentPeriodDate(newDate);
  };

  const resetToCurrentMonth = () => {
    setCurrentPeriodDate(new Date());
  };

  const visibleUsers = useMemo(() => {
    if (!users) return [];
    if (user.role === 'admin') return users;
    // Standard User only sees their own profile
    return users.filter(u => u.id === user.id);
  }, [user, users]);

  const filteredDetails = useMemo(() => {
    if (!selectedDetails) return [];
    return vacations.filter(v => {
      const vDate = new Date(v.date);
      const isCorrectType = v.type === selectedDetails.type;
      const isCorrectUser = v.userId === selectedDetails.userId;
      const isInRange = vDate >= currentRange.start && vDate <= currentRange.end;
      return isCorrectType && isCorrectUser && isInRange;
    });
  }, [selectedDetails, vacations, currentRange]);

  const totalDaysInPeriod = useMemo(() => {
    return filteredDetails.reduce((sum, v) => sum + Number(v.days || 0), 0);
  }, [filteredDetails]);

  const getTypeNameAr = (type: string) => {
    const names: any = { annual: 'سنوي', casual: 'عارضة', sick: 'مرضي', exams: 'امتحانات', absent_with_permission: 'بإذن', absent_without_permission: 'بدون إذن' };
    return names[type] || type;
  };

  return (
    <div className="space-y-6 pb-20" dir="rtl">
      {/* Header & Controls */}
      <div className="glass-card-dark p-6 md:p-8 rounded-[2rem] border border-white/5">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
          <div className="flex items-center gap-3">
            <div className="p-3 bg-rose-600 text-white rounded-2xl shadow-lg active-glow"><Calendar size={24}/></div>
            <div>
              <h2 className="text-2xl font-black text-white leading-none">رصيد إجازاتي</h2>
              <p className="text-[10px] text-rose-400 font-bold uppercase tracking-widest mt-1">Vacation Balance Tracker</p>
            </div>
          </div>

          <button 
            onClick={() => {
              setNewVacation(prev => ({ ...prev, targetUserId: user.id }));
              setIsModalOpen(true);
            }}
            className="w-full md:w-auto bg-rose-600 text-white px-8 py-4 rounded-2xl flex items-center justify-center gap-2 hover:bg-rose-500 shadow-xl font-black text-sm transition-all active:scale-95"
          >
            <Plus size={20}/> تسجيل إجازة
          </button>
        </div>

        {/* Users Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {visibleUsers.map(u => (
            <div key={u.id} className="bg-white/5 p-6 rounded-[2.5rem] border border-white/10 group hover:border-rose-500/30 transition-all relative">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-rose-900/40 rounded-2xl flex items-center justify-center text-rose-400 shadow-sm border border-white/10"><UserIcon size={24}/></div>
                  <div>
                    <p className="font-black text-white">{u.employeeName}</p>
                    <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">{u.employeeCode}</p>
                  </div>
                </div>
                {user.role === 'admin' && (
                  <button onClick={() => setEditingUserBalance(u)} className="p-2 bg-blue-500/10 text-blue-400 rounded-lg hover:bg-blue-500 hover:text-white transition-all"><Edit size={14}/></button>
                )}
              </div>

              <div className="grid grid-cols-4 gap-2">
                {[
                  { label: 'سنوي', type: 'annual', balance: u.vacationBalance?.annual ?? 0, text: 'text-blue-400', light: 'bg-blue-500/10' },
                  { label: 'عارضة', type: 'casual', balance: u.vacationBalance?.casual ?? 0, text: 'text-orange-400', light: 'bg-orange-500/10' },
                  { label: 'مرضي', type: 'sick', balance: u.vacationBalance?.sick ?? 0, text: 'text-red-400', light: 'bg-red-500/10' },
                  { label: 'بدون إذن', type: 'absent_without_permission', balance: u.vacationBalance?.absent_without_permission ?? 0, text: 'text-purple-400', light: 'bg-purple-500/10' }
                ].map(box => (
                  <button 
                    key={box.type}
                    onClick={() => {
                        setSelectedDetails({ userId: u.id, type: box.type, userName: u.employeeName });
                        resetToCurrentMonth();
                    }}
                    className={`${box.light} p-3 rounded-2xl flex flex-col items-center justify-center hover:scale-105 transition-all border border-transparent hover:border-white/20 group/btn`}
                  >
                    <span className={`text-[8px] font-black uppercase ${box.text} mb-1 tracking-tighter opacity-70`}>{box.label}</span>
                    <span className={`text-xl font-black ${box.text}`}>{box.balance}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Details Modal with Timeline Navigation */}
      {selectedDetails && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[2000] flex items-center justify-center p-4" onClick={() => setSelectedDetails(null)}>
          <div className="glass-card-dark rounded-[3rem] w-full max-w-lg overflow-hidden shadow-2xl animate-in zoom-in-95 border border-white/10" onClick={e => e.stopPropagation()}>
            <div className="bg-rose-900/80 p-6 text-white flex justify-between items-center">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-white/10 rounded-xl"><History size={20}/></div>
                <div>
                  <h3 className="text-lg font-black">سجل {getTypeNameAr(selectedDetails.type)}</h3>
                  <p className="text-[10px] font-bold text-rose-300 opacity-80 uppercase tracking-widest">{selectedDetails.userName}</p>
                </div>
              </div>
              <button onClick={() => setSelectedDetails(null)} className="p-2 hover:bg-white/10 rounded-full transition-all"><X size={24}/></button>
            </div>

            {/* Months Navigation Bar */}
            <div className="p-4 bg-white/5 border-b border-white/5 flex justify-between items-center">
              <div className="flex items-center gap-3">
                <button onClick={() => changePeriod('prev')} className="p-2 bg-white/5 hover:bg-white/10 rounded-xl text-rose-400 transition-all"><ChevronRight size={18}/></button>
                <div className="text-center min-w-[120px]">
                  <span className="block text-[8px] font-black text-white/30 uppercase tracking-widest">فترة السجل</span>
                  <span className="text-xs font-black text-white">
                    {currentRange.start.toLocaleDateString('ar-EG', {month: 'long', year: 'numeric'})}
                  </span>
                </div>
                <button onClick={() => changePeriod('next')} className="p-2 bg-white/5 hover:bg-white/10 rounded-xl text-rose-400 transition-all"><ChevronLeft size={18}/></button>
              </div>
              <button onClick={resetToCurrentMonth} title="الشهر الحالي" className="p-2 bg-white/5 hover:bg-white/10 rounded-xl text-amber-400 transition-all border border-white/10"><RotateCcw size={16}/></button>
            </div>

            <div className="max-h-[40vh] overflow-y-auto p-6 space-y-3 custom-scrollbar">
              {filteredDetails.length === 0 ? (
                <div className="text-center py-10 opacity-40 italic font-bold text-white/40">لا توجد سجلات لهذه الفترة</div>
              ) : (
                filteredDetails.map(v => (
                  <div key={v.id} className="bg-white/5 p-4 rounded-2xl border border-white/10 shadow-sm flex justify-between items-center group">
                    <div>
                      <span className="block text-xs font-black text-white">{new Date(v.date).toLocaleDateString('ar-EG', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
                      <span className="block text-[10px] font-bold text-rose-400/60 italic mt-1">المدة: {v.days} يوم</span>
                    </div>
                    {user.role === 'admin' && (
                      <button 
                        onClick={() => handleDeleteVacation(v.id)} 
                        className="p-2 text-red-400/30 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                      >
                        <Trash2 size={16}/>
                      </button>
                    )}
                  </div>
                ))
              )}
            </div>

            <div className="p-6 bg-white/5 border-t border-white/5 flex justify-between items-center">
               <div className="flex flex-col">
                 <span className="text-[10px] font-black text-white/30 uppercase">إجمالي الأيام</span>
                 <span className="text-xl font-black text-rose-400">{totalDaysInPeriod} أيام</span>
               </div>
               <button onClick={() => setSelectedDetails(null)} className="bg-rose-600 text-white px-10 py-4 rounded-2xl font-black text-sm hover:bg-rose-500 transition-all">إغلاق</button>
            </div>
          </div>
        </div>
      )}

      {/* Editing Balance Modal (Admin Only) */}
      {editingUserBalance && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[2000] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] w-full max-w-md p-8 shadow-2xl border border-white/10">
            <h3 className="text-xl font-black text-white mb-6 border-b border-white/10 pb-4">تحديث أرصدة {editingUserBalance.employeeName}</h3>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-white/40 uppercase mr-1 mb-2">سنوي</label>
                <input 
                  type="number" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10"
                  value={editingUserBalance.vacationBalance?.annual}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...(editingUserBalance.vacationBalance || {}), annual: Number(e.target.value)} as any})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-white/40 uppercase mr-1 mb-2">عارضة</label>
                <input 
                  type="number" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10"
                  value={editingUserBalance.vacationBalance?.casual}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...(editingUserBalance.vacationBalance || {}), casual: Number(e.target.value)} as any})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-white/40 uppercase mr-1 mb-2">مرضي</label>
                <input 
                  type="number" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10"
                  value={editingUserBalance.vacationBalance?.sick}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...(editingUserBalance.vacationBalance || {}), sick: Number(e.target.value)} as any})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-white/40 uppercase mr-1 mb-2">غياب (بدون إذن)</label>
                <input 
                  type="number" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10"
                  value={editingUserBalance.vacationBalance?.absent_without_permission}
                  onChange={(e) => setEditingUserBalance({...editingUserBalance, vacationBalance: {...(editingUserBalance.vacationBalance || {}), absent_without_permission: Number(e.target.value)} as any})}
                />
              </div>
            </div>
            <div className="flex gap-4 mt-8">
              <button onClick={() => {
                update(ref(db, `users/${editingUserBalance.id}`), { vacationBalance: editingUserBalance.vacationBalance });
                setEditingUserBalance(null);
                alert("تم تحديث الرصيد بنجاح");
              }} className="flex-1 bg-rose-600 text-white py-4 rounded-xl font-black">حفظ</button>
              <button onClick={() => setEditingUserBalance(null)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}

      {/* Registration Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[2000] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] w-full max-w-md p-8 shadow-2xl animate-in zoom-in-95 border border-white/10">
            <h3 className="text-2xl font-black text-white mb-8 flex items-center gap-3">
              <Plus className="text-rose-500"/> تسجيل إجازة
            </h3>
            <div className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-white/30 uppercase mb-2 mr-1">الموظف</label>
                <select 
                  className={`w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10 ${user.role !== 'admin' ? 'opacity-40' : ''}`}
                  value={user.role === 'admin' ? newVacation.targetUserId : user.id}
                  disabled={user.role !== 'admin'}
                  onChange={(e) => setNewVacation({...newVacation, targetUserId: e.target.value})}
                >
                  {user.role === 'admin' ? (
                    users.map(u => <option key={u.id} value={u.id} className="bg-slate-900">{u.employeeName}</option>)
                  ) : (
                    <option value={user.id} className="bg-slate-900">{user.employeeName}</option>
                  )}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-white/30 uppercase mb-2">التاريخ</label>
                  <input 
                    type="date" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10 text-sm"
                    value={newVacation.date}
                    onChange={(e) => setNewVacation({...newVacation, date: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-white/30 uppercase mb-2">المدة (أيام)</label>
                  <input 
                    type="number" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10"
                    value={newVacation.days}
                    onChange={(e) => setNewVacation({...newVacation, days: Number(e.target.value)})}
                  />
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-white/30 uppercase mb-2">نوع الطلب</label>
                <select 
                  className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10"
                  value={newVacation.type}
                  onChange={(e) => setNewVacation({...newVacation, type: e.target.value as any})}
