            onClick={() => setActiveSubTab(tab.id)}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl whitespace-nowrap transition-all font-black text-xs ${activeSubTab === tab.id ? 'bg-rose-600 text-white shadow-lg' : 'bg-white/5 text-white/40 border border-white/10'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'general' && (
        <div className="glass-card-dark p-6 md:p-10 rounded-[2rem] border border-white/5 animate-in fade-in">
          <h3 className="text-xl font-black text-white mb-8 border-b border-white/10 pb-4">الإعدادات العامة</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-white/30 uppercase tracking-widest mr-2">اسم البرنامج</label>
              <input className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10 text-sm" value={newProgramName} onChange={e => setNewProgramName(e.target.value)}/>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-white/30 uppercase tracking-widest mr-2">رقم الواتساب</label>
              <input className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10 text-sm" value={whatsapp} onChange={e => setWhatsapp(e.target.value)}/>
            </div>

            <div className="md:col-span-2 space-y-4 pt-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="flex items-center justify-between p-5 bg-rose-600/10 rounded-[1.5rem] border border-rose-500/20">
                  <div className="flex items-center gap-3">
                    <Trophy className="text-rose-400" size={24}/>
                    <div>
                      <p className="text-sm font-black text-white">تفعيل نجم الشهر</p>
                      <p className="text-[10px] font-bold text-rose-400/60 uppercase">Top Performer Display</p>
                    </div>
                  </div>
                  <label className="relative inline-flex items-center cursor-pointer">
                    <input type="checkbox" checked={showTopSalesInTicker} onChange={e => setShowTopSalesInTicker(e.target.checked)} className="sr-only peer" />
                    <div className="w-11 h-6 bg-white/10 rounded-full peer peer-checked:bg-rose-600 after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full"></div>
                  </label>
                </div>

                <div className="flex items-center justify-between p-5 bg-blue-600/10 rounded-[1.5rem] border border-blue-500/20">
                  <div className="flex items-center gap-3">
                    <Zap className="text-blue-400" size={24}/>
                    <div>
                      <p className="text-sm font-black text-white">تحريك شريط الأخبار</p>
                      <p className="text-[10px] font-bold text-blue-400/60 uppercase">Animated News Bar</p>
                    </div>
                  </div>
                  <label className="relative inline-flex items-center cursor-pointer">
                    <input type="checkbox" checked={isTickerAnimated} onChange={e => setIsTickerAnimated(e.target.checked)} className="sr-only peer" />
                    <div className="w-11 h-6 bg-white/10 rounded-full peer peer-checked:bg-blue-600 after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full"></div>
                  </label>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-white/30 uppercase mr-2">نص شريط الأخبار</label>
                <textarea className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10 h-24 resize-none text-sm" value={newTickerText} onChange={e => setNewTickerText(e.target.value)} />
              </div>
            </div>
          </div>
          <button onClick={handleSaveGeneral} className="bg-rose-600 text-white px-10 py-4 rounded-xl font-black flex items-center gap-2 shadow-lg hover:bg-rose-500 transition-all">
            <Save size={18}/> حفظ الإعدادات العامة
          </button>
        </div>
      )}

      {activeSubTab === 'users' && (
        <div className="space-y-8 animate-in fade-in">
          <div className="glass-card-dark p-6 md:p-10 rounded-[2.5rem] border border-white/5">
            <h3 className="text-xl font-black text-white mb-6 flex items-center gap-3"><UserPlus className="text-rose-500" /> إضافة موظف جديد</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <input className="glass-input-dark p-4 rounded-xl font-bold text-sm" placeholder="الاسم" value={newUser.employeeName} onChange={e => setNewUser({...newUser, employeeName: e.target.value})}/>
              <input className="glass-input-dark p-4 rounded-xl font-bold text-sm" placeholder="الكود" value={newUser.employeeCode} onChange={e => setNewUser({...newUser, employeeCode: e.target.value})}/>
              <select className="glass-input-dark p-4 rounded-xl font-bold text-sm" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as any})}>
                <option value="coordinator" className="bg-slate-900">منسق</option>
                <option value="usher" className="bg-slate-900">أشر</option>
                <option value="admin" className="bg-slate-900">مدير</option>
              </select>
              <input className="glass-input-dark p-4 rounded-xl font-bold text-sm" placeholder="اسم المستخدم" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})}/>
              <input className="glass-input-dark p-4 rounded-xl font-bold text-sm" type="password" placeholder="كلمة المرور" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})}/>
            </div>
            <button onClick={() => {
              if(!newUser.username || !newUser.password || !newUser.employeeName) return alert("يرجى ملء البيانات");
              const id = push(ref(db, 'users')).key || '';
              set(ref(db, `users/${id}`), { 
                ...newUser, 
                id, 
                isOnline: false, 
                permissions: { 
                    registerSales: true, 
                    viewSalesHistory: true, 
                    registerInventory: true, 
                    viewInventoryHistory: true, 
                    registerCompetitorPrices: true, 
                    viewCompetitorReports: true, 
                    viewVacationMgmt: true, 
                    viewSettings: false, 
                    viewColleaguesSales: false 
                }, 
                vacationBalance: { 
                    annual: 14, 
                    casual: 7, 
                    sick: 0, 
                    exams: 0, 
                    absent_with_permission: 0, 
                    absent_without_permission: 0 
                } 
              });
              setNewUser({ username: '', password: '', employeeName: '', employeeCode: '', role: 'coordinator' });
              alert("تم إنشاء الحساب بنجاح");
            }} className="mt-6 bg-rose-600 text-white px-10 py-4 rounded-xl font-black shadow-lg">إضافة الحساب</button>
          </div>

          <div className="glass-card-dark rounded-[2.5rem] border border-white/5 overflow-hidden">
            <table className="w-full text-right">
              <thead className="bg-white/5 text-[10px] font-black text-white/40">
                <tr><th className="p-6">الموظف</th><th className="p-6">الكود</th><th className="p-6 text-center">الإجراءات</th></tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {users.map(u => (
                  <tr key={u.id} className="hover:bg-white/5 transition-all">
                    <td className="p-6">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-rose-500/10 text-rose-400 flex items-center justify-center font-black border border-rose-500/20">{u.employeeName?.charAt(0)}</div>
                        <span className="font-bold text-sm text-white">{u.employeeName}</span>
                      </div>
                    </td>
                    <td className="p-6 font-bold text-xs text-white/50">{u.employeeCode}</td>
                    <td className="p-6">
                      <div className="flex gap-2 justify-center">
                        <button onClick={() => setMessageTarget(u)} className="p-2 text-amber-400 hover:bg-amber-400/10 rounded-lg" title="إرسال رسالة"><Mail size={16}/></button>
                        <button onClick={() => setEditingCredentials(u)} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded-lg" title="تعديل البيانات"><Key size={16}/></button>
                        <button onClick={() => setEditingPermissions(u.id)} className="p-2 text-rose-400 hover:bg-rose-400/10 rounded-lg" title="الصلاحيات"><Shield size={16}/></button>
                        <button onClick={() => handleDeleteUser(u.id, u.employeeName)} className="p-2 text-red-400 hover:bg-red-400/10 rounded-lg" title="حذف"><Trash2 size={16}/></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Markets & Companies sections omitted for brevity but they remain identical */}
      {/* Modals remain as per previous turns logic */}

      {messageTarget && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4" onClick={() => setMessageTarget(null)}>
          <div className="glass-card-dark rounded-[3rem] p-8 max-w-md w-full border border-white/10 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <h4 className="text-xl font-black text-white mb-6">مراسلة {messageTarget.employeeName}</h4>
            <textarea className="w-full glass-input-dark p-4 rounded-xl font-bold outline-none border border-white/10 h-32 resize-none" placeholder="نص الرسالة..." value={msgText} onChange={e => setMsgText(e.target.value)}/>
            <div className="flex gap-3 mt-8">
              <button onClick={handleSendMessage} className="flex-1 bg-rose-600 text-white py-4 rounded-xl font-black shadow-lg flex items-center justify-center gap-2"><Send size={16}/> إرسال الآن</button>
              <button onClick={() => setMessageTarget(null)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}

      {/* Rest of Modals (Credentials, Permissions, etc.) logic persists */}
    </div>
  );
};

export default Settings;

export type UserRole = 'admin' | 'coordinator' | 'usher';

export interface UserPermissions {
  registerSales: boolean;
  viewSalesHistory: boolean;
  registerInventory: boolean;
  viewInventoryHistory: boolean;
  registerCompetitorPrices: boolean;
  viewCompetitorReports: boolean;
  viewVacationMgmt: boolean;
  viewSettings: boolean;
  viewColleaguesSales: boolean;
}

export interface User {
  id: string;
  username: string;
  password?: string;
  role: UserRole;
  employeeName: string;
  employeeCode: string;
  phone: string;
  isOnline: boolean;
  permissions: UserPermissions;
  vacationBalance: {
    annual: number;
    casual: number;
    sick: number;
    exams: number;
    absent_with_permission?: number;
    absent_without_permission?: number;
  };
}

export interface Notification {
  id: string;
  senderId: string;
  receiverId: string;
  message: string;
  timestamp: string;
  isRead: boolean;
}

export interface AppSettings {
  tickerText: string;
  tickerSpeed: number;
  whatsappNumber: string;
  programName: string;
  showTopSalesInTicker?: boolean;
  isTickerAnimated?: boolean;
}

export interface Market {
  id: string;
  name: string;
  creatorId: string;
}

export interface Company {
  id: string;
  name: string;
  creatorId: string;
}

export interface SaleItem {
  id: string;
  category: string;
  productName: string;
  price: number;
  quantity: number;
}

export interface DailySale {
  id: string;
  userId: string;
  userName: string;
  marketName: string;
  date: string;
  items: SaleItem[];
  total: number;
}

export interface Vacation {
  id: string;
  userId: string;
  userName: string;
  date: string;
  days: number;
  type: 'annual' | 'casual' | 'sick' | 'exams' | 'absent_with_permission' | 'absent_without_permission';
  createdAt: string;
}

export interface InventoryRecord {
  id: string;
  userId: string;
  userName: string;
  marketName: string;
  date: string;
  items: Array<{
    productName: string;
    quantity: number;
  }>;
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, Calendar,
  Loader2, Sparkles, Phone, Palette, Copy, Trash2
} from 'lucide-react';
import { db, ref, onValue, update, remove } from './firebase';
import { User, AppSettings, Notification, Market, Company, DailySale, InventoryRecord, Vacation } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';
import AIChatbot from './views/AIChatbot';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [sales, setSales] = useState<DailySale[]>([]);
  const [inventory, setInventory] = useState<InventoryRecord[]>([]);
  const [vacations, setVacations] = useState<Vacation[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isAIChatOpen, setIsAIChatOpen] = useState(false);
  const [isNotifDropdownOpen, setIsNotifDropdownOpen] = useState(false);
  const [selectedNotif, setSelectedNotif] = useState<Notification | null>(null);
  const [currentTheme, setCurrentTheme] = useState<'rose' | 'dark' | 'purple' | 'emerald'>('rose');

  const notifRef = useRef<HTMLDivElement>(null);

  // Theme Config
  const themes = {
    rose: 'blob-rose',
    dark: 'blob-dark',
    purple: 'blob-purple',
    emerald: 'blob-emerald'
  };

  useEffect(() => {
    document.body.className = themes[currentTheme];
  }, [currentTheme]);

  // Monthly Reset Logic for "Absent without Permission"
  useEffect(() => {
    if (user?.role === 'admin' && users.length > 0) {
      const currentMonth = new Date().getMonth();
      const lastResetMonth = localStorage.getItem('lastResetMonth');

      if (lastResetMonth === null || parseInt(lastResetMonth) !== currentMonth) {
        users.forEach(u => {
          if (u.id && u.vacationBalance) {
            update(ref(db, `users/${u.id}/vacationBalance`), {
              absent_without_permission: 0
            });
          }
        });
        localStorage.setItem('lastResetMonth', currentMonth.toString());
      }
    }
  }, [user, users]);

  useEffect(() => {
    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const usersList = Object.entries(data).map(([id, val]: any) => ({ ...val, id: val.id || id }));
        setUsers(usersList);
      }
    });

    onValue(ref(db, 'sales'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSales(Object.values(data));
    });

    onValue(ref(db, 'inventory'), (snapshot) => {
      const data = snapshot.val();
      if (data) setInventory(Object.values(data));
    });

    onValue(ref(db, 'vacations'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
        setVacations(list);
      }
    });

    onValue(ref(db, 'notifications'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
        setNotifications(list);
      } else {
        setNotifications([]);
      }
    });

    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) setMarkets(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) setCompanies(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
    }
  }, [user]);

  const starOfMonthInfo = useMemo(() => {
    if (!sales || sales.length === 0) return null;
    const now = new Date();
    const currentMonthSales = sales.filter(s => {
      const d = new Date(s.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });
    const userTotals: Record<string, {name: string, total: number}> = {};
    currentMonthSales.forEach(s => {
      if (!userTotals[s.userId]) userTotals[s.userId] = { name: s.userName, total: 0 };
      userTotals[s.userId].total += (Number(s.total) || 0);
    });
    return Object.values(userTotals).sort((a, b) => b.total - a.total)[0] || null;
  }, [sales]);

  const tickerText = useMemo(() => {
    let text = settings?.tickerText || '';
    if (settings?.showTopSalesInTicker && starOfMonthInfo) {
      text = `🏆 نجم الشهر: ${starOfMonthInfo.name} بمبيعات ${starOfMonthInfo.total.toLocaleString()} ج.م 🏆 | ` + text;
    }
    return text;
  }, [settings, starOfMonthInfo]);

  const unreadCount = useMemo(() => {
    if (!user) return 0;
    return notifications.filter(n => n.receiverId === user.id && !n.isRead).length;
  }, [notifications, user]);

  const userNotifications = useMemo(() => {
    if (!user) return [];
    return notifications.filter(n => n.receiverId === user.id).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [notifications, user]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user) update(ref(db, `users/${user.id}`), { isOnline: false });
    setUser(null);
  };

  const openWhatsApp = () => {
    if (settings?.whatsappNumber) {
      window.open(`https://wa.me/${settings.whatsappNumber}`, '_blank');
    } else {
      alert("لم يتم تسجيل رقم واتساب في الإعدادات");
    }
  };

  const toggleTheme = () => {
    const themeOrder: Array<'rose' | 'dark' | 'purple' | 'emerald'> = ['rose', 'dark', 'purple', 'emerald'];
    const nextIdx = (themeOrder.indexOf(currentTheme) + 1) % themeOrder.length;
    setCurrentTheme(themeOrder[nextIdx]);
  };

  const deleteNotification = async (id: string) => {
    await remove(ref(db, `notifications/${id}`));
    if (selectedNotif?.id === id) setSelectedNotif(null);
  };

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: true },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: true },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: true },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: true },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: true },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: true },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: true },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user?.role === 'admin' },
  ].filter(i => i.visible);

  if (isLoading) return <div className="h-screen flex items-center justify-center bg-transparent"><Loader2 className="animate-spin text-rose-50" size={48}/></div>;
  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className={`flex h-screen overflow-hidden relative bg-transparent text-white ${currentTheme}-theme`}>
      {/* Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-[60] backdrop-blur-md transition-all duration-300" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Glass Sidebar */}
      <aside className={`glass-sidebar-inner text-white w-72 flex-shrink-0 transition-all duration-500 z-[70] fixed md:absolute md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:-right-72'} shadow-2xl`}>
        <div className="p-8 flex flex-col h-full">
          <div className="mb-12 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-[0.4em] text-rose-500">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Modern Trade</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="p-2 hover:bg-white/10 rounded-xl transition-all"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-2 overflow-y-auto custom-scrollbar">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all duration-300 relative group ${activeTab === item.id ? 'bg-rose-600/20 text-white font-black active-glow' : 'hover:bg-white/5 text-white/60 font-medium'}`}
              >
                <span className={`${activeTab === item.id ? 'text-rose-400' : 'group-hover:text-white'}`}>{item.icon}</span>
                <span className="text-sm">{item.label}</span>
                {activeTab === item.id && <div className="absolute left-3 w-1.5 h-6 bg-rose-500 rounded-full"></div>}
              </button>
            ))}
          </nav>

          <div className="mt-8 pt-8 border-t border-white/5">
             <button onClick={handleLogout} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-rose-400 hover:bg-rose-500/10 transition-all font-black text-sm">
                <LogOut size={20} />
                <span>تسجيل الخروج</span>
             </button>
          </div>
        </div>
      </aside>

      <main 
        className="flex-1 flex flex-col min-w-0 overflow-hidden"
        onClick={() => {
          if(isSidebarOpen) setIsSidebarOpen(false);
          if(isNotifDropdownOpen) setIsNotifDropdownOpen(false);
        }}
      >
        {tickerText && (
          <div className="bg-rose-950/40 backdrop-blur-md py-2.5 text-rose-100 text-[11px] font-black overflow-hidden z-[50] border-b border-white/5 ticker-container">
            <div className={settings?.isTickerAnimated ? "animate-ticker" : "px-8"}>
              {tickerText} &nbsp;&nbsp; • &nbsp;&nbsp; {tickerText}
            </div>
          </div>
        )}

        <header className="h-20 flex items-center justify-between px-8 glass-header-inner z-[40]">
          <div className="flex items-center gap-4">
            <button 
              onClick={(e) => { e.stopPropagation(); setIsSidebarOpen(!isSidebarOpen); }} 
              className="p-2.5 bg-white/5 text-white rounded-xl hover:bg-white/10 transition-all active:scale-95 flex items-center gap-3"
            >
              <Menu size={22} />
              <span className="hidden md:block font-black text-xs text-white/80">{user.employeeName}</span>
            </button>
            <h2 className="font-black text-white text-lg tracking-tight hidden sm:block">
              {settings?.programName || 'Soft Rose Modern Trade'}
            </h2>
          </div>

          <div className="flex items-center gap-1 md:gap-3">
            {/* Top Navigation Buttons - Ordered Left to Right: Logout, Bell, Style, WhatsApp */}
            <div className="flex items-center gap-2">
              <button 
                onClick={handleLogout} 
                className="p-2.5 bg-white/5 text-rose-400 rounded-xl hover:bg-rose-500 hover:text-white transition-all shadow-sm"
                title="تسجيل الخروج"
              >
                <LogOut size={20} />
              </button>

              <div className="relative" ref={notifRef}>
                <button 
                  onClick={(e) => { e.stopPropagation(); setIsNotifDropdownOpen(!isNotifDropdownOpen); }}
                  className="p-2.5 bg-white/5 text-amber-400 rounded-xl hover:bg-amber-500 hover:text-white transition-all relative shadow-sm"
