    const nextIdx = (themeOrder.indexOf(currentTheme) + 1) % themeOrder.length;
    setCurrentTheme(themeOrder[nextIdx]);
  };

  const openWhatsApp = () => {
    if (settings?.whatsappNumber) {
      window.open(`https://wa.me/${settings.whatsappNumber}`, '_blank');
