import { Calendar, Plus, Trash2, History, X, Edit, Save, ChevronRight, ChevronLeft } from 'lucide-react';

interface Props {
  user: User;
  users: User[];
  vacations: Vacation[];
}

const VacationManagement: React.FC<Props> = ({ user, users, vacations }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDetails, setSelectedDetails] = useState<{ userId: string, type: string, userName: string } | null>(null);
  const [editingVacation, setEditingVacation] = useState<Vacation | null>(null);
  const [currentPeriodDate, setCurrentPeriodDate] = useState(new Date());

  const [newVacation, setNewVacation] = useState({
    date: new Date().toISOString().split('T')[0],
    days: 1,
    type: 'annual' as const,
    targetUserId: user.id
  });

  // Sorting: Chronological (Start to End of Month)
  const sortedVacations = useMemo(() => {
    return [...vacations].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [vacations]);

  const handleAddVacation = async () => {
    const targetUserId = user.role === 'admin' ? newVacation.targetUserId : user.id;

    // Duplicate check for date
    const isDuplicate = vacations.some(v => v.userId === targetUserId && v.date === newVacation.date && v.id !== (editingVacation?.id || ''));
    if (isDuplicate) {
      alert("⚠️ تم تسجيل اليوم من قبل للموظف");
      return;
    }

    const targetUser = users.find(u => u.id === targetUserId) || user;
    const currentBalance = targetUser.vacationBalance || { annual: 14, casual: 7, sick: 0, absent_with_permission: 0, absent_without_permission: 0 };
    let updatedBalance = { ...currentBalance };

    // Logic: If editing, FIRST return old days to balance
    if (editingVacation) {
        if (editingVacation.type === 'annual') updatedBalance.annual += Number(editingVacation.days);
        else if (editingVacation.type === 'casual') updatedBalance.casual += Number(editingVacation.days);
        else if (editingVacation.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) + Number(editingVacation.days);
        else if (editingVacation.type === 'absent_without_permission') updatedBalance.absent_without_permission = (updatedBalance.absent_without_permission || 0) - Number(editingVacation.days);
    }

    // Logic: Apply NEW deduction
    if (newVacation.type === 'annual') updatedBalance.annual -= newVacation.days;
    else if (newVacation.type === 'casual') updatedBalance.casual -= newVacation.days;
    else if (newVacation.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) - newVacation.days;
    else if (newVacation.type === 'absent_without_permission') updatedBalance.absent_without_permission = (updatedBalance.absent_without_permission || 0) + newVacation.days;

    await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });

    if (editingVacation) {
        await update(ref(db, `vacations/${editingVacation.id}`), { ...newVacation, userId: targetUser.id, userName: targetUser.employeeName });
    } else {
        await push(ref(db, 'vacations'), { ...newVacation, userId: targetUser.id, userName: targetUser.employeeName, createdAt: new Date().toISOString() });
    }

    setIsModalOpen(false);
    setEditingVacation(null);
    alert("✅ تم الحفظ بنجاح");
  };

  const handleDeleteVacation = async (id: string) => {
    if (window.confirm("⚠️ هل أنت متأكد؟ سيتم استرداد الأيام للرصيد فوراً.")) {
      const vToDelete = vacations.find(v => v.id === id);
      if (vToDelete) {
        const targetUser = users.find(u => u.id === vToDelete.userId);
        if (targetUser) {
          let updatedBalance = { ...targetUser.vacationBalance };
          if (vToDelete.type === 'annual') updatedBalance.annual += Number(vToDelete.days);
          else if (vToDelete.type === 'casual') updatedBalance.casual += Number(vToDelete.days);
          else if (vToDelete.type === 'absent_with_permission') updatedBalance.absent_with_permission = (updatedBalance.absent_with_permission || 0) + Number(vToDelete.days);
          else if (vToDelete.type === 'absent_without_permission') updatedBalance.absent_without_permission = (updatedBalance.absent_without_permission || 0) - Number(vToDelete.days);
          await update(ref(db, `users/${targetUser.id}`), { vacationBalance: updatedBalance });
        }
      }
      await remove(ref(db, `vacations/${id}`));
    }
  };

  const currentRange = useMemo(() => {
    const d = new Date(currentPeriodDate);
    const start = new Date(d.getFullYear(), d.getMonth(), 1);
    const end = new Date(d.getFullYear(), d.getMonth() + 1, 0, 23, 59, 59);
    return { start, end };
  }, [currentPeriodDate]);

  const filteredDetails = useMemo(() => {
    if (!selectedDetails) return [];
    return sortedVacations.filter(v => {
      const vDate = new Date(v.date);
      return v.type === selectedDetails.type && v.userId === selectedDetails.userId && vDate >= currentRange.start && vDate <= currentRange.end;
    });
  }, [selectedDetails, sortedVacations, currentRange]);

  return (
    <div className="space-y-6 pb-20 text-right" dir="rtl">
      <div className="glass-card-dark p-6 md:p-8 rounded-[2rem]">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
          <div className="flex items-center gap-3">
            <div className="p-3 bg-rose-600 text-white rounded-2xl shadow-lg"><Calendar size={24}/></div>
            <div>
              <h2 className="text-2xl font-black text-white">إدارة أرصدة الإجازات</h2>
              <p className="text-[10px] text-rose-400 font-bold uppercase mt-1">Vacation Balance Hub</p>
            </div>
          </div>
          <button 
            onClick={() => { setIsModalOpen(true); setEditingVacation(null); }}
            className="w-full md:w-auto bg-rose-600 text-white px-8 py-4 rounded-2xl flex items-center justify-center gap-2 font-black text-sm transition-all active:scale-95"
          >
            <Plus size={20}/> تسجيل إجازة
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {(user.role === 'admin' ? users : users.filter(u => u.id === user.id)).map(u => (
            <div key={u.id} className="bg-white/5 p-6 rounded-[2.5rem] border border-white/10 group relative">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-rose-900/40 rounded-2xl flex items-center justify-center text-rose-400 font-black">{u.employeeName?.charAt(0)}</div>
                  <p className="font-black text-white">{u.employeeName}</p>
                </div>
                {user.role === 'admin' && (
                  <div className="flex gap-2">
                    <button onClick={() => { if(window.confirm(`حذف الموظف ${u.employeeName}؟`)) remove(ref(db, `users/${u.id}`)); }} className="p-2 text-red-500 hover:bg-white/10 rounded-xl transition-all"><Trash2 size={16}/></button>
                  </div>
                )}
              </div>
              <div className="grid grid-cols-4 gap-2">
                {[
                  { label: 'سنوي', type: 'annual', balance: u.vacationBalance?.annual ?? 0, color: 'text-blue-400', bg: 'bg-blue-500/10' },
                  { label: 'عارضة', type: 'casual', balance: u.vacationBalance?.casual ?? 0, color: 'text-orange-400', bg: 'bg-orange-500/10' },
                  { label: 'بإذن', type: 'absent_with_permission', balance: u.vacationBalance?.absent_with_permission ?? 0, color: 'text-emerald-400', bg: 'bg-emerald-500/10' },
                  { label: 'بدون إذن', type: 'absent_without_permission', balance: u.vacationBalance?.absent_without_permission ?? 0, color: 'text-purple-400', bg: 'bg-purple-500/10' }
                ].map(box => (
                  <button 
                    key={box.type}
                    onClick={() => { setSelectedDetails({ userId: u.id, type: box.type, userName: u.employeeName }); }}
                    className={`${box.bg} p-3 rounded-2xl flex flex-col items-center justify-center border border-transparent hover:border-white/20`}
                  >
                    <span className={`text-[8px] font-black uppercase ${box.color} mb-1`}>{box.label}</span>
                    <span className={`text-xl font-black ${box.color}`}>{box.balance}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {selectedDetails && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[2000] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] w-full max-w-lg overflow-hidden border border-white/10 animate-in zoom-in-95">
            <div className="bg-rose-900/80 p-6 text-white flex justify-between items-center">
              <div className="flex items-center gap-3">
                <History size={20}/>
                <h3 className="text-lg font-black">سجل إجازات {selectedDetails.userName}</h3>
              </div>
              <button onClick={() => setSelectedDetails(null)} className="p-2 hover:bg-white/10 rounded-full"><X size={24}/></button>
            </div>

            <div className="p-4 bg-white/5 border-b flex justify-between items-center">
              <div className="flex items-center gap-2">
                <button onClick={() => { const d = new Date(currentPeriodDate); d.setMonth(d.getMonth()-1); setCurrentPeriodDate(d); }} className="p-1 hover:bg-white/10 rounded"><ChevronRight size={18}/></button>
                <span className="text-xs font-black">{currentPeriodDate.toLocaleDateString('ar-EG', {month: 'long', year: 'numeric'})}</span>
                <button onClick={() => { const d = new Date(currentPeriodDate); d.setMonth(d.getMonth()+1); setCurrentPeriodDate(d); }} className="p-1 hover:bg-white/10 rounded"><ChevronLeft size={18}/></button>
              </div>
              <span className="text-[10px] font-black opacity-40 uppercase">History List</span>
            </div>

            <div className="max-h-[40vh] overflow-y-auto p-6 space-y-3 custom-scrollbar">
              {filteredDetails.length === 0 ? (
                <p className="text-center opacity-40 py-10 font-bold italic">لا توجد سجلات حالية</p>
              ) : (
                filteredDetails.map(v => (
                  <div key={v.id} className="bg-white/5 p-4 rounded-2xl flex justify-between items-center group">
                    <div>
                      <span className="block text-xs font-black text-white">{new Date(v.date).toLocaleDateString('ar-EG', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
                      <span className="block text-[10px] font-bold text-rose-400 mt-1">المدة: {v.days} يوم</span>
                    </div>
                    {user.role === 'admin' && v.type !== 'annual' && (
                      <div className="flex gap-2">
                        <button onClick={() => { setEditingVacation(v); setNewVacation({ date: v.date, days: v.days, type: v.type, targetUserId: v.userId }); setSelectedDetails(null); setIsModalOpen(true); }} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded-lg"><Edit size={16}/></button>
                        <button onClick={() => handleDeleteVacation(v.id)} className="p-2 text-red-400 hover:bg-red-400/10 rounded-lg"><Trash2 size={16}/></button>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
            <div className="p-6 bg-white/5 flex gap-3">
               <button onClick={() => setSelectedDetails(null)} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black text-sm">إغلاق</button>
            </div>
          </div>
        </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[2000] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] w-full max-w-md p-8 animate-in zoom-in-95">
            <h3 className="text-2xl font-black text-white mb-8">{editingVacation ? 'تعديل إجازة' : 'تسجيل إجازة جديدة'}</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-white/30 mb-2">الموظف</label>
                <select className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none border border-white/10" value={newVacation.targetUserId} onChange={(e) => setNewVacation({...newVacation, targetUserId: e.target.value})} disabled={user.role !== 'admin'}>
                  {users.map(u => <option key={u.id} value={u.id} className="bg-slate-900">{u.employeeName}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-white/30 mb-2">التاريخ</label>
                  <input type="date" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none text-sm" value={newVacation.date} onChange={(e) => setNewVacation({...newVacation, date: e.target.value})} />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-white/30 mb-2">المدة (أيام)</label>
                  <input type="number" className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none" value={newVacation.days} onChange={(e) => setNewVacation({...newVacation, days: Number(e.target.value)})} />
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-white/30 mb-2">نوع الطلب</label>
                <select className="w-full glass-input-dark rounded-xl p-4 font-bold border border-white/10" value={newVacation.type} onChange={(e) => setNewVacation({...newVacation, type: e.target.value as any})}>
                  <option value="annual" className="bg-slate-900">سنوي (خصم من الرصيد)</option>
                  <option value="casual" className="bg-slate-900">عارضة (خصم من الرصيد)</option>
                  <option value="absent_with_permission" className="bg-slate-900">بإذن (تخصم من الراتب)</option>
                  <option value="absent_without_permission" className="bg-slate-900">بدون إذن (إضافة للعداد)</option>
                  <option value="sick" className="bg-slate-900">مرضي</option>
                </select>
              </div>
            </div>
            <div className="flex gap-4 mt-10">
              <button onClick={handleAddVacation} className="flex-1 bg-rose-600 text-white py-4 rounded-xl font-black shadow-lg flex items-center justify-center gap-2"><Save size={18}/> {editingVacation ? 'تحديث' : 'تأكيد'}</button>
              <button onClick={() => setIsModalOpen(false)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default VacationManagement;

import React, { useState } from 'react';
import { User, AppSettings, Market, Company, UserRole } from '../types';
import { db, ref, update, set, push, remove } from '../firebase';
import { 
  Save, UserPlus, Shield, Store, Building2, UserCog, Trash2, Edit, Key, Mail, Trophy, Zap, Plus
} from 'lucide-react';

interface Props {
  user: User;
  settings: AppSettings | null;
  users: User[];
  markets: Market[];
  companies: Company[];
}

const Settings: React.FC<Props> = ({ user, settings, users = [], markets = [], companies = [] }) => {
  if (user.role !== 'admin') return <div className="text-center py-20 font-black">عذراً، للمديرين فقط</div>;

  const [activeSubTab, setActiveSubTab] = useState('general');
  const [newTickerText, setNewTickerText] = useState(settings?.tickerText || '');
  const [whatsapp, setWhatsapp] = useState(settings?.whatsappNumber || '');
  const [isTickerAnimated, setIsTickerAnimated] = useState(settings?.isTickerAnimated || false);
  const [editingCredentials, setEditingCredentials] = useState<User | null>(null);
  const [newItemName, setNewItemName] = useState('');
  const [messageTarget, setMessageTarget] = useState<User | null>(null);
  const [msgText, setMsgText] = useState('');

  const handleSaveGeneral = async () => {
    await update(ref(db, 'settings'), {
      tickerText: newTickerText,
      whatsappNumber: whatsapp,
      isTickerAnimated: isTickerAnimated
    });
    alert("✅ تم الحفظ بنجاح");
  };

  const handleDeleteUser = async (id: string, name: string) => {
    if (window.confirm(`هل أنت متأكد من حذف ${name} نهائياً؟`)) {
      await remove(ref(db, `users/${id}`));
    }
  };

  const handleAddItem = async (type: 'markets' | 'companies') => {
    if (!newItemName.trim()) return;
    const newRef = push(ref(db, type));
    await set(newRef, { name: newItemName.trim(), creatorId: user.id });
    setNewItemName('');
    alert("✅ تمت الإضافة بنجاح");
  };

  const handleUpdatePassword = async () => {
    if (!editingCredentials) return;
    await update(ref(db, `users/${editingCredentials.id}`), {
      username: editingCredentials.username,
      password: editingCredentials.password
    });
    alert("✅ تم تحديث بيانات الدخول");
    setEditingCredentials(null);
  };

  return (
    <div className="space-y-8 pb-20 text-right" dir="rtl">
      <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
        {[{ id: 'general', label: 'عام', icon: <SettingsIcon size={18}/> },
          { id: 'users', label: 'الموظفين', icon: <UserCog size={18}/> },
          { id: 'markets', label: 'الماركتات', icon: <Store size={18}/> },
          { id: 'companies', label: 'المنافسين', icon: <Building2 size={18}/> }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id)}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl transition-all font-black text-xs ${activeSubTab === tab.id ? 'bg-rose-600 text-white' : 'bg-white/5 text-white/40'}`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'general' && (
        <div className="glass-card-dark p-6 md:p-10 rounded-[2rem]">
          <h3 className="text-xl font-black text-white mb-8 border-b border-white/10 pb-4">الإعدادات العامة</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <div>
              <label className="text-[10px] font-black text-white/30 uppercase tracking-widest block mb-2 mr-2">رقم الواتساب</label>
              <input className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none text-sm" value={whatsapp} onChange={e => setWhatsapp(e.target.value)}/>
            </div>
            <div className="flex items-center justify-between p-5 bg-blue-600/10 rounded-[1.5rem] border border-blue-500/20">
              <span className="text-sm font-black text-white flex items-center gap-2"><Zap size={20}/> تحريك شريط الأخبار</span>
              <input type="checkbox" checked={isTickerAnimated} onChange={e => setIsTickerAnimated(e.target.checked)} className="w-5 h-5 accent-blue-600" />
            </div>
            <div className="md:col-span-2">
              <label className="text-[10px] font-black text-white/30 uppercase block mb-2 mr-2">نص شريط الأخبار</label>
              <textarea className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none h-24 resize-none text-sm" value={newTickerText} onChange={e => setNewTickerText(e.target.value)} />
            </div>
          </div>
          <button onClick={handleSaveGeneral} className="bg-rose-600 text-white px-10 py-4 rounded-xl font-black flex items-center gap-2 shadow-lg"><Save size={18}/> حفظ الإعدادات</button>
        </div>
      )}

      {activeSubTab === 'users' && (
        <div className="glass-card-dark rounded-[2.5rem] overflow-hidden">
          <table className="w-full text-right">
            <thead className="bg-white/5 text-[10px] font-black text-white/40">
              <tr><th className="p-6">الموظف</th><th className="p-6 text-center">الإجراءات</th></tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {users.map(u => (
                <tr key={u.id} className="hover:bg-white/5">
                  <td className="p-6 font-bold text-sm text-white">{u.employeeName}</td>
                  <td className="p-6">
                    <div className="flex gap-3 justify-center">
                      <button onClick={() => setMessageTarget(u)} className="p-2 text-amber-400 hover:bg-white/10 rounded-lg"><Mail size={16}/></button>
                      <button onClick={() => setEditingCredentials(u)} className="p-2 text-blue-400 hover:bg-white/10 rounded-lg"><Key size={16}/></button>
                      <button onClick={() => handleDeleteUser(u.id, u.employeeName)} className="p-2 text-red-400 hover:bg-white/10 rounded-lg"><Trash2 size={16}/></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {(activeSubTab === 'markets' || activeSubTab === 'companies') && (
        <div className="space-y-6">
          <div className="glass-card-dark p-6 md:p-10 rounded-[2.5rem]">
            <h3 className="text-xl font-black text-white mb-6 flex items-center gap-3"><Plus className="text-rose-500" /> إضافة {activeSubTab === 'markets' ? 'ماركت' : 'شركة منافسة'}</h3>
            <div className="flex gap-4">
              <input className="flex-1 glass-input-dark p-4 rounded-xl font-bold" placeholder="الاسم الجديد..." value={newItemName} onChange={e => setNewItemName(e.target.value)} />
              <button onClick={() => handleAddItem(activeSubTab as any)} className="bg-rose-600 text-white px-8 py-4 rounded-xl font-black">إضافة</button>
            </div>
          </div>
          <div className="glass-card-dark rounded-[2.5rem] overflow-hidden">
            <div className="divide-y divide-white/5">
              {(activeSubTab === 'markets' ? markets : companies).map(item => (
                <div key={item.id} className="p-6 flex justify-between items-center hover:bg-white/5">
                  <span className="font-bold text-white">{item.name}</span>
                  <button onClick={async () => { if(window.confirm('حذف؟')) await remove(ref(db, `${activeSubTab}/${item.id}`)); }} className="p-2 text-red-400 hover:bg-red-400/10 rounded-lg"><Trash2 size={18}/></button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {editingCredentials && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] p-8 max-w-md w-full animate-in zoom-in-95">
            <h4 className="text-xl font-black text-white mb-6">تحديث بيانات {editingCredentials.employeeName}</h4>
            <div className="space-y-4 text-right">
              <input className="w-full glass-input-dark p-4 rounded-xl font-bold" placeholder="اسم المستخدم" value={editingCredentials.username} onChange={e => setEditingCredentials({...editingCredentials, username: e.target.value})}/>
              <input type="password" className="w-full glass-input-dark p-4 rounded-xl font-bold" placeholder="الباسورد الجديد" value={editingCredentials.password} onChange={e => setEditingCredentials({...editingCredentials, password: e.target.value})}/>
            </div>
            <div className="flex gap-3 mt-8">
              <button onClick={handleUpdatePassword} className="flex-1 bg-blue-600 text-white py-4 rounded-xl font-black">تحديث</button>
              <button onClick={() => setEditingCredentials(null)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}

      {messageTarget && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] p-8 max-w-md w-full animate-in zoom-in-95">
            <h4 className="text-xl font-black text-white mb-6">إرسال رسالة إلى {messageTarget.employeeName}</h4>
            <textarea className="w-full glass-input-dark p-4 rounded-xl font-bold h-32 resize-none" placeholder="اكتب رسالتك..." value={msgText} onChange={e => setMsgText(e.target.value)}/>
