        <div className="glass-card-dark p-6 md:p-10 rounded-[2rem]">
          <h3 className="text-xl font-black text-white mb-8 border-b border-white/10 pb-4">الإعدادات العامة</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <div>
              <label className="text-[10px] font-black text-white/30 uppercase tracking-widest block mb-2 mr-2">رقم الواتساب</label>
              <input className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none text-sm" value={whatsapp} onChange={e => setWhatsapp(e.target.value)}/>
            </div>
            <div className="flex items-center justify-between p-5 bg-blue-600/10 rounded-[1.5rem] border border-blue-500/20">
              <span className="text-sm font-black text-white flex items-center gap-2"><Zap size={20}/> تحريك شريط الأخبار</span>
              <input type="checkbox" checked={isTickerAnimated} onChange={e => setIsTickerAnimated(e.target.checked)} className="w-5 h-5 accent-blue-600" />
            </div>
            <div className="md:col-span-2">
              <label className="text-[10px] font-black text-white/30 uppercase block mb-2 mr-2">نص شريط الأخبار</label>
              <textarea className="w-full glass-input-dark rounded-xl p-4 font-bold outline-none h-24 resize-none text-sm" value={newTickerText} onChange={e => setNewTickerText(e.target.value)} />
            </div>
          </div>
          <button onClick={handleSaveGeneral} className="bg-rose-600 text-white px-10 py-4 rounded-xl font-black flex items-center gap-2 shadow-lg"><Save size={18}/> حفظ الإعدادات</button>
        </div>
      )}

      {activeSubTab === 'users' && (
        <div className="glass-card-dark rounded-[2.5rem] overflow-hidden">
          <table className="w-full text-right">
            <thead className="bg-white/5 text-[10px] font-black text-white/40">
              <tr><th className="p-6">الموظف</th><th className="p-6 text-center">الإجراءات</th></tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {users.map(u => (
                <tr key={u.id} className="hover:bg-white/5">
                  <td className="p-6 font-bold text-sm text-white">{u.employeeName}</td>
                  <td className="p-6">
                    <div className="flex gap-3 justify-center">
                      <button onClick={() => setMessageTarget(u)} className="p-2 text-amber-400 hover:bg-white/10 rounded-lg" title="إرسال رسالة"><Mail size={16}/></button>
                      <button onClick={() => setEditingPermissions(u)} className="p-2 text-rose-400 hover:bg-white/10 rounded-lg" title="تعديل الصلاحيات"><Shield size={16}/></button>
                      <button onClick={() => setEditingCredentials(u)} className="p-2 text-blue-400 hover:bg-white/10 rounded-lg" title="تغيير الباسورد"><Key size={16}/></button>
                      <button onClick={() => handleDeleteUser(u.id, u.employeeName)} className="p-2 text-red-400 hover:bg-white/10 rounded-lg" title="حذف المستخدم"><Trash2 size={16}/></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {(activeSubTab === 'markets' || activeSubTab === 'companies') && (
        <div className="space-y-6">
          <div className="glass-card-dark p-6 md:p-10 rounded-[2.5rem]">
            <h3 className="text-xl font-black text-white mb-6 flex items-center gap-3"><Plus className="text-rose-500" /> إضافة {activeSubTab === 'markets' ? 'ماركت' : 'شركة منافسة'}</h3>
            <div className="flex gap-4">
              <input className="flex-1 glass-input-dark p-4 rounded-xl font-bold" placeholder="الاسم الجديد..." value={newItemName} onChange={e => setNewItemName(e.target.value)} />
              <button onClick={() => handleAddItem(activeSubTab as any)} className="bg-rose-600 text-white px-8 py-4 rounded-xl font-black">إضافة</button>
            </div>
          </div>
          <div className="glass-card-dark rounded-[2.5rem] overflow-hidden">
            <div className="divide-y divide-white/5">
              {(activeSubTab === 'markets' ? markets : companies).map(item => (
                <div key={item.id} className="p-6 flex justify-between items-center hover:bg-white/5">
                  <span className="font-bold text-white">{item.name}</span>
                  <button onClick={async () => { if(window.confirm('حذف؟')) await remove(ref(db, `${activeSubTab}/${item.id}`)); }} className="p-2 text-red-400 hover:bg-red-400/10 rounded-lg"><Trash2 size={18}/></button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Permissions Modal */}
      {editingPermissions && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] p-8 max-w-xl w-full border border-white/10 animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-6">
              <h4 className="text-xl font-black text-white">صلاحيات {editingPermissions.employeeName}</h4>
              <button onClick={() => setEditingPermissions(null)} className="p-2 hover:bg-white/10 rounded-full"><X size={20}/></button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[60vh] overflow-y-auto custom-scrollbar p-2">
              {[
                { key: 'registerSales', label: 'تسجيل المبيعات' },
                { key: 'viewSalesHistory', label: 'رؤية سجل المبيعات' },
                { key: 'viewColleaguesSales', label: 'رؤية مبيعات الزملاء' },
                { key: 'registerInventory', label: 'تسجيل المخزون' },
                { key: 'viewInventoryHistory', label: 'رؤية سجل المخزون' },
                { key: 'registerCompetitorPrices', label: 'تسجيل أسعار المنافسين' },
                { key: 'viewCompetitorReports', label: 'رؤية تقارير المنافسين' },
                { key: 'viewVacationMgmt', label: 'إدارة الإجازات' },
                { key: 'viewSettings', label: 'دخول الإعدادات' }
              ].map(item => (
                <button 
                  key={item.key}
                  onClick={() => togglePermission(item.key as keyof UserPermissions)}
                  className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${editingPermissions.permissions[item.key as keyof UserPermissions] ? 'bg-rose-600/20 border-rose-500 text-white' : 'bg-white/5 border-white/10 text-white/40'}`}
                >
                  <span className="text-xs font-bold">{item.label}</span>
                  {editingPermissions.permissions[item.key as keyof UserPermissions] ? <CheckCircle2 size={18} className="text-rose-400" /> : <div className="w-[18px] h-[18px] rounded-full border border-white/20" />}
                </button>
              ))}
            </div>
            <div className="flex gap-3 mt-8">
              <button onClick={handleSavePermissions} className="flex-1 bg-rose-600 text-white py-4 rounded-xl font-black">حفظ الصلاحيات</button>
              <button onClick={() => setEditingPermissions(null)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}

      {editingCredentials && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] p-8 max-w-md w-full animate-in zoom-in-95">
            <h4 className="text-xl font-black text-white mb-6">تحديث بيانات {editingCredentials.employeeName}</h4>
            <div className="space-y-4 text-right">
              <input className="w-full glass-input-dark p-4 rounded-xl font-bold" placeholder="اسم المستخدم" value={editingCredentials.username} onChange={e => setEditingCredentials({...editingCredentials, username: e.target.value})}/>
              <input type="password" className="w-full glass-input-dark p-4 rounded-xl font-bold" placeholder="الباسورد الجديد" value={editingCredentials.password} onChange={e => setEditingCredentials({...editingCredentials, password: e.target.value})}/>
            </div>
            <div className="flex gap-3 mt-8">
              <button onClick={handleUpdatePassword} className="flex-1 bg-blue-600 text-white py-4 rounded-xl font-black">تحديث</button>
              <button onClick={() => setEditingCredentials(null)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}

      {messageTarget && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="glass-card-dark rounded-[3rem] p-8 max-w-md w-full animate-in zoom-in-95">
            <h4 className="text-xl font-black text-white mb-6">إرسال رسالة إلى {messageTarget.employeeName}</h4>
            <textarea className="w-full glass-input-dark p-4 rounded-xl font-bold h-32 resize-none" placeholder="اكتب رسالتك..." value={msgText} onChange={e => setMsgText(e.target.value)}/>
            <div className="flex gap-3 mt-8">
              <button onClick={async () => { await push(ref(db, 'notifications'), { senderId: user.id, receiverId: messageTarget.id, message: msgText, timestamp: new Date().toISOString(), isRead: false }); alert('تم الإرسال'); setMessageTarget(null); setMsgText(''); }} className="flex-1 bg-rose-600 text-white py-4 rounded-xl font-black">إرسال الآن</button>
              <button onClick={() => setMessageTarget(null)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl font-black">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Settings;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ShoppingCart, History, Package, ClipboardList, 
  TrendingUp, BarChart, Settings as SettingsIcon, 
  LogOut, Menu, X, Bell, Calendar,
  Loader2, Sparkles, Phone, Palette, Copy, Trash2
} from 'lucide-react';
import { db, ref, onValue, update, remove } from './firebase';
import { User, AppSettings, Notification, Market, Company, DailySale, InventoryRecord, Vacation } from './types';

// View Components
import DailySales from './views/DailySales';
import SalesHistory from './views/SalesHistory';
import InventoryRegistration from './views/InventoryRegistration';
import InventoryHistory from './views/InventoryHistory';
import CompetitorPrices from './views/CompetitorPrices';
import CompetitorReports from './views/CompetitorReports';
import VacationManagement from './views/VacationManagement';
import Settings from './views/Settings';
import Login from './views/Login';
import AIChatbot from './views/AIChatbot';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('daily-sales');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [sales, setSales] = useState<DailySale[]>([]);
  const [inventory, setInventory] = useState<InventoryRecord[]>([]);
  const [vacations, setVacations] = useState<Vacation[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isAIChatOpen, setIsAIChatOpen] = useState(false);
  const [isNotifDropdownOpen, setIsNotifDropdownOpen] = useState(false);
  const [selectedNotif, setSelectedNotif] = useState<Notification | null>(null);
  const [currentTheme, setCurrentTheme] = useState<'rose' | 'dark' | 'purple' | 'emerald'>('rose');

  const themes = {
    rose: 'blob-rose',
    dark: 'blob-dark',
    purple: 'blob-purple',
    emerald: 'blob-emerald'
  };

  useEffect(() => {
    document.body.className = themes[currentTheme];
  }, [currentTheme]);

  useEffect(() => {
    onValue(ref(db, 'settings'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSettings(data);
    });

    onValue(ref(db, 'users'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const usersList = Object.entries(data).map(([id, val]: any) => ({ ...val, id: val.id || id }));
        setUsers(usersList);
      }
    });

    onValue(ref(db, 'sales'), (snapshot) => {
      const data = snapshot.val();
      if (data) setSales(Object.values(data));
    });

    onValue(ref(db, 'inventory'), (snapshot) => {
      const data = snapshot.val();
      if (data) setInventory(Object.values(data));
    });

    onValue(ref(db, 'vacations'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
        setVacations(list);
      }
    });

    onValue(ref(db, 'notifications'), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.entries(data).map(([id, val]: any) => ({ ...val, id }));
        setNotifications(list);
      } else {
        setNotifications([]);
      }
    });

    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (user) {
      onValue(ref(db, 'markets'), (snapshot) => {
        const data = snapshot.val();
        if (data) setMarkets(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
      onValue(ref(db, 'companies'), (snapshot) => {
        const data = snapshot.val();
        if (data) setCompanies(Object.entries(data).map(([id, val]: any) => ({ id, ...val })));
      });
    }
  }, [user]);

  const unreadCount = useMemo(() => {
    if (!user) return 0;
    return notifications.filter(n => n.receiverId === user.id && !n.isRead).length;
  }, [notifications, user]);

  const userNotifications = useMemo(() => {
    if (!user) return [];
    return notifications.filter(n => n.receiverId === user.id).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [notifications, user]);

  const handleLogin = (loggedUser: User) => {
    setUser(loggedUser);
    update(ref(db, `users/${loggedUser.id}`), { isOnline: true });
  };

  const handleLogout = () => {
    if (user) update(ref(db, `users/${user.id}`), { isOnline: false });
    setUser(null);
  };

  const toggleTheme = () => {
    const themeOrder: Array<'rose' | 'dark' | 'purple' | 'emerald'> = ['rose', 'dark', 'purple', 'emerald'];
    const nextIdx = (themeOrder.indexOf(currentTheme) + 1) % themeOrder.length;
    setCurrentTheme(themeOrder[nextIdx]);
  };

  const openWhatsApp = () => {
    if (settings?.whatsappNumber) {
      window.open(`https://wa.me/${settings.whatsappNumber}`, '_blank');
    } else {
      alert("لم يتم تسجيل رقم واتساب في الإعدادات");
    }
  };

  const sidebarItems = [
    { id: 'daily-sales', label: 'المبيعات اليومية', icon: <ShoppingCart size={20}/>, visible: true },
    { id: 'sales-history', label: 'سجل المبيعات', icon: <History size={20}/>, visible: true },
    { id: 'inventory-reg', label: 'تسجيل المخزون', icon: <Package size={20}/>, visible: true },
    { id: 'inventory-history', label: 'سجل المخزون', icon: <ClipboardList size={20}/>, visible: true },
    { id: 'competitor-prices', label: 'أسعار المنافسين', icon: <TrendingUp size={20}/>, visible: true },
    { id: 'competitor-reports', label: 'تقارير المنافسين', icon: <BarChart size={20}/>, visible: true },
    { id: 'vacation-mgmt', label: 'رصيد الاجازات', icon: <Calendar size={20}/>, visible: true },
    { id: 'settings', label: 'إعدادات النظام', icon: <SettingsIcon size={20}/>, visible: user?.role === 'admin' },
  ].filter(i => i.visible);

  if (isLoading) return <div className="h-screen flex items-center justify-center bg-transparent"><Loader2 className="animate-spin text-rose-50" size={48}/></div>;
  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className={`flex h-screen overflow-hidden relative bg-transparent text-white ${currentTheme}-theme`}>
      {/* Sidebar Overlay */}
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/60 z-[60] backdrop-blur-md" onClick={() => setIsSidebarOpen(false)}/>
      )}

      {/* Glass Sidebar */}
      <aside className={`glass-sidebar-inner text-white w-72 flex-shrink-0 transition-all duration-500 z-[70] fixed md:absolute md:relative inset-y-0 ${isSidebarOpen ? 'right-0' : '-right-72 md:-right-72'} shadow-2xl`}>
        <div className="p-8 flex flex-col h-full">
          <div className="mb-12 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase font-black tracking-[0.4em] text-rose-500">SOFT ROSE</span>
              <h1 className="text-xl font-black tracking-tighter">Soft Rose</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="p-2 hover:bg-white/10 rounded-xl transition-all"><X size={20}/></button>
          </div>

          <nav className="flex-1 space-y-2 overflow-y-auto custom-scrollbar">
            {sidebarItems.map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all duration-300 relative group ${activeTab === item.id ? 'bg-rose-600/20 text-white font-black active-glow' : 'hover:bg-white/5 text-white/60 font-medium'}`}
              >
                <span className={`${activeTab === item.id ? 'text-rose-400' : 'group-hover:text-white'}`}>{item.icon}</span>
                <span className="text-sm">{item.label}</span>
                {activeTab === item.id && <div className="absolute left-3 w-1.5 h-6 bg-rose-500 rounded-full"></div>}
              </button>
            ))}
          </nav>

          <div className="mt-8 pt-8 border-t border-white/5">
             <button onClick={handleLogout} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-rose-400 hover:bg-rose-500/10 transition-all font-black text-sm">
                <LogOut size={20} />
                <span>تسجيل الخروج</span>
             </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {settings?.tickerText && (
          <div className="bg-rose-950/40 backdrop-blur-md py-2 text-rose-100 text-[11px] font-black overflow-hidden z-[50] border-b border-white/5 ticker-container">
            <div className={settings?.isTickerAnimated ? "animate-ticker" : "px-8"}>
              {settings.tickerText} &nbsp;&nbsp; • &nbsp;&nbsp; {settings.tickerText}
            </div>
          </div>
        )}

        <header className="h-20 flex items-center justify-between px-8 glass-header-inner z-[40]">
          <div className="flex items-center gap-4">
            <button 
              onClick={(e) => { e.stopPropagation(); setIsSidebarOpen(!isSidebarOpen); }} 
              className="p-2.5 bg-white/5 text-white rounded-xl hover:bg-white/10 transition-all active:scale-95 flex items-center gap-3"
            >
              <Menu size={22} />
              <span className="font-black text-sm text-white/80">{user.employeeName}</span>
            </button>
          </div>

          {/* Program Name in Header */}
          <div className="hidden md:block">
            <h2 className="text-lg font-black tracking-widest text-white/90">SOFT ROSE MODERN TRADE</h2>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={handleLogout} 
              className="p-2.5 bg-white/5 text-rose-400 rounded-xl hover:bg-rose-500 hover:text-white transition-all shadow-sm"
              title="تسجيل الخروج"
            >
              <LogOut size={20} />
            </button>

            <div className="relative">
              <button 
                onClick={(e) => { e.stopPropagation(); setIsNotifDropdownOpen(!isNotifDropdownOpen); }}
                className="p-2.5 bg-white/5 text-amber-400 rounded-xl hover:bg-amber-500 hover:text-white transition-all relative shadow-sm"
                title="الإشعارات"
              >
                <Bell size={20} />
                {unreadCount > 0 && <div className="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-red-600 rounded-full border-2 border-slate-900 animate-pulse"></div>}
              </button>

              {isNotifDropdownOpen && (
                <div className="absolute left-0 mt-4 w-72 glass-card-dark rounded-2xl overflow-hidden shadow-2xl z-[100] animate-in fade-in slide-in-from-top-2" onClick={e => e.stopPropagation()}>
                  <div className="p-4 bg-white/5 border-b border-white/10">
                    <span className="text-xs font-black text-right block">مركز التنبيهات</span>
                  </div>
                  <div className="max-h-64 overflow-y-auto custom-scrollbar">
                    {userNotifications.length === 0 ? (
                      <div className="p-8 text-center text-white/20 text-[10px] font-bold italic">لا توجد رسائل جديدة</div>
                    ) : (
                      userNotifications.map(n => (
                        <button 
                          key={n.id} 
                          onClick={() => {
                            setSelectedNotif(n);
                            setIsNotifDropdownOpen(false);
                            update(ref(db, `notifications/${n.id}`), { isRead: true });
                          }}
                          className={`w-full p-4 text-right hover:bg-white/5 transition-all border-b border-white/5 flex gap-3 items-start ${!n.isRead ? 'bg-rose-600/10' : ''}`}
                        >
                          <div className={`w-2 h-2 rounded-full mt-1.5 shrink-0 ${!n.isRead ? 'bg-rose-500' : 'bg-transparent'}`}></div>
                          <p className={`text-xs ${!n.isRead ? 'font-black text-white' : 'font-medium text-white/60'} line-clamp-2`}>{n.message}</p>
                        </button>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>

            <button onClick={toggleTheme} className="p-2.5 bg-white/5 text-blue-400 rounded-xl hover:bg-blue-500 transition-all shadow-sm" title="تغيير الاستايل">
              <Palette size={20} />
            </button>

            <button onClick={openWhatsApp} className="p-2.5 bg-white/5 text-green-400 rounded-xl hover:bg-green-500 transition-all shadow-sm" title="تواصل واتساب">
              <Phone size={20} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto h-full">
            <div className="glass-card-dark rounded-[2.5rem] p-6 md:p-10 min-h-full">
              {activeTab === 'daily-sales' && <DailySales user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'sales-history' && <SalesHistory user={user} markets={markets.map(m => m.name)} users={users} />}
              {activeTab === 'inventory-reg' && <InventoryRegistration user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'inventory-history' && <InventoryHistory user={user} markets={markets.map(m => m.name)} users={users} />}
              {activeTab === 'competitor-prices' && <CompetitorPrices user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'competitor-reports' && <CompetitorReports user={user} markets={markets.map(m => m.name)} />}
              {activeTab === 'vacation-mgmt' && <VacationManagement user={user} users={users} vacations={vacations} />}
              {activeTab === 'settings' && <Settings user={user} settings={settings} users={users} markets={markets} companies={companies} />}
            </div>
          </div>
        </div>

        {selectedNotif && (
          <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[2000] flex items-center justify-center p-4">
            <div className="glass-card-dark rounded-[3rem] p-8 max-w-md w-full border border-white/10 animate-in zoom-in-95">
               <div className="flex justify-between items-center mb-6">
                 <h3 className="text-sm font-black text-amber-400">رسالة واردة</h3>
                 <button onClick={() => setSelectedNotif(null)} className="p-2 hover:bg-white/10 rounded-full"><X size={20}/></button>
               </div>
               <div className="bg-white/5 p-6 rounded-2xl border border-white/10 text-sm font-bold leading-relaxed mb-8 text-right">
                 {selectedNotif.message}
               </div>
               <div className="flex gap-4">
                 <button 
                  onClick={() => { navigator.clipboard.writeText(selectedNotif.message); alert("تم النسخ بنجاح"); }} 
                  className="flex-1 bg-white/10 text-white py-4 rounded-xl flex items-center justify-center gap-2 font-black text-xs"
                 >
                   <Copy size={16}/> نسخ النص
                 </button>
                 <button 
                  onClick={async () => { await remove(ref(db, `notifications/${selectedNotif.id}`)); setSelectedNotif(null); }} 
                  className="flex-1 bg-red-600 text-white py-4 rounded-xl flex items-center justify-center gap-2 font-black text-xs"
                 >
                   <Trash2 size={16}/> حذف
                 </button>
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

